window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["c10-exam"] = window.COURSE_LANG["c10-exam"] || {};
window.COURSE_LANG["c10-exam"]["es"] = [
  {"id":1,"q":"Un circuito de 120 V alimenta un elemento calefactor con una resistencia de 20 ohmios; ¿cuál es el consumo de corriente?","opts":["2 A","0.17 A","6 A","2400 A"],"re":"Por la ley de Ohm, I = V/R = 120/20 = 6 A."},
  {"id":2,"q":"¿Qué tipo de aislamiento de conductor está clasificado para 90°C en lugares secos pero NO está aprobado para uso en lugares mojados?","opts":["THWN-2","THHN","XHHW-2","USE-2"],"re":"THHN es un aislamiento de 90°C para lugares secos/húmedos; para lugares mojados se usa THWN-2 o XHHW-2. Véase NEC Table 310.4(A)."},
  {"id":3,"q":"En una habitación habitable de una unidad de vivienda, ¿cuál es la distancia horizontal máxima desde cualquier punto a lo largo de la línea de pared hasta una salida de tomacorriente?","opts":["3 pies","12 pies","10 pies","6 pies"],"re":"NEC 210.52(A) requiere que ningún punto a lo largo de la línea del piso de una pared esté a más de 6 ft de un tomacorriente, de modo que un cordón de electrodoméstico de 6 ft pueda alcanzar una salida desde cualquier dirección."},
  {"id":4,"q":"Según NEC 430.22, ¿cuál es la ampacidad mínima del conductor del circuito ramal requerida para un solo motor de servicio continuo con una corriente a plena carga de 28 amperios?","opts":["28 amperios","31 amperios","40 amperios","35 amperios"],"re":"NEC 430.22 requiere que los conductores del circuito ramal para un solo motor tengan una ampacidad de al menos el 125% de la corriente a plena carga del motor: 28 A x 1.25 = 35 A."},
  {"id":5,"q":"Según Cal/OSHA Title 8 Section 3314, ¿cuál es el propósito principal de un procedimiento de bloqueo/etiquetado (lockout/tagout)?","opts":["Controlar la energía peligrosa para que el equipo no pueda ser energizado o arrancado de forma inesperada durante el servicio o mantenimiento","Documentar las calificaciones de cada electricista en el sitio de trabajo","Reducir la corriente de falla disponible en las terminales del equipo","Proporcionar una trayectoria de tierra de respaldo para el sistema eléctrico"],"re":"Cal/OSHA T8 Section 3314 requiere el control de la energía peligrosa mediante bloqueo/etiquetado para que las máquinas o equipos queden aislados y no puedan arrancar de forma inesperada durante el servicio."},
  {"id":6,"q":"¿Qué indica la 'W' en la designación de aislamiento de conductor THWN-2?","opts":["Construcción trenzada (cableada)","El alambre es sólido","Codificación de color blanco","Apto para lugares mojados"],"re":"En la nomenclatura de aislamiento del NEC, la 'W' significa que el conductor está clasificado para lugares mojados. Véase NEC Table 310.4(A) y su Anexo."},
  {"id":7,"q":"¿Cuál es la potencia disipada por un electrodoméstico de 240 V que consume 12.5 A?","opts":["3000 W","19.2 W","252.5 W","1920 W"],"re":"Usando P = V x I = 240 x 12.5 = 3000 W."},
  {"id":8,"q":"Al dimensionar los conductores del circuito ramal para un solo motor según NEC 430.22, ¿qué valor debe usarse como base para el cálculo?","opts":["El valor de corriente a plena carga de las tablas del NEC","La corriente a plena carga de la placa de identificación del motor","La corriente a rotor bloqueado del motor","El amperaje del factor de servicio estampado en la placa de identificación"],"re":"NEC 430.6(A) especifica que el dimensionamiento del conductor y del dispositivo de sobrecorriente según 430.22 se basa en los valores de las tablas (como Table 430.248/430.250), no en la FLA de la placa de identificación."},
  {"id":9,"q":"De acuerdo con NFPA 70E, ¿cuál es la regla general respecto al trabajo en equipos eléctricos?","opts":["El equipo debe colocarse en una condición de trabajo eléctricamente segura (desenergizado) a menos que desenergizarlo introduzca peligros adicionales o sea inviable","El equipo puede permanecer energizado siempre que haya un segundo trabajador presente","El equipo debe permanecer energizado para poder verificar el voltaje en todo momento","El trabajo energizado siempre es aceptable si se usan guantes de goma"],"re":"NFPA 70E requiere establecer una condición de trabajo eléctricamente segura antes de iniciar el trabajo; el trabajo energizado solo se permite cuando desenergizar introduce peligros adicionales o mayores, o es inviable debido al diseño del equipo o a limitaciones operativas."},
  {"id":10,"q":"¿Qué tipo de aislamiento está destinado específicamente para uso en acometida subterránea y es apto para enterramiento directo?","opts":["THHN","USE","RHW","TW"],"re":"USE (Underground Service Entrance) está clasificado para enterramiento directo y uso subterráneo. Véase NEC Table 310.4(A)."},
  {"id":11,"q":"Una resistencia de 8 ohmios conduce una corriente de 5 A; ¿cuánta potencia disipa?","opts":["200 W","40 W","1.6 W","320 W"],"re":"Usando P = I al cuadrado x R = 5 al cuadrado x 8 = 25 x 8 = 200 W."},
  {"id":12,"q":"Según la regla de espaciamiento de tomacorrientes en viviendas, ¿cuál es el espaciamiento máximo permitido entre tomacorrientes de uso general adyacentes a lo largo de una pared?","opts":["6 pies","20 pies","15 pies","12 pies"],"re":"Debido a que ningún punto puede estar a más de 6 ft de un tomacorriente, los tomacorrientes espaciados uniformemente a lo largo de una pared pueden estar separados hasta 12 ft (alcance de 6 ft desde cada uno), según NEC 210.52(A)."},
  {"id":13,"q":"Un motor trifásico de servicio continuo tiene una corriente a plena carga de 80 amperios; ¿cuál es la ampacidad mínima del conductor del circuito ramal requerida por NEC 430.22?","opts":["100 amperios","92 amperios","80 amperios","125 amperios"],"re":"NEC 430.22 requiere el 125% de la FLC del motor: 80 A x 1.25 = 100 A de ampacidad mínima del conductor."},
  {"id":14,"q":"¿Qué procedimiento se utiliza para verificar que un circuito está desenergizado antes de que una persona calificada comience a trabajar?","opts":["El método vivo-muerto-vivo (probar antes de tocar) usando un comprobador de voltaje con clasificación adecuada","Confirmar que el medidor de la empresa de servicios dejó de girar","Inspección visual únicamente de las etiquetas del tablero","Tocar brevemente el conductor con el dorso de la mano"],"re":"El método vivo-muerto-vivo requiere probar el comprobador de voltaje en una fuente viva conocida, probar los conductores desenergizados y luego volver a probar en la fuente viva conocida para confirmar que el comprobador sigue funcionando, verificando la ausencia de voltaje."},
  {"id":15,"q":"¿Para qué temperatura máxima de operación está clasificado el aislamiento RHW?","opts":["75°C","90°C","60°C","105°C"],"re":"RHW es un aislamiento termoestable clasificado para 75°C en lugares mojados y secos. Véase NEC Table 310.4(A)."},
  {"id":16,"q":"Una fuente de 120 V está conectada a través de una resistencia de 60 ohmios; ¿qué potencia se disipa?","opts":["2 W","7200 W","240 W","120 W"],"re":"Usando P = V al cuadrado / R = 120 al cuadrado / 60 = 14400 / 60 = 240 W."},
  {"id":17,"q":"Para un motor de servicio continuo con un factor de servicio marcado de 1.15, ¿qué porcentaje de la corriente a plena carga de la placa de identificación del motor se usa para dimensionar la protección de sobrecarga separada según NEC 430.32?","opts":["125%","115%","140%","250%"],"re":"NEC 430.32(A)(1) permite la protección de sobrecarga al 125% de la FLA de la placa de identificación cuando el factor de servicio es 1.15 o mayor (o el aumento de temperatura es de 40°C o menos)."},
  {"id":18,"q":"Según NFPA 70E, ¿qué límite solo puede ser cruzado por una persona calificada que use el EPP de protección contra descargas apropiado?","opts":["El límite de arco eléctrico para observadores no calificados","El límite de aproximación limitada para visitantes escoltados","El límite de aproximación restringida","La cerca perimetral exterior de la propiedad"],"re":"Según NFPA 70E, el límite de aproximación restringida solo puede ser cruzado por una persona calificada que tenga un plan documentado y use el EPP de protección contra descargas apropiado, debido al mayor riesgo de contacto con partes energizadas."},
  {"id":19,"q":"XHHW es un aislamiento termoestable; ¿cuál es su clasificación de temperatura en un lugar seco?","opts":["60°C","75°C","110°C","90°C"],"re":"XHHW está clasificado para 90°C en lugares secos/húmedos (y 75°C en lugares mojados). Véase NEC Table 310.4(A)."},
  {"id":20,"q":"Tres resistencias de 10 ohmios, 15 ohmios y 25 ohmios se conectan en serie; ¿cuál es la resistencia total?","opts":["4.84 ohmios","5 ohmios","50 ohmios","3750 ohmios"],"re":"Las resistencias en serie se suman: 10 + 15 + 25 = 50 ohmios."},
  {"id":21,"q":"Para los fines del espaciamiento de tomacorrientes en viviendas, ¿de qué ancho o mayor debe ser cualquier espacio de pared para que se le deba proveer una salida de tomacorriente?","opts":["12 pulgadas (1 ft) o más ancho","24 pulgadas (2 ft) o más ancho","18 pulgadas o más ancho","36 pulgadas (3 ft) o más ancho"],"re":"NEC 210.52(A)(2) define un espacio de pared que debe contarse como cualquier espacio de 2 ft (600 mm) o más de ancho, incluido el espacio medido alrededor de las esquinas."},
  {"id":22,"q":"Un motor de servicio continuo tiene un factor de servicio de 1.0 y un aumento de temperatura de 50°C; ¿qué porcentaje de la corriente a plena carga de la placa de identificación se permite para dimensionar su protección de sobrecarga según NEC 430.32?","opts":["100%","130%","125%","115%"],"re":"NEC 430.32(A)(1) limita la protección de sobrecarga al 115% de la FLA de la placa de identificación para motores que no tienen un factor de servicio de 1.15+ ni un aumento de temperatura de 40°C o menos."},
  {"id":23,"q":"Un tendido requiere conductores en un conduit que se instalará en un lugar subterráneo continuamente mojado; ¿qué aislamiento es apropiado?","opts":["THWN-2","Solo TW","Solo THHN","RHH"],"re":"THWN-2 lleva clasificación 'W' y es apto para lugares mojados; THHN, TW (60°C) y RHH (seco) son menos apropiados aquí. Véase NEC Table 310.4(A)."},
  {"id":24,"q":"¿Qué documento requiere NFPA 70E antes de realizar trabajo energizado justificado dentro del límite de aproximación restringida o de arco eléctrico?","opts":["Una hoja de datos de seguridad de materiales","Un certificado de ocupación del edificio","Un permiso de trabajo eléctrico energizado","Una hoja de cálculo de carga"],"re":"NFPA 70E requiere un permiso de trabajo eléctrico energizado, firmado por la gerencia autorizada, cuando el trabajo se realiza dentro del límite de aproximación restringida o donde existe un peligro de arco eléctrico y el trabajo no puede realizarse desenergizado."},
  {"id":25,"q":"Dos resistencias de 20 ohmios se conectan en paralelo; ¿cuál es la resistencia equivalente?","opts":["40 ohmios","10 ohmios","20 ohmios","0.1 ohmios"],"re":"Para dos resistencias iguales en paralelo, R = R/2 = 20/2 = 10 ohmios."},
  {"id":26,"q":"En comparación con el cobre, un conductor de aluminio del mismo tamaño AWG generalmente tiene ¿cuál característica?","opts":["Mayor ampacidad","Sin ampacidad especificada","Ampacidad idéntica","Menor ampacidad"],"re":"El aluminio tiene mayor resistividad que el cobre, por lo que un conductor de aluminio del mismo tamaño tiene una ampacidad menor. Véase NEC Table 310.16."},
  {"id":27,"q":"La placa de identificación de un motor indica 16 amperios de corriente a plena carga y un factor de servicio de 1.25; ¿cuál es el ajuste máximo de protección de sobrecarga permitido por NEC 430.32?","opts":["16 amperios","20 amperios","18.4 amperios","24 amperios"],"re":"Con un factor de servicio de 1.15 o más, NEC 430.32(A)(1) permite el 125% de la FLA de la placa de identificación: 16 A x 1.25 = 20 A."},
  {"id":28,"q":"¿Cómo define NFPA 70E a una persona calificada?","opts":["Cualquier trabajador que haya estado empleado por la empresa durante al menos cinco años","Cualquier persona que tenga una licencia de conducir válida y una tarjeta de primeros auxilios","Únicamente un ingeniero profesional con licencia","Alguien que ha demostrado destrezas y conocimientos relacionados con la construcción y operación de equipos eléctricos y ha recibido capacitación en seguridad para reconocer y evitar los peligros involucrados"],"re":"NFPA 70E define a una persona calificada como alguien que ha demostrado destrezas y conocimientos relacionados con la construcción y operación de los equipos e instalaciones eléctricas y ha recibido capacitación en seguridad para identificar y evitar los peligros involucrados."},
  {"id":29,"q":"Una resistencia de 6 ohmios y una de 12 ohmios se conectan en paralelo; ¿cuál es la resistencia total?","opts":["18 ohmios","4 ohmios","9 ohmios","0.25 ohmios"],"re":"En paralelo: R = (6 x 12)/(6 + 12) = 72/18 = 4 ohmios."},
  {"id":30,"q":"Según NEC Table 310.16, ¿cuál es la ampacidad de un conductor de cobre 14 AWG en la columna de 60°C?","opts":["25 A","20 A","15 A","30 A"],"re":"En la columna de 60°C de la Table 310.16, el cobre 14 AWG está clasificado para 15 A."},
  {"id":31,"q":"A lo largo de la encimera (countertop) de una cocina, los tomacorrientes que sirven la encimera deben instalarse de modo que ningún punto a lo largo de la línea de pared de la encimera esté a más de qué distancia de un tomacorriente?","opts":["24 pulgadas","20 pulgadas","12 pulgadas","30 pulgadas"],"re":"NEC 210.52(C) requiere que los tomacorrientes se coloquen de modo que ningún punto a lo largo de la línea de pared de la encimera esté a más de 24 in. de un tomacorriente, respaldando la regla de 'ningún punto a más de 24 in.' para un alcance de cordón de 2 ft."},
  {"id":32,"q":"¿Cuál es el propósito principal del dispositivo de protección de sobrecarga del motor requerido por NEC 430 Part III?","opts":["Proteger contra cortocircuitos entre conductores","Proteger el motor y los conductores contra la sobrecorriente sostenida debida a una sobrecarga del motor","Proporcionar desconexión instantánea durante una falla a tierra","Limitar los picos de voltaje durante el arranque del motor"],"re":"Los dispositivos de sobrecarga de NEC 430.32 protegen el motor, el aparato de control del motor y los conductores del circuito ramal contra el calentamiento excesivo debido a sobrecorrientes de funcionamiento (sobrecargas), no contra cortocircuitos ni fallas a tierra."},
  {"id":33,"q":"¿Cuál es el propósito del límite de arco eléctrico establecido según NFPA 70E?","opts":["Marca dónde la energía incidente equivale a 1.2 cal/cm2, el inicio de una quemadura de segundo grado en la piel descubierta","Indica la longitud máxima de un cordón de extensión permitido","Define el radio de curvatura mínimo para los conductores","Establece la distancia para la iluminación de emergencia requerida"],"re":"El límite de arco eléctrico es la distancia a la cual la energía incidente es de 1.2 cal/cm2; en este punto una persona desprotegida podría recibir una quemadura de segundo grado si ocurriera un arco eléctrico."},
  {"id":34,"q":"Cuatro resistencias de 100 ohmios se conectan en paralelo; ¿cuál es la resistencia equivalente?","opts":["400 ohmios","100 ohmios","25 ohmios","50 ohmios"],"re":"Para resistencias iguales en paralelo, R = R/n = 100/4 = 25 ohmios."},
  {"id":35,"q":"Las tres columnas de temperatura en NEC Table 310.16 representan ¿cuál propiedad del conductor?","opts":["Clasificaciones de temperatura del aislamiento","Rangos de temperatura ambiente","Porcentajes de llenado del conduit","Clasificaciones de clase de voltaje"],"re":"Las columnas de 60°C, 75°C y 90°C corresponden a la clasificación de temperatura del aislamiento del conductor. Véase NEC Table 310.16."},
  {"id":36,"q":"¿Qué dispositivo en un circuito ramal de motor está diseñado para proteger contra cortocircuitos y fallas a tierra en lugar de sobrecargas de funcionamiento?","opts":["El relé de sobrecarga térmica","El transformador de control","El contacto de retención del motor","El dispositivo de protección contra cortocircuito y falla a tierra del circuito ramal (fusible o interruptor)"],"re":"NEC 430 Part IV requiere un dispositivo de protección contra cortocircuito y falla a tierra del circuito ramal (típicamente un fusible o un interruptor automático de tiempo inverso) que es independiente del dispositivo de sobrecarga de funcionamiento de Part III."},
  {"id":37,"q":"En un circuito en serie con una resistencia de 30 ohmios y una de 60 ohmios a través de 90 V, ¿cuál es la corriente del circuito?","opts":["3 A","0.5 A","1 A","90 A"],"re":"R total = 30 + 60 = 90 ohmios; I = V/R = 90/90 = 1 A."},
  {"id":38,"q":"Cuando un conductor con aislamiento de 90°C termina en un equipo clasificado para 75°C, ¿qué columna de ampacidad debe usarse para la clasificación final de la terminación?","opts":["60°C","90°C","75°C","Promedio de 75°C y 90°C"],"re":"Según NEC 110.14(C), rige la clasificación de temperatura más baja de cualquier terminación o conductor conectado; aquí aplica la columna de 75°C."},
  {"id":39,"q":"Al aplicar el bloqueo/etiquetado según Cal/OSHA T8 Section 3314, ¿quién está autorizado a retirar un candado que un empleado autorizado colocó en un medio de desconexión?","opts":["Cualquier electricista del siguiente turno que necesite el circuito","Generalmente solo el empleado autorizado que aplicó ese candado, excepto mediante un procedimiento documentado cuando ese empleado no está disponible","El guardia de seguridad del sitio al final del día","Cualquier aprendiz que trabaje en la misma área"],"re":"Cal/OSHA T8 Section 3314 requiere que cada candado sea retirado por el empleado que lo aplicó; el retiro por otros solo se permite mediante un procedimiento documentado específico cuando ese empleado está ausente y el empleador verifica que es seguro."},
  {"id":40,"q":"¿De qué ancho mínimo debe ser un espacio de encimera de pared en una cocina antes de que se requiera una salida de tomacorriente para servirlo?","opts":["12 pulgadas","6 pulgadas","18 pulgadas","24 pulgadas"],"re":"NEC 210.52(C)(1) requiere un tomacorriente para cada espacio de encimera de pared que tenga 12 in. (300 mm) o más de ancho."},
  {"id":41,"q":"¿Por qué el dispositivo de protección contra cortocircuito y falla a tierra del circuito ramal de un motor típicamente está clasificado más alto que la corriente a plena carga del motor?","opts":["Porque también debe servir como el dispositivo de sobrecarga","Porque los conductores siempre están sobredimensionados","Porque debe permitir la alta corriente de irrupción (rotor bloqueado) durante el arranque del motor sin dispararse","Porque la corriente de la placa de identificación es inexacta"],"re":"Los motores consumen una gran corriente de irrupción/rotor bloqueado al arrancar, por lo que NEC 430.52 permite que el dispositivo de cortocircuito/falla a tierra se ajuste muy por encima de la FLC para que no se dispare por molestia, sin dejar de proteger contra fallas."},
  {"id":42,"q":"La columna de 90°C de una tabla de ampacidad se usa principalmente para ¿cuál propósito?","opts":["La carga final permitida en las terminales","Determinar el tamaño del conduit","Aplicar factores de reducción/corrección como punto de partida","Seleccionar directamente el tamaño del dispositivo de sobrecorriente"],"re":"La ampacidad de 90°C se usa comúnmente como valor de partida para los factores de ajuste y corrección, siempre que no se excedan las terminaciones. Véase NEC 110.14(C) y 310.15."},
  {"id":43,"q":"Una carga monofásica consume 16 A a 240 V; ¿cuál es la potencia aparente en voltio-amperios?","opts":["3840 VA","15 VA","256 VA","1920 VA"],"re":"Potencia aparente S = V x I = 240 x 16 = 3840 VA."},
  {"id":44,"q":"¿Qué requiere establecer una condición de trabajo eléctricamente segura después de que se abre el medio de desconexión?","opts":["Comenzar el trabajo de inmediato ya que el interruptor está apagado","Esperar 24 horas antes de cualquier prueba","Verificar visualmente que la desconexión esté abierta, aplicar bloqueo/etiquetado, probar la ausencia de voltaje y poner a tierra donde pueda haber energía inducida o almacenada","Llamar a la empresa de servicios para confirmar la lectura del medidor"],"re":"NFPA 70E enumera los pasos para establecer una condición de trabajo eléctricamente segura, incluido verificar que la desconexión esté abierta, aplicar LOTO, probar la ausencia de voltaje con un dispositivo de clasificación adecuada y aplicar conexiones a tierra donde pudiera existir voltaje almacenado o inducido."},
  {"id":45,"q":"Cuando la temperatura ambiente excede los 30°C (86°F), la ampacidad del conductor de la Table 310.16 debe ser:","opts":["Multiplicada por un factor de corrección menor que 1.0","Aumentada por el factor de corrección","Dejada sin cambios","Multiplicada por 1.25"],"re":"Las temperaturas ambiente más altas reducen la ampacidad, por lo que se aplica un factor de corrección menor que 1.0 de la Table 310.15(B)(1)."},
  {"id":46,"q":"¿Qué corriente consume un calefactor resistivo monofásico de 1500 W en un circuito de 120 V?","opts":["12.5 A","180000 A","0.08 A","8 A"],"re":"I = P/V = 1500/120 = 12.5 A (resistivo, PF = 1)."},
  {"id":47,"q":"En un motor de inducción trifásico estándar, ¿cómo se invierte la dirección de rotación?","opts":["Invirtiendo los tres conductores de línea","Invirtiendo la conexión del conductor de puesta a tierra del equipo","Intercambiando dos cualesquiera de los tres conductores de línea","Aumentando el voltaje de alimentación"],"re":"Intercambiar dos cualesquiera de los tres conductores de línea invierte la secuencia de fases, lo que invierte la dirección del campo magnético giratorio y, por tanto, la rotación del motor."},
  {"id":48,"q":"¿Cuál de las siguientes tareas puede realizar una persona no calificada cerca de equipos eléctricos energizados?","opts":["Abrir un centro de control de motores energizado para diagnosticar fallas","Trabajo fuera del límite de aproximación limitada, donde no hay exposición a partes energizadas","Cruzar el límite de aproximación restringida para tomar mediciones","Reemplazar conexiones de barra energizadas durante un corte"],"re":"Según NFPA 70E, una persona no calificada puede trabajar fuera del límite de aproximación limitada; no se le permite cruzarlo hacia partes energizadas expuestas a menos que sea escoltada continuamente por una persona calificada, e incluso entonces no puede realizar el trabajo calificado."},
  {"id":49,"q":"Una encimera de isla de cocina con una dimensión larga de 24 in. o mayor y una dimensión corta de 12 in. o mayor generalmente requiere al menos cuántas salidas de tomacorriente?","opts":["Cero","Tres","Dos","Una"],"re":"NEC 210.52(C) requiere al menos una salida de tomacorriente para un espacio de encimera de isla que cumpla con las dimensiones mínimas de 24 in. por 12 in."},
  {"id":50,"q":"Las tablas de ampacidad como la Table 310.16 se basan en una temperatura ambiente supuesta de:","opts":["30°C (86°F)","20°C (68°F)","40°C (104°F)","60°C (140°F)"],"re":"La Table 310.16 se basa en una temperatura ambiente de 30°C (86°F); otras temperaturas ambiente requieren factores de corrección. Véase NEC 310.15(B)."},
  {"id":51,"q":"Una resistencia disipa 600 W con una corriente de 5 A; ¿cuál es su resistencia?","opts":["120 ohmios","24 ohmios","3000 ohmios","0.042 ohmios"],"re":"A partir de P = I al cuadrado x R, R = P / I al cuadrado = 600 / 25 = 24 ohmios."},
  {"id":52,"q":"Un motor trifásico conectado a las líneas L1-T1, L2-T2, L3-T3 está girando en la dirección incorrecta; ¿qué cambio corregirá la rotación?","opts":["Intercambiar solo L1 y L2","Intercambiar los tres conductores simultáneamente","Reconectar el neutro","Agregar un capacitor de desfase"],"re":"Invertir dos conductores cualesquiera invierte la rotación; intercambiar L1 y L2 (o cualquier par único) invierte la secuencia de fases y corrige la dirección."},
  {"id":53,"q":"Si un conductor de 90°C se instala en una temperatura ambiente de 50°C, ¿por qué es ventajoso partir de la columna de 90°C?","opts":["Su mayor ampacidad base absorbe mejor la corrección por temperatura","Evita cualquier reducción","Elimina la necesidad de factores de corrección","Permite un dispositivo de sobrecorriente más pequeño"],"re":"Usar la mayor ampacidad base de 90°C da más margen cuando el factor de corrección por temperatura ambiente reduce el valor, según lo permitido por NEC 310.15(B) y 110.14(C)."},
  {"id":54,"q":"¿Cuál es el peligro principal contra el que está diseñado el EPP de arco eléctrico?","opts":["Caídas desde plataformas de trabajo elevadas","Quemaduras térmicas por el calor radiante y convectivo de un arco eléctrico","Pérdida auditiva por maquinaria giratoria","Salpicaduras químicas del electrolito de baterías"],"re":"El EPP con clasificación de arco se selecciona en función de la energía incidente para proteger al trabajador de la intensa energía térmica de un arco eléctrico; se clasifica en cal/cm2 para igualar o exceder la energía incidente calculada."},
  {"id":55,"q":"¿Qué voltaje se requiere para hacer pasar 4 A a través de una resistencia de 35 ohmios?","opts":["140 V","8.75 V","0.114 V","39 V"],"re":"Por la ley de Ohm, V = I x R = 4 x 35 = 140 V."},
  {"id":56,"q":"En un arrancador magnético de motor, ¿cuál es la función del contacto de retención (de sostenimiento) en el circuito de control?","opts":["Abrir el circuito durante una condición de sobrecarga","Mantener energizada la bobina del arrancador después de soltar el botón momentáneo de arranque","Reducir el voltaje de control","Invertir la rotación del motor"],"re":"El contacto de retención es un contacto auxiliar cableado en paralelo con el botón de arranque; una vez que la bobina se energiza, se cierra y mantiene la alimentación de la bobina para que el motor siga funcionando después de soltar el botón de arranque."},
  {"id":57,"q":"De acuerdo con la Table 310.15(C)(1), ¿qué factor de ajuste aplica cuando se agrupan de 4 a 6 conductores portadores de corriente en una canalización?","opts":["100%","80%","70%","50%"],"re":"Para 4 a 6 conductores portadores de corriente, el factor de ajuste es 80%. Véase NEC Table 310.15(C)(1)."},
  {"id":58,"q":"Los tomacorrientes instalados para servir las superficies de encimera de cocina de una vivienda deben ser alimentados por al menos cuántos circuitos ramales para electrodomésticos pequeños?","opts":["Un circuito de 15 amperios","Dos circuitos de 20 amperios","Un circuito de 30 amperios","Tres circuitos de 15 amperios"],"re":"NEC 210.11(C)(1) y 210.52(B) requieren al menos dos circuitos ramales de 20 amperios para electrodomésticos pequeños que sirvan los tomacorrientes de la encimera y otros en la cocina, despensa y áreas de comedor."},
  {"id":59,"q":"Según el método de categoría de EPP de NFPA 70E, ¿qué determina cuál categoría de EPP de arco eléctrico aplica a una tarea?","opts":["El color del gabinete del equipo","Los parámetros específicos del equipo y de la tarea enumerados en las tablas de categoría de EPP de arco eléctrico, incluidos el voltaje y la corriente de falla disponible","La potencia total en caballos de fuerza de todos los motores conectados","La antigüedad del tablero eléctrico"],"re":"Las tablas de categoría de EPP de NFPA 70E asignan una categoría (1 a 4) según el tipo específico de equipo, la corriente de cortocircuito disponible y el tiempo de despeje de falla, que en conjunto estiman la exposición al arco eléctrico."},
  {"id":60,"q":"Un electrodoméstico de 2000 W opera durante 3 horas; ¿cuánta energía consume?","opts":["0.67 kWh","667 Wh","6 kWh","6000 kWh"],"re":"Energía = potencia x tiempo = 2000 W x 3 h = 6000 Wh = 6 kWh."},
  {"id":61,"q":"En un circuito de control estándar de arranque/paro de tres hilos, ¿cómo se cablean típicamente los botones de arranque y paro?","opts":["El de arranque es normalmente cerrado y el de paro es normalmente abierto","Ambos botones son normalmente cerrados y en paralelo","El de arranque (normalmente abierto) está en paralelo con el contacto de retención, y el de paro (normalmente cerrado) está en serie","Ambos botones son normalmente abiertos y en serie"],"re":"Una estación estándar de arranque/paro usa un botón de arranque normalmente abierto (en paralelo con el contacto de retención para sellarse) y un botón de paro normalmente cerrado en serie, de modo que al presionar paro se desenergiza la bobina."},
  {"id":62,"q":"Según la Table 310.15(C)(1), ¿qué factor de ajuste aplica cuando se tienden juntos de 7 a 9 conductores portadores de corriente en una canalización?","opts":["60%","80%","70%","50%"],"re":"Para 7 a 9 conductores portadores de corriente, el factor de ajuste es 70%. Véase NEC Table 310.15(C)(1)."},
  {"id":63,"q":"Al realizar la prueba vivo-muerto-vivo, ¿por qué debe verificarse el comprobador de voltaje en una fuente energizada conocida tanto antes como después de probar el circuito desenergizado?","opts":["Para cargar la batería interna del comprobador","Para confirmar que el comprobador funciona correctamente y no se confíe en una lectura falsa de 'muerto'","Para calibrar el comprobador a la frecuencia de la empresa de servicios local","Para descargar la capacitancia almacenada en los conductores"],"re":"Volver a verificar el comprobador en una fuente viva conocida después de la prueba de 'muerto' confirma que el instrumento no falló durante la prueba, asegurando que la lectura de ausencia de voltaje era válida antes de tocar los conductores."},
  {"id":64,"q":"Si la electricidad cuesta 0.20 dólares por kWh, ¿cuánto cuesta operar una carga de 5 kW durante 8 horas?","opts":["40.00 dólares","1.60 dólares","8.00 dólares","0.20 dólares"],"re":"Energía = 5 kW x 8 h = 40 kWh; costo = 40 x 0.20 = 8.00 dólares."},
  {"id":65,"q":"¿A partir de qué número de conductores portadores de corriente en una sola canalización comienzan a aplicar los factores de ajuste de la Table 310.15(C)(1)?","opts":["2 o más","Más de 3 (4 o más)","3 o más","Más de 9"],"re":"Los factores de ajuste comienzan cuando hay más de tres conductores portadores de corriente (es decir, 4 o más). Véase NEC 310.15(C)(1)."},
  {"id":66,"q":"¿Cuál es la diferencia principal entre un contactor y un arrancador magnético de motor?","opts":["Un contactor incluye protección de sobrecarga integrada, pero un arrancador no","Un contactor solo puede conmutar cargas de CC","Un arrancador es esencialmente un contactor con protección de sobrecarga integral añadida","Un arrancador no tiene bobina electromagnética"],"re":"Un arrancador magnético de motor es un contactor combinado con un relé de sobrecarga; un contactor simple conmuta la carga pero no proporciona protección de sobrecarga de funcionamiento."},
  {"id":67,"q":"En una vivienda, los pasillos de al menos qué longitud requieren un mínimo de una salida de tomacorriente?","opts":["15 pies","5 pies","12 pies","10 pies"],"re":"NEC 210.52(H) requiere que los pasillos de 10 ft (3.0 m) o más de longitud tengan al menos una salida de tomacorriente."},
  {"id":68,"q":"Un motor entrega 10 HP de salida mecánica; ¿aproximadamente cuántos watts son?","opts":["746 W","7460 W","1340 W","74.6 W"],"re":"Usando 1 HP = 746 W, 10 HP = 10 x 746 = 7460 W."},
  {"id":69,"q":"Según NFPA 70E, ¿qué condición justifica realizar trabajo en conductores eléctricos energizados en lugar de desenergizarlos?","opts":["La cuadrilla quiere terminar el trabajo más rápido","El supervisor prefiere verbalmente el trabajo energizado","Desenergizar introduciría peligros adicionales o mayores, o es inviable debido al diseño del equipo o a limitaciones operativas","El equipo está clasificado por encima de 600 voltios"],"re":"NFPA 70E permite el trabajo energizado solo cuando desenergizar introduce peligros adicionales o mayores (como apagar un soporte vital) o es inviable debido al diseño del equipo o a limitaciones operativas; la conveniencia o el ahorro de tiempo no califican."},
  {"id":70,"q":"Seis conductores de cobre THHN 12 AWG portadores de corriente (valor de 90°C de 30 A) comparten un conduit; después de aplicar el ajuste por agrupamiento, la ampacidad ajustada es aproximadamente:","opts":["30 A","27 A","21 A","24 A"],"re":"Partiendo del valor de 90°C de 30 A y aplicando el factor del 80% para 4 a 6 conductores se obtiene 30 × 0.80 = 24 A. Véase NEC Table 310.15(C)(1)."},
  {"id":71,"q":"Cuando el relé de sobrecarga de un arrancador magnético de motor se dispara, ¿qué circuito abre directamente para detener el motor?","opts":["El circuito de control, desenergizando la bobina del arrancador","Los conductores principales de potencia (línea) hacia el motor","El conductor de puesta a tierra del equipo","El alimentador del circuito ramal"],"re":"Los contactos del relé de sobrecarga están cableados en el circuito de control; cuando se disparan y abren, la bobina del arrancador se desenergiza, liberando los contactos principales y desconectando el motor."},
  {"id":72,"q":"Un motor de 5 HP es 100 por ciento eficiente y funciona a 240 V monofásico con PF 1; ¿qué corriente consume?","opts":["3730 A","15.5 A","0.064 A","31 A"],"re":"P = 5 x 746 = 3730 W; I = P/V = 3730/240 = 15.5 A."},
  {"id":73,"q":"Ocho conductores portadores de corriente con una ampacidad base de 90°C de 40 A cada uno se agrupan en una canalización; la ampacidad ajustada es:","opts":["40 A","36 A","28 A","32 A"],"re":"Para 7 a 9 conductores el factor es 70%, así que 40 × 0.70 = 28 A. Véase NEC Table 310.15(C)(1)."},
  {"id":74,"q":"¿Cuál es la función del límite de aproximación limitada según NFPA 70E?","opts":["Es la distancia desde una parte energizada expuesta dentro de la cual existe un peligro de descarga","Es el alcance máximo de un camión con canastilla","Marca el borde del sistema de electrodos de puesta a tierra del equipo","Es el límite para la cobertura de rociadores contra incendios"],"re":"El límite de aproximación limitada es la distancia desde un conductor o parte de circuito energizada expuesta dentro de la cual existe un peligro de descarga; las personas no calificadas no deben cruzarlo sin un escolta calificado."},
  {"id":75,"q":"En un circuito de control de motor típico que usa un transformador de control, ¿qué voltaje se suministra más comúnmente al circuito de control?","opts":["480 voltios","240 voltios","24 voltios","120 voltios"],"re":"Los transformadores de control comúnmente reducen el voltaje de línea a 120 voltios para el circuito de control, proporcionando un voltaje más seguro y estandarizado para los dispositivos piloto y las bobinas."},
  {"id":76,"q":"Una unidad de vivienda debe tener al menos cuántas salidas de tomacorriente instaladas por cada baño, ubicadas adyacentes a cada lavabo?","opts":["No se requiere ninguna","Al menos dos por baño","Una solo si la habitación excede 50 sq ft","Al menos una dentro de 36 in. del borde exterior de cada lavabo"],"re":"NEC 210.52(D) requiere al menos una salida de tomacorriente instalada dentro de 36 in. del borde exterior de cada lavabo (lavamanos) de baño."},
  {"id":77,"q":"Un motor tiene una entrada de 5000 W y una salida de 4000 W; ¿cuál es su eficiencia?","opts":["125 por ciento","80 por ciento","20 por ciento","90 por ciento"],"re":"Eficiencia = salida/entrada = 4000/5000 = 0.80 = 80 por ciento."},
  {"id":78,"q":"En un circuito monofásico de 3 hilos, 120/240 voltios, normalmente balanceado, el conductor neutro es:","opts":["Siempre contado como conductor portador de corriente","Contado solo si la carga supera los 50 amperios","No contado como conductor portador de corriente","Contado como dos conductores"],"re":"El neutro de un circuito monofásico balanceado de 3 hilos solo conduce la corriente desbalanceada y no se cuenta como portador de corriente. Véase NEC 310.15(E)."},
  {"id":79,"q":"Antes de energizar equipo recién instalado después del mantenimiento según Cal/OSHA T8 Section 3314, ¿qué debe verificarse?","opts":["Que el papeleo de la garantía esté archivado","Que la pintura del gabinete se haya secado","Que todos los empleados estén despejados, las herramientas retiradas, las guardas reinstaladas y que cada trabajador haya retirado su propio candado antes de reenergizar","Que la factura de servicios se haya pagado"],"re":"Cal/OSHA T8 Section 3314 requiere que antes de reenergizar, se inspeccione el área de trabajo para asegurar que se hayan retirado los elementos no esenciales, los componentes estén intactos, los empleados estén despejados y cada empleado autorizado retire su propio dispositivo de bloqueo."},
  {"id":80,"q":"¿Qué utiliza un arrancador magnético reversible para cambiar la dirección de un motor trifásico?","opts":["Un solo contactor con una bobina reversible","Dos contactores (avance y retroceso) que intercambian dos de los conductores de línea","Una resistencia variable en el circuito del rotor","Un banco de capacitores conmutado en la línea"],"re":"Un arrancador reversible usa dos contactores enclavados mecánica y eléctricamente; el contactor de retroceso está cableado para intercambiar dos de los tres conductores de línea, invirtiendo la rotación."},
  {"id":81,"q":"¿Cuándo se requiere contar el conductor neutro de un circuito en estrella (wye) trifásico de 4 hilos como conductor portador de corriente?","opts":["Nunca","Solo cuando conduce corriente desbalanceada de una carga lineal","Cuando la mayor parte de la carga consiste en cargas no lineales","Solo en sistemas de 480Y/277 voltios"],"re":"Según NEC 310.15(E), el neutro se cuenta cuando la mayor parte de la carga es no lineal (armónica), porque entonces conduce corriente significativa."},
  {"id":82,"q":"Un motor entrega 3 HP en el eje con una eficiencia del 75 por ciento; ¿cuál es la potencia eléctrica de entrada?","opts":["2984 W","1678 W","2238 W","1119 W"],"re":"Salida = 3 x 746 = 2238 W; entrada = salida/eficiencia = 2238/0.75 = 2984 W."},
  {"id":83,"q":"Un análisis de peligro de arco eléctrico determina principalmente cuáles dos elementos clave para una pieza de equipo?","opts":["El color del aislamiento del conductor y el tamaño del conduit","El fabricante del interruptor y el número de catálogo","La temperatura ambiente y la humedad","La energía incidente (o categoría de EPP) y el límite de arco eléctrico"],"re":"Una evaluación de riesgo de arco eléctrico establece la energía incidente (o asigna una categoría de EPP) y el límite de arco eléctrico para poder seleccionar el EPP con clasificación de arco correcto y conocer la distancia de protección."},
  {"id":84,"q":"En un circuito de 3 hilos tomado de dos fases y el neutro de un sistema trifásico en estrella (wye) de 4 hilos, el neutro es:","opts":["No contado como portador de corriente","Contado como conductor portador de corriente","Contado como medio conductor","Permitido ser más pequeño que las fases"],"re":"Según NEC 310.15(E), el neutro de tal circuito en estrella de 3 hilos conduce aproximadamente la misma corriente que los conductores de fase y se cuenta como portador de corriente."},
  {"id":85,"q":"¿Por qué los contactores de avance y retroceso en un arrancador reversible están enclavados mecánica y eléctricamente?","opts":["Para evitar que ambos contactores se cierren al mismo tiempo, lo que causaría un cortocircuito de línea a línea","Para aumentar el par del motor","Para reducir el voltaje de control","Para permitir la operación simultánea en dos direcciones"],"re":"El enclavamiento asegura que solo un contactor de dirección pueda energizarse a la vez; cerrar ambos conectaría dos fases entre sí a través de los conductores intercambiados, creando un cortocircuito de fase a fase."},
  {"id":86,"q":"Un vestíbulo (foyer) de una unidad de vivienda que no es parte de un pasillo y tiene un área mayor a 60 sq ft requiere salidas de tomacorriente en cualquier espacio de pared de qué ancho o mayor?","opts":["3 ft","2 ft","1 ft","4 ft"],"re":"NEC 210.52(I) requiere salidas de tomacorriente en vestíbulos mayores a 60 sq ft para cada espacio de pared de 3 ft (900 mm) o más de ancho que no esté interrumpido por puertas y aberturas similares."},
  {"id":87,"q":"Un motor monofásico consume 10 A a 240 V y entrega 1800 W de potencia real; ¿cuál es su factor de potencia?","opts":["0.90","1.33","0.50","0.75"],"re":"PF = P / (V x I) = 1800 / (240 x 10) = 1800/2400 = 0.75."},
  {"id":88,"q":"Un conductor de puesta a tierra del equipo (EGC) tendido en la misma canalización que los conductores del circuito se cuenta como cuántos conductores portadores de corriente?","opts":["Uno","Dos","Cero","Depende de su tamaño"],"re":"Los conductores de puesta a tierra y de unión no se cuentan como conductores portadores de corriente para fines de ajuste. Véase NEC 310.15(E)."},
  {"id":89,"q":"¿Qué dispositivo es apropiado para verificar la ausencia de voltaje durante el paso de probar antes de tocar?","opts":["Un detector tipo pluma sin contacto usado por sí solo como único medio","Un ohmímetro de continuidad ajustado a la escala de resistencia","Un amperímetro de gancho leyendo la corriente de carga","Un comprobador de voltaje de contacto con clasificación adecuada, confirmado en funcionamiento antes y después de la prueba"],"re":"NFPA 70E requiere un detector o comprobador de voltaje con clasificación adecuada para verificar la ausencia de voltaje, y el dispositivo debe probarse para su correcto funcionamiento inmediatamente antes y después de la prueba de ausencia de voltaje."},
  {"id":90,"q":"¿Cuál es la potencia real de una carga monofásica que consume 20 A a 120 V con un factor de potencia de 0.85?","opts":["2400 W","102 W","2823 W","2040 W"],"re":"Potencia real P = V x I x PF = 120 x 20 x 0.85 = 2040 W."},
  {"id":91,"q":"¿En qué se diferencia un motor de inducción monofásico de un motor de inducción trifásico respecto al arranque?","opts":["Un motor monofásico requiere un método de arranque auxiliar (como un devanado de arranque), mientras que un motor trifásico es de arranque automático","Un motor monofásico es inherentemente de arranque automático sin medios auxiliares","Un motor trifásico no puede arrancar bajo carga","Ambos requieren un capacitor para arrancar"],"re":"Un motor trifásico produce un campo magnético giratorio y es de arranque automático; el campo pulsante de un motor monofásico no lo es, por lo que necesita un devanado de arranque (y a menudo un capacitor) para desarrollar par de arranque."},
  {"id":92,"q":"¿Cuál es el tamaño mínimo de conductor generalmente permitido para conductores instalados en paralelo?","opts":["4 AWG","1/0 AWG","1 AWG","2/0 AWG"],"re":"NEC 310.10(G) (conductores en paralelo) permite el paralelaje solo para tamaños 1/0 AWG y mayores, con excepciones limitadas."},
  {"id":93,"q":"Según Cal/OSHA T8 Section 3314, ¿qué debe hacerse con la energía almacenada (como capacitores cargados o tensión de resortes) durante el bloqueo?","opts":["Puede ignorarse si la desconexión principal está bloqueada en posición abierta","Debe aumentarse para probar el equipo","Debe liberarse, desconectarse, restringirse o hacerse segura de otra manera antes de comenzar el trabajo","Debe medirse pero dejarse en su lugar"],"re":"Cal/OSHA T8 Section 3314 requiere que la energía almacenada o residual sea disipada o restringida de modo que no pueda causar lesiones; bloquear la desconexión por sí solo no aborda la energía capacitiva o mecánica almacenada."},
  {"id":94,"q":"Un circuito monofásico conduce 25 A a lo largo de un tendido de un solo sentido donde la resistencia total del conductor para el tendido es de 0.4 ohmios; ¿cuál es la caída de voltaje?","opts":["10 V","62.5 V","0.016 V","100 V"],"re":"Caída de voltaje Vd = I x R = 25 x 0.4 = 10 V."},
  {"id":95,"q":"¿Qué ubicación de vivienda requiere que los tomacorrientes de 125 voltios, 15 y 20 amperios estén protegidos con GFCI?","opts":["Un clóset de dormitorio","Un baño","Un espacio de gateo en el ático sin equipos","Un comedor formal"],"re":"NEC 210.8(A) incluye los baños entre las ubicaciones de vivienda donde los tomacorrientes de 125 voltios, 15 y 20 amperios deben tener protección de interruptor de circuito por falla a tierra (GFCI)."},
  {"id":96,"q":"En un motor monofásico de arranque por capacitor, ¿cuál es el propósito del capacitor de arranque?","opts":["Crear un desfase en el devanado de arranque para que el motor desarrolle par de arranque","Mejorar continuamente el factor de potencia de funcionamiento","Limitar la corriente de rotor bloqueado al devanado de funcionamiento","Convertir la potencia monofásica en trifásica"],"re":"El capacitor de arranque desfasa la corriente en el devanado de arranque respecto al devanado de funcionamiento, produciendo un campo giratorio que proporciona un alto par de arranque."},
  {"id":97,"q":"Cuando los conductores se instalan en paralelo, los conductores en paralelo de cada fase deben ser:","opts":["De diferentes tamaños para balancear la carga","De la misma longitud, material y tamaño","De diferentes tipos de aislamiento","Conectados con diferentes terminaciones"],"re":"Según NEC 310.10(G), los conductores en paralelo de cada fase deben ser idénticos en longitud, material, tamaño y aislamiento, y terminados de la misma manera."},
  {"id":98,"q":"Un circuito ramal de 120 V tiene una caída de voltaje medida de 6 V; ¿cuál es el porcentaje de caída de voltaje?","opts":["20 por ciento","0.5 por ciento","2 por ciento","5 por ciento"],"re":"Porcentaje de caída = Vd/Vfuente x 100 = 6/120 x 100 = 5 por ciento."},
  {"id":99,"q":"¿Cuándo puede una persona no calificada cruzar el límite de aproximación limitada hacia una parte energizada expuesta?","opts":["Nunca, bajo ninguna circunstancia","En cualquier momento, siempre que use lentes de seguridad","Solo durante las horas de luz del día","Solo cuando es escoltada o asesorada continuamente por una persona calificada y está debidamente protegida"],"re":"NFPA 70E permite que una persona no calificada cruce el límite de aproximación limitada solo cuando es escoltada continuamente por una persona calificada que la advierte de los peligros y garantiza su protección; aun así, no puede realizar el trabajo calificado."},
  {"id":100,"q":"En un motor de arranque por capacitor e inducción de funcionamiento, ¿qué dispositivo desconecta el devanado de arranque una vez que el motor alcanza aproximadamente el 75% de la velocidad plena?","opts":["Un relé de sobrecarga térmica","Un interruptor centrífugo","Un contactor magnético","Un transformador de control"],"re":"Un interruptor centrífugo (o relé equivalente) se abre para retirar el devanado de arranque y el capacitor de arranque del circuito una vez que el motor se acerca a la velocidad de funcionamiento."},
  {"id":101,"q":"Se instalan dos conductores de cobre de 250 kcmil por fase en paralelo; eléctricamente se comportan como:","opts":["Un conductor de 250 kcmil","Un conductor con la mitad de la ampacidad","Un solo conductor con aproximadamente el doble de ampacidad","Dos circuitos ramales separados"],"re":"Los conductores en paralelo comparten la carga y se tratan como un solo conductor con ampacidad combinada (aproximadamente el doble). Vea NEC 310.10(G)."},
  {"id":102,"q":"En un alimentador de 240 V, los conductores tienen una resistencia total de 0.15 ohms y conducen 40 A; ¿cuál es el porcentaje de caída de tensión?","opts":["2.5 por ciento","6 V","0.6 por ciento","25 por ciento"],"re":"Vd = 40 x 0.15 = 6 V; porcentaje = 6/240 x 100 = 2.5 por ciento."},
  {"id":103,"q":"Los receptáculos de una unidad de vivienda instalados para servir las superficies de mostrador de la cocina deben contar con qué tipo de protección?","opts":["Solo AFCI","Solo protección contra sobretensiones","Protección GFCI","Ninguna protección especial"],"re":"NEC 210.8(A) exige protección GFCI para los receptáculos que sirven las superficies de mostrador de la cocina en viviendas."},
  {"id":104,"q":"¿Cuál es el menor tamaño de conductor de cobre para circuito ramal que generalmente se permite para un circuito ramal de uso general de 15 amperes?","opts":["12 AWG","16 AWG","14 AWG","10 AWG"],"re":"El 14 AWG de cobre es el conductor de circuito ramal estándar más pequeño (15 A); se requiere 12 AWG para circuitos de 20 A. Vea NEC 210.19 y la Tabla 310.16."},
  {"id":105,"q":"¿Qué información debe incluir típicamente un permiso de trabajo eléctrico energizado según la NFPA 70E?","opts":["El horario de almuerzo en el sitio de trabajo y la asignación de estacionamiento","El precio de venta al público de las piezas de repuesto","Los nombres de todos los empleados anteriores que dieron servicio al equipo","Una descripción del trabajo, la justificación para el trabajo energizado, los resultados de la evaluación de riesgo de descarga y arco eléctrico, y el EPP requerido"],"re":"La NFPA 70E especifica que el permiso de trabajo energizado incluya la descripción del circuito/equipo, la justificación para trabajar energizado, los resultados de las evaluaciones de riesgo de descarga y arco eléctrico, el EPP requerido y las firmas de aprobación de la gerencia."},
  {"id":106,"q":"Un motor monofásico de arranque por capacitor zumba pero no arranca y no gira; ¿cuál falla es la causa más probable?","opts":["El devanado de marcha está abierto","El capacitor de arranque o el circuito del devanado de arranque está abierto (por ejemplo, un capacitor o un interruptor centrífugo defectuoso)","La tensión de alimentación es demasiado alta","Los cojinetes del motor tienen exceso de grasa"],"re":"El zumbido sin arrancar típicamente indica que el devanado de marcha está energizado pero el circuito de arranque (capacitor, devanado de arranque o interruptor centrífugo) está abierto, por lo que no se produce par de arranque."},
  {"id":107,"q":"Usando la fórmula monofásica de caída de tensión Vd = 2 x K x I x L / CM, con K = 12.9, I = 20 A, L = 100 ft y CM = 10380, ¿cuál es la caída de tensión aproximada?","opts":["2.48 V","4.97 V","9.94 V","0.50 V"],"re":"Vd = (2 x 12.9 x 20 x 100)/10380 = 51600/10380 = 4.97 V."},
  {"id":108,"q":"¿Cuál es el menor tamaño de conductor de cobre permitido para un circuito ramal de 20 amperes?","opts":["16 AWG","12 AWG","14 AWG","10 AWG"],"re":"Un circuito ramal de 20 amperes requiere un conductor de cobre mínimo de 12 AWG según NEC 240.4(D) y la Tabla 310.16."},
  {"id":109,"q":"¿Cuál es la función principal de un variador de frecuencia (VFD) conectado a un motor de inducción de CA?","opts":["Controlar la velocidad del motor variando la frecuencia (y la tensión) suministrada al motor","Convertir CA a CC para el motor","Proporcionar únicamente protección contra sobrecarga","Corregir el factor de potencia del lado de la empresa de servicios"],"re":"Un VFD ajusta la frecuencia de salida y, proporcionalmente, la tensión hacia el motor; dado que la velocidad sincrónica es proporcional a la frecuencia, esto controla la velocidad del motor."},
  {"id":110,"q":"¿Por qué la NFPA 70E enfatiza desenergizar el equipo en lugar de depender únicamente del EPP?","opts":["El EPP es más costoso que desenergizar","Eliminar el peligro al desenergizar es más eficaz que el EPP, el cual solo mitiga las consecuencias si ocurre un incidente","El EPP no se puede limpiar después de usarlo","Desenergizar se requiere únicamente por razones estéticas"],"re":"La NFPA 70E sigue la jerarquía de controles de riesgo, donde la eliminación (desenergizar) es el control más eficaz y el EPP es la última línea de defensa que solo reduce la gravedad de la lesión si ocurre un arco o una descarga."},
  {"id":111,"q":"Una carga resistiva monofásica de 240 V consume 4800 W; ¿cuál es su resistencia?","opts":["12 ohms","20 ohms","0.05 ohms","50 ohms"],"re":"A partir de P = V al cuadrado / R, R = V al cuadrado / P = 57600 / 4800 = 12 ohms."},
  {"id":112,"q":"Según NEC 240.4(D), ¿cuál es la máxima protección contra sobrecorriente que generalmente se permite para conductores de cobre de 14 AWG?","opts":["10 A","20 A","15 A","25 A"],"re":"NEC 240.4(D) limita el 14 AWG de cobre a un dispositivo de sobrecorriente máximo de 15 amperes, sin importar su ampacidad tabulada mayor."},
  {"id":113,"q":"¿Cuál de las siguientes ubicaciones de receptáculos en una vivienda generalmente requiere protección GFCI?","opts":["Una pared de la sala de estar","Exteriores","Una pared del dormitorio","Un pasillo central"],"re":"NEC 210.8(A) exige protección GFCI para los receptáculos de 125 voltios, 15 y 20 amperes ubicados en exteriores de las viviendas."},
  {"id":114,"q":"Un VFD generalmente controla la velocidad de un motor de inducción de CA manteniendo qué relación entre la tensión y la frecuencia?","opts":["Tensión cero a baja frecuencia","Una corriente constante sin importar la frecuencia","Tensión máxima en todas las frecuencias","Una relación constante de volts por hertz (V/Hz)"],"re":"Para mantener un flujo magnético y una capacidad de par constantes en todo el rango de velocidad, un VFD típicamente mantiene una relación constante de volts por hertz mientras varía la frecuencia de salida."},
  {"id":115,"q":"¿Cuál de las siguientes describe mejor la frontera de aproximación restringida en comparación con la frontera de aproximación limitada?","opts":["La frontera de aproximación restringida está más cerca de la parte energizada y considera el mayor riesgo debido al arco eléctrico más el movimiento involuntario","La frontera de aproximación restringida está más lejos de la parte energizada que la frontera de aproximación limitada","Las dos fronteras siempre están a la misma distancia","La frontera de aproximación restringida se aplica únicamente a peligros mecánicos"],"re":"La frontera de aproximación restringida está más cerca de la parte energizada expuesta que la frontera de aproximación limitada; cruzarla requiere una persona calificada con el EPP apropiado debido a la mayor probabilidad de arco combinada con el movimiento involuntario."},
  {"id":116,"q":"Según NEC 240.4(D), el dispositivo de sobrecorriente máximo para conductores de cobre de 12 AWG generalmente es:","opts":["30 A","25 A","15 A","20 A"],"re":"NEC 240.4(D) limita el 12 AWG de cobre a un dispositivo de sobrecorriente máximo de 20 amperes."},
  {"id":117,"q":"Tres lámparas de 60 W cada una a 120 V se conectan en paralelo; ¿cuál es la corriente total consumida?","opts":["0.5 A","180 A","4.5 A","1.5 A"],"re":"P total = 3 x 60 = 180 W; I = P/V = 180/120 = 1.5 A."},
  {"id":118,"q":"¿Cuál es un beneficio común de arrancar un motor de CA con un VFD en lugar de un arranque directo a la línea?","opts":["Aumenta la corriente de irrupción a rotor bloqueado","Proporciona un arranque suave con reducción de la corriente de irrupción y del esfuerzo mecánico","Elimina la necesidad de cualquier protección contra sobrecarga","Requiere que el motor sea de tipo sincrónico"],"re":"Un VFD aumenta gradualmente la frecuencia y la tensión, proporcionando un arranque suave que reduce considerablemente la corriente de irrupción y el esfuerzo mecánico/eléctrico en comparación con el arranque directo a la línea."},
  {"id":119,"q":"Según Cal/OSHA T8 Sección 3314, ¿cuándo se considera aceptable un dispositivo de etiquetado solo (sin un candado)?","opts":["Cuando el trabajador prefiera etiquetas en lugar de candados","En cualquier momento en que el equipo supere los 480 voltios","Solo cuando el dispositivo de aislamiento de energía no se pueda bloquear, y medidas de seguridad adicionales proporcionen una protección equivalente al bloqueo","Solo los fines de semana"],"re":"Cal/OSHA T8 Sección 3314 permite el etiquetado solo únicamente cuando el dispositivo de aislamiento de energía no puede aceptar un candado, y entonces el empleador debe proporcionar protección total al empleado equivalente a la de un programa de bloqueo."},
  {"id":120,"q":"Según NEC 240.4(D), el dispositivo de sobrecorriente máximo para conductores de cobre de 10 AWG generalmente es:","opts":["20 A","30 A","25 A","40 A"],"re":"NEC 240.4(D) limita el 10 AWG de cobre a un dispositivo de sobrecorriente máximo de 30 amperes."},
  {"id":121,"q":"Un elemento de calentador de agua tiene una resistencia de 12.8 ohms en un circuito de 240 V; ¿cuál es su consumo de potencia?","opts":["3072 W","18.75 W","4500 W","737280 W"],"re":"P = V al cuadrado / R = 57600 / 12.8 = 4500 W."},
  {"id":122,"q":"Un receptáculo de 125 voltios en un sótano sin terminar de una vivienda generalmente requiere qué tipo de protección?","opts":["Ninguna protección","Solo AFCI","Protección GFCI","Solo tierra aislada"],"re":"NEC 210.8(A) exige protección GFCI para los receptáculos de 125 voltios, 15 y 20 amperes instalados en sótanos sin terminar de las viviendas."},
  {"id":123,"q":"Para conductores de aluminio según NEC 240.4(D), ¿cuál es la máxima protección contra sobrecorriente para el 12 AWG de aluminio?","opts":["20 A","10 A","15 A","25 A"],"re":"NEC 240.4(D) limita el 12 AWG de aluminio/aluminio revestido de cobre a un dispositivo de sobrecorriente máximo de 15 amperes."},
  {"id":124,"q":"Al leer la placa de datos de un motor, ¿qué representa el valor de RPM indicado?","opts":["La velocidad sincrónica del campo magnético","La velocidad únicamente sin carga","La sobrevelocidad máxima permisible","La velocidad de operación aproximada a plena carga del eje del motor"],"re":"Las RPM de la placa de datos son la velocidad a plena carga (nominal) del motor, que en un motor de inducción es ligeramente menor que la velocidad sincrónica debido al deslizamiento."},
  {"id":125,"q":"¿Cuál es la secuencia correcta del procedimiento de verificación vivo-muerto-vivo?","opts":["Probar una fuente viva conocida, probar el circuito en el que se va a trabajar para verificar la ausencia de tensión, y luego volver a probar la fuente viva conocida","Probar el circuito muerto, luego tocarlo, y luego probar una fuente viva","Tocar el circuito primero, luego probar una fuente viva dos veces","Probar resistencia, probar continuidad, y luego probar corriente"],"re":"El método vivo-muerto-vivo verifica el probador en una fuente energizada conocida, luego confirma que el circuito objetivo está muerto, y luego vuelve a verificar el probador en una fuente viva conocida para comprobar que aún funciona, confirmando un resultado válido de ausencia de tensión."},
  {"id":126,"q":"En un circuito en serie, un resistor de 5 ohms y uno de 5 ohms son seguidos por un resistor de 10 ohms; ¿cuál es la resistencia total?","opts":["2 ohms","250 ohms","20 ohms","10 ohms"],"re":"En serie se suma: 5 + 5 + 10 = 20 ohms."},
  {"id":127,"q":"¿Por qué el cableado de aluminio típicamente requiere un tamaño de conductor mayor que el de cobre para la misma ampacidad?","opts":["El aluminio se funde a una temperatura más baja","El aluminio no se puede aislar tan bien","El aluminio es más pesado que el cobre","El aluminio tiene mayor resistividad eléctrica"],"re":"La mayor resistividad del aluminio significa que se necesita una sección transversal mayor para conducir la misma corriente. Vea las comparaciones de ampacidad de la Tabla 310.16 del NEC."},
  {"id":128,"q":"En la placa de datos de un motor, ¿qué indica principalmente la letra de código (letra de código NEMA)?","opts":["Los kVA a rotor bloqueado por caballo de fuerza (característica de irrupción de arranque)","La eficiencia a plena carga","La temperatura ambiente máxima","La clase de aislamiento"],"re":"La letra de código NEMA en la placa de datos indica los kVA a rotor bloqueado por caballo de fuerza, que se usa para determinar la corriente de arranque (irrupción) del motor."},
  {"id":129,"q":"¿Cuál es la resistencia equivalente de un resistor de 10 ohms, uno de 20 ohms y uno de 30 ohms conectados en paralelo?","opts":["60 ohms","0.183 ohms","20 ohms","5.45 ohms"],"re":"1/R = 1/10 + 1/20 + 1/30 = 6/60 + 3/60 + 2/60 = 11/60; R = 60/11 = 5.45 ohms."},
  {"id":130,"q":"¿Cuál afirmación sobre la ropa con clasificación de arco según la NFPA 70E es correcta?","opts":["Las camisetas comunes de algodón proporcionan protección adecuada contra arco","Cualquier ropa retardante de llama está automáticamente clasificada para arco","Las prendas con clasificación de arco deben tener una clasificación de arco igual o mayor que la energía incidente estimada a la distancia de trabajo","La ropa con clasificación de arco solo necesita cubrir las manos"],"re":"La NFPA 70E exige que el EPP con clasificación de arco tenga una clasificación de arco (en cal/cm2) al menos igual a la energía incidente disponible; la ropa sin clasificación, incluso de algodón, puede encenderse o fundirse y no proporciona protección certificada."},
  {"id":131,"q":"Un receptáculo instalado en el garaje de una vivienda debe contar con cuál de los siguientes?","opts":["Una configuración de tipo con seguro","Protección GFCI","Solo protección AFCI","Un neutro aislado"],"re":"NEC 210.8(A) exige protección GFCI para los receptáculos de 125 voltios, 15 y 20 amperes instalados en los garajes de las viviendas."},
  {"id":132,"q":"Las terminales listadas y marcadas como 'CU-AL' o 'AL-CU' se requieren al conectar:","opts":["Únicamente conductores mayores de 1/0","Únicamente conductores de cobre","Únicamente conductores de puesta a tierra","Conductores de aluminio o de cobre en esa terminación"],"re":"Las terminaciones marcadas CU-AL/AL-CU están probadas y listadas para usarse con conductores de aluminio y de cobre. Vea NEC 110.14(A)."},
  {"id":133,"q":"Un circuito de motor monofásico de 240 V entrega 7200 W de potencia real con un factor de potencia de 0.80; ¿cuál es la corriente de línea?","opts":["37.5 A","30 A","24 A","60 A"],"re":"I = P / (V x FP) = 7200 / (240 x 0.80) = 7200/192 = 37.5 A."},
  {"id":134,"q":"En la placa de datos de un motor, ¿qué indica un factor de servicio (SF) de 1.15?","opts":["El motor siempre debe funcionar al 115% de la tensión nominal","El motor puede operarse continuamente hasta el 115% de su potencia nominal en caballos de fuerza sin daño inmediato","La corriente de arranque es el 115% de la corriente a plena carga","El aislamiento está clasificado para 115°C"],"re":"Un factor de servicio de 1.15 significa que el motor puede soportar una sobrecarga continua del 15% por encima de su potencia nominal en caballos de fuerza bajo condiciones especificadas; también afecta el dimensionamiento permitido de la sobrecarga según NEC 430.32."},
  {"id":135,"q":"¿Cuál es la función de una condición de trabajo eléctricamente segura para eliminar los peligros eléctricos?","opts":["Elimina los peligros de descarga y arco eléctrico porque se verifica que el equipo está desenergizado, aislado e incapaz de ser reenergizado","Reduce el peligro a la mitad pero aún requiere EPP completo","Solo protege contra arco eléctrico, no contra descarga","Se aplica únicamente a circuitos de control de baja tensión"],"re":"Una vez que se establece y verifica una condición de trabajo eléctricamente segura, se elimina la fuente de energía eléctrica, eliminando tanto el peligro de descarga como el de arco eléctrico, de modo que el trabajo ya no se considera trabajo energizado."},
  {"id":136,"q":"Cuando se aplican a un conductor tanto los factores de corrección por temperatura ambiente como los de ajuste por agrupamiento, deben:","opts":["Multiplicarse juntos con la ampacidad base","Sumarse juntos","Ignorarse si los conductores están clasificados a 90°C","Usarse por separado, eligiendo el menor"],"re":"Los factores de corrección y de ajuste se multiplican juntos y se aplican a la ampacidad base. Vea NEC 310.15(B) y (C)."},
  {"id":137,"q":"Una carga de 3 kW funciona continuamente durante un día completo; ¿cuánta energía se consume?","opts":["24 kWh","3 kWh","72 kWh","125 kWh"],"re":"Energía = 3 kW x 24 h = 72 kWh."},
  {"id":138,"q":"La placa de datos de un motor muestra una clasificación de doble tensión de 230/460 V; ¿qué le ocurre generalmente a la corriente a plena carga cuando el motor se conecta para la tensión más alta (460 V)?","opts":["Se duplica aproximadamente","Permanece exactamente igual","Se vuelve cero","Es aproximadamente la mitad del valor de 230 V"],"re":"Para una potencia dada en caballos de fuerza, la corriente es inversamente proporcional a la tensión, por lo que conectar para 460 V consume aproximadamente la mitad de la corriente a plena carga requerida a 230 V."},
  {"id":139,"q":"Un conductor clasificado USE-2 tiene qué clasificación de temperatura?","opts":["60°C","75°C","105°C","90°C"],"re":"El sufijo '-2' indica una clasificación de 90°C en mojado y en seco, por lo que el USE-2 está clasificado a 90°C. Vea la Tabla 310.4(A) del NEC."},
  {"id":140,"q":"¿Quién está autorizado para determinar que el trabajo energizado está justificado y para aprobar un permiso de trabajo eléctrico energizado?","opts":["Cualquier trabajador de la cuadrilla por voto mayoritario","La primera persona en llegar al sitio","El representante de ventas del fabricante del equipo","El personal gerencial autorizado, después de que la justificación y la evaluación de riesgo estén documentadas"],"re":"La NFPA 70E exige que el permiso de trabajo eléctrico energizado sea revisado y firmado por la gerencia autorizada, confirmando la justificación para el trabajo energizado y las evaluaciones de riesgo completadas."},
  {"id":141,"q":"Los receptáculos instalados dentro de qué distancia del borde exterior de un fregadero generalmente requieren protección GFCI en una vivienda?","opts":["3 feet","4 feet","10 feet","6 feet"],"re":"NEC 210.8(A) exige protección GFCI para los receptáculos ubicados dentro de 6 ft del borde exterior de un fregadero."},
  {"id":142,"q":"Un motor de bomba consume 4 kW de entrada y produce 5 HP de salida útil; ¿cuál es su eficiencia?","opts":["125 por ciento","80 por ciento","93 por ciento","75 por ciento"],"re":"Salida = 5 x 746 = 3730 W; ef = 3730/4000 = 0.93 = 93 por ciento."},
  {"id":143,"q":"Se comparan un motor monofásico de 5 hp a 230 V y un motor trifásico de 5 hp a 230 V; ¿cuál afirmación sobre sus corrientes a plena carga es generalmente verdadera?","opts":["El motor monofásico consume menos corriente que el motor trifásico","Ambos consumen exactamente la misma corriente","El motor monofásico consume más corriente que el motor trifásico para la misma potencia en caballos de fuerza y tensión","El motor trifásico no puede operar a 230 V"],"re":"Para la misma potencia en caballos de fuerza y tensión, un motor monofásico consume considerablemente más corriente que un motor trifásico porque la potencia trifásica se entrega de manera más eficiente a través de tres conductores."},
  {"id":144,"q":"El conductor USE simple sin una cubierta exterior clasificada para ese propósito generalmente NO se permite usar como:","opts":["Alimentador subterráneo","Acometida de entrada enterrada directamente","Acometida lateral subterránea","Cableado de circuito ramal interior dentro de las instalaciones"],"re":"El USE está destinado para uso subterráneo/de acometida; no está listado para cableado interior general dentro de los edificios. Vea las notas de la Tabla 310.4(A) del NEC."},
  {"id":145,"q":"Durante el bloqueo/etiquetado, ¿dónde debe colocar su dispositivo de bloqueo cada empleado autorizado?","opts":["En la placa de datos del equipo","Únicamente en la puerta del cuarto eléctrico","En el dispositivo de aislamiento de energía, para que cada trabajador controle el aislamiento con su propio candado","En su caja de herramientas personal para resguardarlo"],"re":"Cal/OSHA T8 Sección 3314 exige que el dispositivo de bloqueo se aplique al medio de aislamiento de energía; cuando hay varios trabajadores involucrados, cada uno aplica su propio candado (a menudo mediante una mordaza de bloqueo grupal) para que el aislamiento no pueda retirarse hasta que cada trabajador haya terminado."},
  {"id":146,"q":"Una carga monofásica de 8 kVA opera con un factor de potencia de 0.90; ¿cuál es la potencia real en kW?","opts":["7.2 kW","8.89 kW","8 kW","0.9 kW"],"re":"Potencia real = kVA x FP = 8 x 0.90 = 7.2 kW."},
  {"id":147,"q":"Un conductor de doble clasificación marcado 'THHN/THWN-2' puede usarse en una ubicación mojada a qué clasificación de temperatura?","opts":["60°C","90°C","75°C","No puede usarse en ubicaciones mojadas"],"re":"La clasificación THWN-2 proporciona 90°C tanto en ubicaciones mojadas como secas para el conductor de doble clasificación. Vea la Tabla 310.4(A) del NEC."},
  {"id":148,"q":"Un motor trifásico que funciona en un sistema de 480 V de repente consume corriente alta, se calienta y zumba fuertemente; ¿cuál condición debe revisarse primero?","opts":["Tensión excesiva en el circuito de control","Una fase abierta (monofaseo) en la alimentación","Un conductor de puesta a tierra invertido","Un conductor de circuito ramal demasiado grande"],"re":"La pérdida de una fase (monofaseo) hace que un motor trifásico se sobrecaliente y consuma corriente alta en las fases restantes; revisar si hay una fase abierta o un fusible fundido es el primer paso."},
  {"id":149,"q":"Un receptáculo del área de lavandería de una vivienda que sirve el equipo de lavandería generalmente requiere qué tipo de protección?","opts":["Protección GFCI","Solo resistente a manipulación","Solo AFCI","Ninguna protección"],"re":"NEC 210.8(A) exige protección GFCI para los receptáculos de 125 voltios, 15 y 20 amperes instalados en las áreas de lavandería de las viviendas."},
  {"id":150,"q":"¿Cuál factor aumenta la energía incidente disponible en una pieza de equipo dada durante un arco eléctrico?","opts":["Un tiempo de despeje de falla más corto del dispositivo de protección aguas arriba","Una duración del arco más larga antes de que el dispositivo de protección despeje la falla","Una distancia de trabajo mayor desde la fuente del arco","Una corriente de cortocircuito disponible menor"],"re":"La energía incidente aumenta con una duración del arco más larga; mientras más tarde el dispositivo de protección aguas arriba en despejar la falla, más energía térmica se entrega, razón por la cual una protección de despeje rápido reduce el peligro de arco eléctrico."},
  {"id":151,"q":"Si un circuito de 277 V tiene una caída de tensión máxima permitida del 3 por ciento, ¿cuál es la caída máxima permitida en volts?","opts":["0.83 V","8.31 V","83.1 V","9.23 V"],"re":"Caída máxima = 0.03 x 277 = 8.31 V."},
  {"id":152,"q":"Se instalan diez conductores portadores de corriente en una sola canalización; ¿cuál factor de ajuste de la Tabla 310.15(C)(1) se aplica?","opts":["50%","70%","80%","45%"],"re":"Para 10 a 20 conductores portadores de corriente el factor de ajuste es 50%. Vea la Tabla 310.15(C)(1) del NEC."},
  {"id":153,"q":"Si la bobina de un arrancador magnético de motor no se energiza cuando se presiona el botón de arranque, ¿cuál es un primer elemento lógico que revisar en el circuito de control?","opts":["Los cojinetes del motor","La dirección de rotación del motor","La potencia nominal en caballos de fuerza de la placa de datos","La continuidad del circuito de control, incluyendo el botón de paro, los contactos de sobrecarga y el fusible de control"],"re":"Una bobina que no se activa indica un circuito de control abierto; revise el botón de paro (NC), los contactos de sobrecarga (NC), el fusible de control y la continuidad de la bobina antes de sospechar de problemas mecánicos."},
  {"id":154,"q":"¿Cuál afirmación sobre el conteo de conductores portadores de corriente para reducción es correcta?","opts":["El neutro puesto a tierra siempre se cuenta","Los conductores de puesta a tierra de equipos se cuentan","Solo se cuentan los conductores no puestos a tierra (vivos) y los neutros que califican","Todos los conductores de la canalización se cuentan"],"re":"Solo se cuentan los conductores no puestos a tierra más los neutros que realmente conducen corriente; los EGC y los neutros no portadores de corriente se excluyen. Vea NEC 310.15(E)."},
  {"id":155,"q":"¿Qué debe hacer una persona calificada antes de cruzar la frontera de arco eléctrico para realizar una tarea?","opts":["Esperar hasta que la energía incidente disminuya por sí sola","Quitarse todas las joyas metálicas y proceder con ropa de calle","Usar EPP con clasificación de arco igual o mayor que la energía incidente a la distancia de trabajo","Notificar por escrito al departamento de bomberos local"],"re":"La NFPA 70E exige que cualquiera que cruce la frontera de arco eléctrico use EPP con clasificación de arco con una clasificación de arco al menos igual a la energía incidente estimada a la distancia de trabajo para prevenir una quemadura de segundo grado."},
  {"id":156,"q":"Un tramo de conductor cae 7.2 V en un circuito de 120 V que alimenta una carga; ¿cuál es la tensión entregada en la carga?","opts":["112.8 V","127.2 V","6 V","120 V"],"re":"Tensión en la carga = fuente menos caída = 120 - 7.2 = 112.8 V."},
  {"id":157,"q":"Los conductores del circuito ramal de un motor de servicio continuo se dimensionan al 125% de la corriente a plena carga; el dispositivo de sobrecarga para el mismo motor (SF 1.15) se dimensiona al 125% de la FLA de la placa de datos. ¿Por qué estos dos porcentajes pueden referirse a valores de corriente diferentes?","opts":["Los conductores usan la FLC de la tabla del NEC, mientras que el dispositivo de sobrecarga usa los amperes reales a plena carga de la placa de datos","Ambos siempre deben usar exactamente el mismo valor de corriente","El dispositivo de sobrecarga usa la corriente a rotor bloqueado","Los conductores usan los amperes de la placa de datos y las sobrecargas usan los valores de la tabla"],"re":"Según NEC 430.6(A), el dimensionamiento de los conductores y del dispositivo de cortocircuito usa los valores de FLC de la tabla, mientras que la protección contra sobrecarga según 430.32 se basa en la corriente real a plena carga de la placa de datos del motor."},
  {"id":158,"q":"Cuando un solo receptáculo GFCI se conecta para proteger receptáculos aguas abajo, las salidas protegidas deben conectarse a cuál conjunto de terminales del dispositivo GFCI?","opts":["Las terminales LINE","Únicamente la terminal de puesta a tierra","Las terminales LOAD","Cualquier conjunto funciona igual"],"re":"Los receptáculos aguas abajo (protegidos) deben conectarse a las terminales LOAD del GFCI; la alimentación entrante se conecta a las terminales LINE."},
  {"id":159,"q":"Para una carga continua, los conductores del circuito ramal deben tener una ampacidad permisible no menor a qué porcentaje de la carga continua?","opts":["100%","125%","150%","115%"],"re":"Según NEC 210.19(A) y 215.2, los conductores que alimentan cargas continuas deben dimensionarse no menor al 125% de la carga continua."},
  {"id":160,"q":"Una corriente de 0.25 A fluye a través de un resistor de 480 ohms; ¿cuánta potencia se disipa?","opts":["30 W","120 W","7680 W","1920 W"],"re":"P = I al cuadrado x R = 0.0625 x 480 = 30 W."},
  {"id":161,"q":"Según Cal/OSHA T8 Sección 3314, ¿con qué frecuencia deben inspeccionarse o revisarse los procedimientos de bloqueo/etiquetado?","opts":["Solo una vez cuando el empleado es contratado por primera vez","Cada diez años","Periódicamente, al menos anualmente, para asegurar que los procedimientos y el desempeño del empleado sigan siendo eficaces","Nunca, una vez que el programa escrito está creado"],"re":"Cal/OSHA T8 Sección 3314 exige una inspección periódica, al menos anual, de los procedimientos de control de energía para corregir deficiencias y verificar que los empleados autorizados los sigan correctamente."},
  {"id":162,"q":"Un motor monofásico de servicio continuo de 240 V tiene una corriente a plena carga de tabla de 20 amperes; ¿qué ampacidad mínima de conductor de circuito ramal requiere NEC 430.22?","opts":["20 amperes","25 amperes","23 amperes","30 amperes"],"re":"NEC 430.22 exige el 125% de la FLC para un solo motor: 20 A x 1.25 = 25 A de ampacidad mínima del conductor."},
  {"id":163,"q":"Seis conductores portadores de corriente están en un conduit y el ambiente es de 40°C; tanto la corrección por ambiente de 0.91 como el ajuste del 80% se aplican a una ampacidad base de 90°C de 40 A, dando aproximadamente:","opts":["40 A","36 A","32 A","29 A"],"re":"40 A × 0.91 × 0.80 ≈ 29 A; los factores de corrección y de ajuste se multiplican según NEC 310.15(B) y (C)."},
  {"id":164,"q":"Dos resistores en serie conducen los mismos 2 A; si uno es de 15 ohms y el otro de 25 ohms, ¿cuál es la tensión total a través del par?","opts":["20 V","8 V","40 V","80 V"],"re":"R total = 15 + 25 = 40 ohms; V = I x R = 2 x 40 = 80 V."},
  {"id":165,"q":"¿Qué distingue a una persona calificada de una persona no calificada cuando se trata de las fronteras de aproximación por descarga?","opts":["Las personas no calificadas pueden cruzar libremente cualquier frontera si usan guantes","Solo una persona calificada puede cruzar la frontera de aproximación restringida hacia partes energizadas expuestas usando el EPP apropiado y un plan","Ambas pueden cruzar todas las fronteras por igual","Solo la persona no calificada puede cruzar la frontera de aproximación restringida"],"re":"La NFPA 70E permite que solo una persona calificada, usando el EPP de descarga apropiado y un plan de aproximación documentado, cruce la frontera de aproximación restringida; las personas no calificadas se mantienen fuera de la frontera de aproximación limitada salvo bajo escolta calificada."},
  {"id":166,"q":"¿Cuál material conductor es más ligero en peso y más bajo en costo, lo que lo hace común para grandes tramos de acometida y alimentadores a pesar de necesitar sobredimensionamiento?","opts":["Cobre recubierto de plata","Cobre","Cobre estañado","Aluminio"],"re":"El aluminio es más ligero y más barato que el cobre, razón por la cual se usa ampliamente para alimentadores y acometidas más grandes aunque deba sobredimensionarse para igual ampacidad. Vea la Tabla 310.16 del NEC."},
  {"id":167,"q":"Si la protección contra sobrecarga inicial dimensionada al 125% de la FLA de la placa de datos se dispara durante el ciclo normal de arranque del motor, ¿qué permite NEC 430.32 como solución?","opts":["Eliminar por completo la protección contra sobrecarga","Reemplazar el motor por una unidad de mayor potencia en caballos de fuerza","Reducir el tamaño del conductor del circuito ramal","Aumentar el ajuste de disparo de la sobrecarga hasta un máximo permitido mayor (como el 140% de la FLA)"],"re":"NEC 430.32(C) permite aumentar el tamaño de la sobrecarga a un máximo mayor (por ejemplo, hasta el 140% para motores con SF 1.15 o más) cuando el valor inicial no es suficiente para permitir que el motor arranque."},
  {"id":168,"q":"Un dispositivo GFCI está diseñado para abrir el circuito cuando detecta un desbalance de corriente de aproximadamente qué valor entre los conductores vivo y neutro?","opts":["0.5 ampere","20 miliamperes","4 a 6 miliamperes","5 amperes"],"re":"Un GFCI Clase A está diseñado para dispararse cuando la diferencia entre las corrientes del conductor vivo y del conductor puesto a tierra alcanza aproximadamente 4 a 6 miliamperes, protegiendo contra descargas."},
  {"id":169,"q":"Un motor monofásico de 7.5 HP con 90 por ciento de eficiencia opera a 240 V; ¿cuál es la potencia de entrada aproximada?","opts":["6217 W","5036 W","5595 W","4500 W"],"re":"Salida = 7.5 x 746 = 5595 W; entrada = 5595/0.90 = 6217 W."},
  {"id":170,"q":"Después de un incidente eléctrico o cuando el estado de un circuito es incierto, ¿cuál es la suposición más segura que debe hacer un trabajador?","opts":["Suponer que el circuito está desenergizado para ahorrar tiempo en las pruebas","Suponer que el interruptor se disparó y despejó la falla","Tratar todos los conductores y partes como energizados hasta que se verifique que están desenergizados mediante una condición de trabajo eléctricamente segura","Suponer que otro trabajador ya lo bloqueó"],"re":"Cal/OSHA y la NFPA 70E exigen que los conductores y las partes del circuito se traten como energizados hasta que se establezca y verifique una condición de trabajo eléctricamente segura, porque las suposiciones no verificadas sobre la desenergización causan muchas lesiones eléctricas."},
  {"id":171,"q":"Cuatro conductores portadores de corriente con una ampacidad base de 90°C de 55 A cada uno están agrupados en una canalización; ¿cuál es la ampacidad ajustada?","opts":["55 A","49.5 A","44 A","38.5 A"],"re":"Para 4-6 conductores el factor de ajuste es 80%, por lo que 55 × 0.80 = 44 A. Vea la Tabla 310.15(C)(1) del NEC."},
  {"id":172,"q":"Un transformador monofásico tiene una tensión primaria de 480 V y una tensión secundaria de 120 V, entonces ¿cuál es su relación de vueltas?","opts":["1:4","1:2","2:1","4:1"],"re":"La relación de vueltas es igual a la tensión primaria dividida entre la tensión secundaria, por lo que 480 V dividido entre 120 V es igual a una relación de 4:1."},
  {"id":173,"q":"Un circuito de 120 V alimenta una carga a 150 ft de distancia; si la caída de tensión de ida y vuelta es de 3.6 V, ¿qué porcentaje de la tensión de la fuente se pierde?","opts":["0.3 por ciento","1 por ciento","6 por ciento","3 por ciento"],"re":"Porcentaje de caída = 3.6/120 x 100 = 3 por ciento."},
  {"id":174,"q":"Al instalar tubería metálica eléctrica (EMT) en una pared, ¿cuál es la distancia máxima a la que la canalización debe estar sujetada de forma segura desde cada caja de salida, caja de empalme u otra terminación de conduit?","opts":["18 inches","10 feet","3 feet","5 feet"],"re":"Según NEC 358.30, el EMT debe estar sujetado de forma segura dentro de 3 ft de cada caja de salida, caja de empalme, gabinete o accesorio."},
  {"id":175,"q":"¿A qué nivel aproximado de corriente alterna de 60 Hz que pasa a través del cuerpo humano una persona típicamente pierde la capacidad de soltar un conductor debido a la contracción muscular?","opts":["Aproximadamente 1 mA","Aproximadamente 500 mA","Aproximadamente 100 mA","Aproximadamente 10 a 16 mA"],"re":"El umbral de soltar para la mayoría de los adultos es de aproximadamente 10 a 16 mA; por encima de esto los músculos se contraen y la víctima no puede soltar el conductor energizado."},
  {"id":176,"q":"En un sistema trifásico balanceado conectado en estrella, ¿cuál es la relación entre la tensión de línea y la tensión de fase?","opts":["La tensión de línea es igual a la tensión de fase","La tensión de línea es igual a la tensión de fase por 3","La tensión de línea es igual a la tensión de fase dividida entre 1.732","La tensión de línea es igual a la tensión de fase por 1.732"],"re":"En una configuración en estrella, la tensión de línea = tensión de fase × √3 (1.732), mientras que la corriente de línea es igual a la corriente de fase."},
  {"id":177,"q":"¿Cuál dispositivo está diseñado para detectar condiciones peligrosas de arqueo en el cableado de circuitos ramales y se requiere para los dormitorios de unidades de vivienda?","opts":["GFCI","Dispositivo de protección contra sobretensiones","Receptáculo de tierra aislada","AFCI"],"re":"NEC 210.12 exige protección con interruptor de circuito por falla de arco (AFCI) para los circuitos ramales que alimentan salidas en los dormitorios de las viviendas, los cuales detectan fallas de arqueo."},
  {"id":178,"q":"¿Cuál instrumento de prueba mide la resistencia de aislamiento de un conductor aplicando una alta tensión de CC?","opts":["Amperímetro de gancho","Medidor de rotación de fase","Megóhmetro (megger)","Detector de tensión sin contacto"],"re":"Un megóhmetro, o megger, aplica una alta tensión de prueba de CC (como 500 V o 1000 V) para medir la resistencia de aislamiento en megaohmios."},
  {"id":179,"q":"¿Cuál es el máximo total de grados de curvas permitido en un tramo de conduit entre puntos de tiro tales como cajas o cuerpos de conduit?","opts":["180 grados","540 grados","270 grados","360 grados"],"re":"El NEC limita el total de curvas entre puntos de tiro a un máximo de 360 grados (el equivalente a cuatro curvas de un cuarto) para canalizaciones como EMT, RMC, IMC y PVC."},
  {"id":180,"q":"¿Aproximadamente qué nivel de corriente a través del cuerpo se considera generalmente el umbral de percepción, donde una persona apenas puede sentir un hormigueo?","opts":["Aproximadamente 1 mA","Aproximadamente 50 mA","Aproximadamente 200 mA","Aproximadamente 1,000 mA"],"re":"El umbral de percepción para la mayoría de las personas es de alrededor de 1 mA, produciendo una leve sensación de hormigueo."},
  {"id":181,"q":"¿Cuál es la potencia aparente total de una carga trifásica que opera a 480 V de línea a línea consumiendo 50 A por línea?","opts":["72,000 VA","24,000 VA","41,569 VA","13,856 VA"],"re":"La potencia aparente trifásica S = √3 × VL × IL = 1.732 × 480 × 50 = 41,569 VA."},
  {"id":182,"q":"¿Cuál instrumento permite leer la corriente en un conductor sin abrir el circuito ni desconectar ningún cable?","opts":["Megóhmetro","Amperímetro de gancho","Probador de aislamiento","Probador de continuidad"],"re":"Un amperímetro de gancho mide la corriente al detectar el campo magnético alrededor de un conductor, por lo que no es necesario abrir el circuito."},
  {"id":183,"q":"El cable con cubierta no metálica (Tipo NM) instalado sobre la superficie de los miembros estructurales debe asegurarse a intervalos que no excedan qué distancia?","opts":["4 1/2 feet","3 feet","6 feet","10 feet"],"re":"Según NEC 334.30, el cable Tipo NM debe asegurarse a intervalos que no excedan 4 1/2 ft."},
  {"id":184,"q":"Las corrientes en el rango de aproximadamente 100 a 200 mA a través del pecho son especialmente peligrosas principalmente porque pueden causar cuál condición potencialmente mortal?","opts":["Solo quemaduras menores en la piel","Calambres musculares que se resuelven rápidamente","Pérdida temporal de la audición","Fibrilación ventricular del corazón"],"re":"Las corrientes de aproximadamente 100 a 200 mA a través del pecho pueden llevar el corazón a fibrilación ventricular, que es frecuentemente mortal sin intervención inmediata."},
  {"id":185,"q":"Un motor trifásico de 240 V entrega 30 kW de potencia real con un factor de potencia de 0.85; ¿aproximadamente qué corriente de línea consume?","opts":["72 A","85 A","104 A","60 A"],"re":"IL = P / (√3 × VL × FP) = 30,000 / (1.732 × 240 × 0.85) = 84.9 A ≈ 85 A."},
  {"id":186,"q":"El cable Tipo NM debe asegurarse dentro de qué distancia máxima de cada caja de salida, caja de empalme o gabinete donde entra el cable?","opts":["12 inches","24 inches","18 inches","8 inches"],"re":"Según NEC 334.30, el cable NM debe asegurarse dentro de 12 in. de cada caja de salida, caja de empalme, gabinete o accesorio."},
  {"id":187,"q":"La protección AFCI generalmente se requiere para los circuitos ramales que alimentan salidas en cuál de las siguientes áreas de una vivienda?","opts":["Baños","Patios exteriores","Garajes separados sin calefacción","Dormitorios y salas de estar"],"re":"NEC 210.12(A) exige protección AFCI para los circuitos ramales que alimentan salidas en las áreas habitables de las viviendas tales como dormitorios, salas de estar, cuartos familiares y habitaciones similares."},
  {"id":188,"q":"Un transformador reductor ideal con una relación de vueltas de 10:1 conduce 5 A en su devanado primario, entonces ¿cuál es la corriente secundaria aproximada?","opts":["0.5 A","50 A","5 A","15 A"],"re":"En un transformador ideal la relación de corriente es la inversa de la relación de vueltas, por lo que un reductor de 10:1 consume 5 A en el primario y entrega aproximadamente 50 A en el secundario."},
  {"id":189,"q":"Cuando se instalan más de dos conductores en un conduit o tubería, ¿el llenado máximo permitido de conductores es qué porcentaje del área de la sección transversal de la canalización?","opts":["31 por ciento","40 por ciento","53 por ciento","60 por ciento"],"re":"Según el Capítulo 9, Tabla 1 del NEC, donde se instalan más de 2 conductores en una canalización, el llenado máximo es del 40 por ciento del área de la sección transversal."},
  {"id":190,"q":"En un sistema trifásico balanceado conectado en delta, ¿cuál es la relación entre la corriente de línea y la corriente de fase (devanado)?","opts":["La corriente de línea es igual a la corriente de fase","La corriente de línea es igual a la corriente de fase dividida entre 1.732","La corriente de línea es igual a la corriente de fase por 3","La corriente de línea es igual a la corriente de fase por 1.732"],"re":"En una configuración en delta, la corriente de línea = corriente de fase × √3 (1.732), mientras que la tensión de línea es igual a la tensión de fase."},
  {"id":191,"q":"Un interruptor de circuito por falla a tierra (GFCI) Clase A está diseñado para dispararse cuando la diferencia de corriente entre los conductores vivo y neutro alcanza aproximadamente qué valor?","opts":["500 mA","30 mA","100 mA","5 mA"],"re":"Un GFCI Clase A se dispara con una corriente de falla a tierra de aproximadamente 5 mA (nominalmente 4 a 6 mA), el nivel elegido para proteger a las personas de descargas letales."},
  {"id":192,"q":"En un transformador trifásico balanceado conectado en estrella, ¿cómo se compara la tensión de línea con la tensión de fase (devanado)?","opts":["La tensión de línea es la raíz cuadrada de 3 veces la tensión de fase","La tensión de línea es la mitad de la tensión de fase","La tensión de línea es 3 veces la tensión de fase","La tensión de línea es igual a la tensión de fase"],"re":"En una conexión en estrella la tensión de línea es igual a la tensión de fase multiplicada por la raíz cuadrada de 3 (aproximadamente 1.732), mientras que las corrientes de línea y de fase son iguales."},
  {"id":193,"q":"Un solo conductor aislado instalado solo en un conduit puede llenar un máximo de qué porcentaje del área de la sección transversal de la canalización?","opts":["31 por ciento","40 por ciento","53 por ciento","60 por ciento"],"re":"Según el Capítulo 9, Tabla 1 del NEC, se permite que un conductor en una canalización tenga un llenado máximo del 53 por ciento."},
  {"id":194,"q":"Un sistema trifásico en estrella tiene una tensión de fase de 277 V; ¿cuál es la tensión aproximada de línea a línea?","opts":["277 V","480 V","831 V","160 V"],"re":"Tensión de línea en estrella = tensión de fase × √3 = 277 × 1.732 = 480 V."},
  {"id":195,"q":"¿Cuál es el peligro principal que la protección AFCI pretende reducir?","opts":["Incendios causados por fallas de arqueo","Descarga eléctrica a una persona","Caída de tensión en tramos largos","Conductores neutros sobrecargados"],"re":"Los dispositivos AFCI están destinados a desenergizar un circuito cuando se detecta una falla de arqueo, reduciendo el riesgo de incendios provocados por arqueo en el cableado, según NEC 210.12."},
  {"id":196,"q":"Según OSHA 1926.404, ¿cuál de las siguientes describe mejor el requisito de GFCI para las salidas de receptáculos de 125 voltios, monofásicas, de 15 y 20 amperes utilizadas por los empleados en un sitio de construcción?","opts":["La protección GFCI se requiere únicamente cuando llueve","La protección GFCI nunca se requiere en exteriores","La protección GFCI se requiere para todos esos receptáculos que no formen parte del cableado permanente","La protección GFCI se aplica únicamente a circuitos de 240 voltios"],"re":"OSHA exige protección GFCI para todas las salidas de receptáculos de 125 V, monofásicas, de 15, 20 y 30 A que no formen parte del cableado permanente y que sean utilizadas por los empleados."},
  {"id":197,"q":"¿Cuál es el propósito principal de usar un medidor de rotación de fase antes de conectar un motor trifásico?","opts":["Medir la resistencia de aislamiento","Verificar la secuencia de fases para que el motor gire en la dirección correcta","Medir la resistencia del electrodo de tierra","Comprobar la continuidad del conductor"],"re":"Un medidor de rotación de fase confirma la secuencia de fases A-B-C para que un motor trifásico gire en la dirección prevista al energizarse."},
  {"id":198,"q":"Cuando se instalan exactamente dos conductores en un conduit, ¿el llenado máximo de conductores permitido es qué porcentaje del área de la sección transversal de la canalización?","opts":["60 por ciento","40 por ciento","53 por ciento","31 por ciento"],"re":"Según el Capítulo 9, Tabla 1 del NEC, dos conductores en una canalización están limitados a un llenado máximo del 31 por ciento."},
  {"id":199,"q":"¿Cuál es la potencia real consumida por una carga trifásica a 208 V que consume 40 A por línea con un factor de potencia de 0.9?","opts":["14,400 W","8,320 W","16,000 W","12,973 W"],"re":"P = √3 × VL × IL × FP = 1.732 × 208 × 40 × 0.9 = 12,973 W."},
  {"id":200,"q":"En un sitio de construcción, OSHA 1926.404 permite que un empleador use un programa de conductor de puesta a tierra de equipos garantizado como alternativa a cuál medida de protección?","opts":["Procedimientos de bloqueo/etiquetado","Requisitos de casco de seguridad","Sistemas personales de detención de caídas","Protección GFCI en receptáculos temporales"],"re":"El programa de conductor de puesta a tierra de equipos garantizado es la alternativa permitida a la protección GFCI para receptáculos que no formen parte del cableado permanente."},
  {"id":201,"q":"Al usar un multímetro digital configurado en la función de resistencia (ohmios), ¿en qué condición debe probarse el circuito?","opts":["Energizado a plena carga","Bajo voltaje reducido","Energizado sin carga","Desenergizado y sin voltaje presente"],"re":"Las mediciones de resistencia y continuidad deben hacerse en un circuito desenergizado, porque el voltaje aplicado dará lecturas falsas y puede dañar el medidor."},
  {"id":202,"q":"Cuando un método de cableado tipo cable o canalización atraviesa un montante de madera y el borde del agujero perforado está a menos de 1 1/4 pulgadas del borde más cercano del montante, ¿qué protección se requiere?","opts":["Una placa o buje de acero de al menos 1/16 de pulgada de espesor","No se requiere protección adicional","Envolver el cable con cinta eléctrica","Duplicar el espaciamiento de las grapas"],"re":"Según NEC 300.4(A), cuando el agujero está a menos de 1 1/4 pulg. del borde más cercano, una placa o buje de acero de al menos 1/16 pulg. de espesor debe proteger el cableado de tornillos y clavos."},
  {"id":203,"q":"Un sistema trifásico de 480 V línea a línea está conectado en estrella; ¿cuál es el voltaje de cualquier línea al neutro?","opts":["480 V","277 V","240 V","831 V"],"re":"Voltaje línea a neutro (de fase) = voltaje de línea ÷ √3 = 480 ÷ 1.732 = 277 V."},
  {"id":204,"q":"En una unidad de vivienda nueva, los receptáculos de 125 voltios, 15 y 20 amperios instalados en las áreas especificadas por el Código deben ser de qué tipo para resistir la inserción de objetos extraños por parte de los niños?","opts":["Resistentes a la intemperie","Resistentes a la manipulación","De tierra aislada","De grado hospitalario"],"re":"NEC 406.12 requiere receptáculos resistentes a la manipulación (TR) listados para los receptáculos de 125 voltios, 15 y 20 amperios en unidades de vivienda, los cuales tienen obturadores internos que impiden la inserción de objetos."},
  {"id":205,"q":"¿Qué tipo de canalización es más susceptible a la corrosión y NO es adecuada para ambientes corrosivos severos a menos que se le proporcione protección suplementaria contra la corrosión?","opts":["Tubería metálica eléctrica (EMT)","PVC Cédula 40","Conduit metálico rígido (RMC)","Conduit metálico intermedio (IMC)"],"re":"Según NEC 358.10, el EMT y sus accesorios son susceptibles a la corrosión y requieren protección suplementaria en condiciones corrosivas severas, a diferencia del PVC."},
  {"id":206,"q":"Bajo un programa garantizado de conductor de puesta a tierra de equipos, cada juego de cordón y receptáculo que no forma parte del cableado permanente debe, como mínimo, probarse para verificar la continuidad y la conexión adecuada del terminal del conductor de puesta a tierra de equipos, ¿con qué frecuencia?","opts":["Antes del primer uso, después de una reparación y al menos cada 3 meses","Una vez al año","Solo cuando una herramienta falla","Una vez cada 5 años"],"re":"OSHA requiere realizar pruebas antes del primer uso, después de cualquier reparación, después de sospecha de daño y a intervalos que no excedan 3 meses (6 meses para receptáculos fijos no expuestos a daño)."},
  {"id":207,"q":"Un transformador buck-boost se usa más comúnmente para hacer cuál de las siguientes acciones?","opts":["Hacer una pequeña corrección de voltaje, como elevar 208 V a aproximadamente 230 V","Convertir energía monofásica a trifásica","Proporcionar aislamiento completo entre dos sistemas grandes","Reducir un primario a un servicio de 120/240 V derivado por separado"],"re":"Un transformador buck-boost se conecta como autotransformador para hacer un pequeño ajuste porcentual en el voltaje, como reducir (buck) o aumentar (boost) un suministro en aproximadamente 5 a 20 por ciento."},
  {"id":208,"q":"Un transformador monofásico tiene un voltaje primario de 480 V y un voltaje secundario de 120 V; ¿cuál es la relación de vueltas?","opts":["4:1","1:4","2:1","6:1"],"re":"Relación de vueltas = voltaje primario ÷ voltaje secundario = 480 ÷ 120 = 4, expresada como 4:1."},
  {"id":209,"q":"El conduit rígido de PVC (Cédula 40) instalado en una pared debe sujetarse firmemente dentro de qué distancia de cada caja, gabinete u otra terminación del conduit?","opts":["18 pulgadas","8 pies","3 pies","5 pies"],"re":"Según NEC 352.30, el conduit rígido de PVC debe sujetarse firmemente dentro de los 3 pies de cada caja, gabinete, cuerpo de conduit u otra terminación."},
  {"id":210,"q":"En un programa garantizado de conductor de puesta a tierra de equipos, ¿cuál de las siguientes pruebas debe realizarse en cada juego de cordón y receptáculo?","opts":["Una medición de la decoloración del color del conductor","Una prueba de que todos los conductores de puesta a tierra de equipos tienen continuidad eléctrica","Una prueba únicamente de la resistencia a la tracción del cordón","Una verificación de la fecha de garantía del fabricante"],"re":"Cada juego de cordón y receptáculo debe probarse para verificar que el conductor de puesta a tierra de equipos tiene continuidad eléctrica y está correctamente conectado a su terminal apropiado."},
  {"id":211,"q":"Antes de energizar un tablero recién instalado, ¿qué verificación de puesta en servicio debe realizarse en todas las terminaciones?","opts":["Aplicar corriente a plena carga y observar el calentamiento","Energizar y leer el voltaje en cada interruptor","Verificar que cada lengüeta esté apretada al par de torsión especificado por el fabricante","Rociar limpiador de contactos en cada lengüeta"],"re":"Un paso clave de puesta en servicio previo a la energización es apretar todas las terminaciones a los valores de par de torsión especificados por el fabricante usando una herramienta de torque calibrada para evitar conexiones flojas de alta resistencia."},
  {"id":212,"q":"Un transformador con una relación de vueltas de 10:1 tiene 240 V aplicados a su primario; ¿cuál es el voltaje secundario (ignorando las pérdidas)?","opts":["24 V","120 V","10 V","2,400 V"],"re":"Voltaje secundario = voltaje primario ÷ relación de vueltas = 240 ÷ 10 = 24 V."},
  {"id":213,"q":"Se requiere instalar un accesorio de expansión en un tramo de conduit rígido de PVC para compensar cuál condición?","opts":["Interferencia electromagnética","Caída de voltaje en distancias largas","Relleno excesivo de conductores","Expansión y contracción térmica del conduit"],"re":"Según NEC 352.44, se deben proporcionar accesorios de expansión para compensar la expansión y contracción térmica cuando se espera que el cambio de longitud sea de 1/4 pulg. o mayor."},
  {"id":214,"q":"¿Qué característica distingue a un receptáculo resistente a la manipulación de un receptáculo estándar?","opts":["Obturadores internos accionados por resorte sobre las ranuras","Una clasificación de amperaje más alta","Una junta a prueba de intemperie","Un supresor de sobretensiones integrado"],"re":"Los receptáculos resistentes a la manipulación (NEC 406.12) usan obturadores internos accionados por resorte que se abren solo cuando ambas patas de un enchufe se insertan simultáneamente, bloqueando la inserción de un solo objeto."},
  {"id":215,"q":"¿Qué método se usa para medir la resistencia a tierra de una varilla de puesta a tierra hincada?","opts":["Prueba de continuidad con un multímetro en el rango de ohmios","Prueba de resistencia de tierra de caída de potencial de tres puntos","Prueba de resistencia de aislamiento con un megóhmetro","Medición de corriente con pinza del conductor del servicio"],"re":"La resistencia del electrodo de tierra se mide comúnmente con una prueba de caída de potencial de tres puntos usando sondas auxiliares, o con un probador de resistencia de tierra tipo pinza."},
  {"id":216,"q":"Un taladro eléctrico portátil marcado con el símbolo de un cuadrado dentro de un cuadrado se describe como de doble aislamiento; ¿qué indica esta designación sobre la herramienta?","opts":["Depende de dos capas independientes de aislamiento y no requiere un conductor de puesta a tierra de equipos","Siempre debe conectarse a un GFCI para ser segura","Está clasificada para uso solo en lugares mojados","Contiene dos baterías internas"],"re":"El símbolo de cuadrado dentro de un cuadrado identifica una herramienta de doble aislamiento, que proporciona dos sistemas de aislamiento independientes y por lo tanto no necesita un conductor de puesta a tierra."},
  {"id":217,"q":"¿Cuál es la corriente a plena carga en el secundario de un transformador monofásico de 25 kVA con un secundario de 240 V?","opts":["60 A","104 A","208 A","10 A"],"re":"Corriente secundaria monofásica = kVA × 1000 ÷ V = 25,000 ÷ 240 = 104 A."},
  {"id":218,"q":"En una caja de salida estándar, ¿qué volumen en pulgadas cúbicas debe asignarse por cada conductor 14 AWG al realizar un cálculo de relleno de caja?","opts":["1.5 pulgadas cúbicas","2.5 pulgadas cúbicas","2.25 pulgadas cúbicas","2.0 pulgadas cúbicas"],"re":"Según la Tabla 314.16(B) del NEC, cada conductor 14 AWG requiere una asignación de volumen de 2.0 pulgadas cúbicas."},
  {"id":219,"q":"Un transformador trifásico está clasificado en 75 kVA con un secundario de 208 V; ¿cuál es la corriente de línea aproximada a plena carga del secundario?","opts":["208 A","625 A","360 A","104 A"],"re":"Corriente trifásica = kVA × 1000 ÷ (√3 × V) = 75,000 ÷ (1.732 × 208) = 75,000 ÷ 360.3 = 208 A."},
  {"id":220,"q":"Un probador de voltaje sin contacto es más adecuado para cuál tarea?","opts":["Medir el voltaje exacto línea a línea","Medir la relación de vueltas de un transformador","Medir el consumo de corriente en un alimentador","Indicar rápidamente la presencia de voltaje sin tocar un conductor"],"re":"Un probador de voltaje sin contacto detecta el campo eléctrico e indica si hay voltaje presente, pero no muestra un valor exacto."},
  {"id":221,"q":"Una herramienta eléctrica portátil puesta a tierra con un enchufe de tres patas se conecta a un receptáculo de dos hilos usando un adaptador cuya coleta de puesta a tierra se deja sin conectar; ¿cuál es el principal peligro?","opts":["La carcasa metálica de la herramienta no tiene una ruta a tierra si ocurre una falla interna","La herramienta funcionará en reversa","La herramienta consumirá corriente excesiva y disparará el interruptor","La herramienta sobrecalentará el receptáculo"],"re":"Sin la coleta de puesta a tierra conectada, una falla al bastidor metálico de la herramienta deja la carcasa energizada sin una ruta de baja resistencia a tierra, exponiendo al usuario a una descarga."},
  {"id":222,"q":"En un cálculo de relleno de caja, ¿qué volumen en pulgadas cúbicas debe asignarse por cada conductor 12 AWG?","opts":["2.25 pulgadas cúbicas","2.0 pulgadas cúbicas","2.5 pulgadas cúbicas","3.0 pulgadas cúbicas"],"re":"Según la Tabla 314.16(B) del NEC, cada conductor 12 AWG requiere una asignación de volumen de 2.25 pulgadas cúbicas."},
  {"id":223,"q":"Un receptáculo de 15 o 20 amperios, 125 voltios instalado en exteriores en un lugar húmedo o mojado debe estar listado como cuál tipo?","opts":["Solo resistente a la manipulación","De autopuesta a tierra","De grado hospitalario","Resistente a la intemperie (WR)"],"re":"NEC 406.9(A) y (B) requieren que los receptáculos en lugares húmedos o mojados sean del tipo resistente a la intemperie (WR), listados para esas condiciones."},
  {"id":224,"q":"Si un transformador reductor tiene una corriente secundaria de 100 A y una relación de vueltas de 5:1, ¿cuál es la corriente primaria aproximada (ignorando las pérdidas)?","opts":["500 A","20 A","100 A","25 A"],"re":"Corriente primaria = corriente secundaria ÷ relación de vueltas = 100 ÷ 5 = 20 A (la corriente es inversamente proporcional a la relación de voltaje)."},
  {"id":225,"q":"Al calcular el relleno de caja, ¿cómo se cuentan todos los conductores de puesta a tierra de equipos que entran a una caja, sin importar cuántos haya?","opts":["Cada conductor de puesta a tierra cuenta como un conductor separado","No se cuentan en absoluto","Todos los conductores de puesta a tierra juntos cuentan como una sola asignación de volumen de conductor basada en el más grande","Cuentan doble debido al requisito de unión"],"re":"Según NEC 314.16(B)(5), todos los conductores de puesta a tierra de equipos cuentan colectivamente como una sola asignación de volumen de conductor, basada en el conductor de puesta a tierra más grande presente."},
  {"id":226,"q":"Para un transformador monofásico de 25 kVA con un secundario de 240 V, ¿cuál es la corriente secundaria aproximada a plena carga?","opts":["Aproximadamente 60 A","Aproximadamente 208 A","Aproximadamente 104 A","Aproximadamente 25 A"],"re":"La corriente secundaria es igual a los VA divididos por el voltaje, entonces 25,000 VA divididos por 240 V es aproximadamente 104 A."},
  {"id":227,"q":"Al trabajar sobre o cerca de partes eléctricas energizadas expuestas, ¿qué tipo de escalera portátil se recomienda para reducir el riesgo de descarga eléctrica?","opts":["Escalera de aluminio","Escalera de acero","Escalera de magnesio","Escalera de fibra de vidrio (no conductora)"],"re":"Una escalera de fibra de vidrio tiene rieles laterales no conductores, lo que la hace la elección adecuada cerca de partes energizadas donde una escalera metálica podría convertirse en una ruta eléctrica."},
  {"id":228,"q":"En un cálculo de relleno de caja, ¿cuántas asignaciones de volumen de conductor se cuentan por un solo dispositivo como un receptáculo o interruptor montado en un yugo o tira?","opts":["Una basada en el conductor más grande conectado al dispositivo","Dos basadas en el conductor más grande conectado al dispositivo","Tres sin importar el tamaño del conductor","Cero porque los dispositivos no se cuentan"],"re":"Según NEC 314.16(B)(4), cada yugo o tira que contiene uno o más dispositivos se cuenta como dos asignaciones de volumen de conductor basadas en el conductor más grande conectado a él."},
  {"id":229,"q":"¿Qué tamaño de transformador, en kVA, se requiere como mínimo para alimentar una carga monofásica de 240 V que consume 80 A?","opts":["10 kVA","19.2 kVA","33.3 kVA","15 kVA"],"re":"kVA = V × A ÷ 1000 = 240 × 80 ÷ 1000 = 19.2 kVA."},
  {"id":230,"q":"Al poner en servicio un sistema derivado por separado de un transformador de tipo seco, ¿dónde debe hacerse la conexión de puesta a tierra (unión) del sistema?","opts":["En el extremo de carga de cada circuito ramal","Solo en el transformador de la empresa de servicios","En la fuente, uniendo el neutro secundario a un electrodo de puesta a tierra","En cada receptáculo individual"],"re":"Un sistema derivado por separado debe tener su conductor puesto a tierra (neutro) unido a un electrodo de puesta a tierra en o cerca de la fuente, normalmente con un puente de unión del sistema en el transformador."},
  {"id":231,"q":"Un electricista debe cambiar una luminaria ubicada cerca de conductores aéreos energizados y elige una escalera; ¿cuál de las siguientes es la opción menos apropiada?","opts":["Una escalera de madera seca","Una escalera de extensión de aluminio","Una escalera de fibra de vidrio","Una escalera de tijera no conductora"],"re":"Una escalera de aluminio es conductora y la menos apropiada cerca de conductores energizados; en su lugar deben usarse escaleras de fibra de vidrio u otras no conductoras."},
  {"id":232,"q":"Un receptáculo de 15 o 20 amperios, 125 voltios en un lugar mojado debe tener un encerramiento que sea a prueba de intemperie ¿bajo qué condición?","opts":["Solo cuando la cubierta está cerrada","Esté o no insertada una clavija de enchufe","Solo cuando no hay un enchufe insertado","Solo durante clima seco"],"re":"NEC 406.9(B)(1) requiere que los receptáculos en lugares mojados tengan un encerramiento a prueba de intemperie (una cubierta de uso/mientras está en uso) que permanezca a prueba de intemperie esté o no insertado un enchufe."},
  {"id":233,"q":"¿Cuál de los siguientes métodos de cableado es flexible y se usa comúnmente para la conexión final a un motor a fin de reducir la transmisión de vibración y ruido?","opts":["Conduit metálico rígido (RMC)","PVC Cédula 80","Tubería metálica eléctrica (EMT)","Conduit metálico flexible (FMC)"],"re":"Según el Artículo 348 del NEC, el conduit metálico flexible (FMC) se usa donde se necesita flexibilidad, como en las conexiones de motores, para amortiguar la vibración."},
  {"id":234,"q":"Un transformador monofásico reduce 7,200 V a 240 V; si el primario consume 5 A, ¿cuál es la corriente secundaria aproximada (ignorando las pérdidas)?","opts":["0.17 A","30 A","150 A","300 A"],"re":"Corriente secundaria = corriente primaria × (V primario ÷ V secundario) = 5 × (7200 ÷ 240) = 5 × 30 = 150 A."},
  {"id":235,"q":"Si un megóhmetro lee una resistencia de aislamiento muy baja o cercana a cero entre un conductor y tierra, ¿qué indica esto con mayor probabilidad?","opts":["Aislamiento excelente","Un sistema correctamente puesto a tierra que no requiere más acción","Un circuito abierto","Ruptura del aislamiento o una falla a tierra"],"re":"Una lectura muy baja de resistencia de aislamiento indica un aislamiento deteriorado o dañado o una ruta de falla a tierra, que debe corregirse antes de energizar."},
  {"id":236,"q":"Si descubre a un compañero de trabajo que todavía está en contacto con un conductor energizado y no puede soltarse, ¿cuál es la primera acción correcta?","opts":["Agarrar inmediatamente a la víctima y jalarla con las manos desnudas","Echar agua a la víctima para enfriar las quemaduras","Desenergizar el circuito o usar un objeto no conductor para separar a la víctima de la fuente","Comenzar compresiones torácicas mientras la víctima todavía está energizada"],"re":"Primero debe eliminar la fuente de electricidad, ya sea cortando la energía o usando un medio no conductor para liberar a la víctima, antes de tocarla o comenzar la RCP."},
  {"id":237,"q":"¿Qué canalización flexible está específicamente listada y es adecuada para uso en lugares mojados y ambientes húmedos donde pueden estar presentes líquidos?","opts":["Conduit metálico flexible (FMC)","Conduit metálico flexible hermético a líquidos (LFMC)","Tubería no metálica eléctrica (ENT) sin accesorios","EMT estándar sin accesorios a prueba de intemperie"],"re":"Según el Artículo 350 del NEC, el conduit metálico flexible hermético a líquidos (LFMC) tiene una cubierta exterior hermética a líquidos que lo hace adecuado para lugares mojados; el FMC estándar no lo es."},
  {"id":238,"q":"Según la Tabla 430.248 del NEC, la corriente a plena carga de un motor monofásico de 240 V, 5 HP es aproximadamente:","opts":["28 A","15 A","56 A","8 A"],"re":"La Tabla 430.248 del NEC indica un motor monofásico de 5 HP a 230 V (usado para 240 V) con 28 A de corriente a plena carga."},
  {"id":239,"q":"En un devanado de transformador trifásico conectado en delta, ¿cómo se relaciona la corriente de línea con la corriente de fase (devanado)?","opts":["La corriente de línea es igual a 3 veces la corriente de fase","La corriente de línea es igual a la corriente de fase","La corriente de línea es un tercio de la corriente de fase","La corriente de línea es igual a la raíz cuadrada de 3 por la corriente de fase"],"re":"En una conexión delta la corriente de línea es igual a la corriente de fase multiplicada por la raíz cuadrada de 3, mientras que los voltajes de línea y de fase son iguales."},
  {"id":240,"q":"La tubería no metálica eléctrica (ENT) generalmente NO se permite instalar en cuál de los siguientes lugares?","opts":["Expuesta donde está sujeta a daño físico","Oculta dentro de paredes, pisos y techos","Sobre un techo suspendido en un edificio de un piso","Embebida en una losa de concreto"],"re":"Según NEC 362.12, el ENT no se permite donde esté sujeto a daño físico porque su material no metálico ofrece protección mecánica limitada."},
  {"id":241,"q":"La cubierta que mantiene un receptáculo exterior a prueba de intemperie incluso mientras un cordón está enchufado se llama comúnmente ¿cómo?","opts":["Una placa de cubierta empotrada","Una cubierta ciega","Una junta de placa frontal","Una cubierta de uso (mientras está en uso)"],"re":"Una cubierta de uso o mientras está en uso (NEC 406.9(B)(1)) es un encerramiento tipo burbuja que mantiene la integridad a prueba de intemperie mientras un enchufe y cordón permanecen insertados en un lugar mojado."},
  {"id":242,"q":"Después de que una víctima de descarga ha sido separada con seguridad de la fuente eléctrica y se encuentra sin pulso y sin respiración, ¿cuál es el paso apropiado a seguir?","opts":["Esperar a que sanen las quemaduras antes de actuar","Comenzar la RCP y hacer que alguien llame a los servicios de emergencia","Darle agua a la víctima para beber","Llevar a la víctima a un vehículo y conducir al hospital sin más ayuda"],"re":"Una vez que la víctima está libre de la fuente y no muestra pulso ni respiración, comience la RCP de inmediato y asegúrese de que se llame a los servicios médicos de emergencia."},
  {"id":243,"q":"Al dimensionar los conductores del circuito ramal para un solo motor de funcionamiento continuo, ¿qué valor de corriente requiere usar el NEC?","opts":["La corriente real medida del motor","La corriente de rotor bloqueado","El valor de corriente a plena carga de las tablas de motores del NEC","La corriente de placa dividida por 1.25"],"re":"NEC 430.6(A) requiere usar los valores de corriente a plena carga de las Tablas 430.247 a 430.250 en lugar de la corriente de placa para el dimensionamiento de conductores."},
  {"id":244,"q":"El cable tipo AC (blindado) debe sujetarse a intervalos que no excedan qué distancia cuando se instala a lo largo de los miembros estructurales?","opts":["3 pies","8 pies","4 1/2 pies","6 pies"],"re":"Según NEC 320.30, el cable tipo AC debe sujetarse a intervalos que no excedan 4 1/2 pies."},
  {"id":245,"q":"¿Qué función del instrumento es la elección correcta para verificar que un fusible está bueno sin retirarlo de un portafusibles desenergizado?","opts":["Voltaje de CA","Corriente con pinza","Continuidad (ohmios)","Resistencia de aislamiento"],"re":"En un circuito desenergizado, la función de continuidad (ohmios) muestra una resistencia baja a través de un fusible bueno y un circuito abierto (sin continuidad) a través de un fusible fundido."},
  {"id":246,"q":"¿Por qué es peligroso tocar a una víctima de descarga eléctrica que todavía está en contacto con la fuente energizada antes de que se retire la energía?","opts":["La víctima puede portar una enfermedad contagiosa","La ropa de la víctima puede ser inflamable","La corriente puede pasar a través de la víctima y hacia el rescatista, creando una segunda víctima","El rescatista podría dañar el equipo eléctrico"],"re":"Si la fuente todavía está energizada, la corriente puede fluir a través de la víctima hacia el rescatista, convirtiéndolo en una segunda víctima de descarga."},
  {"id":247,"q":"Un motor monofásico de 230 V está clasificado en 1 HP y opera a aproximadamente 80% de eficiencia con factor de potencia unitario; ¿aproximadamente qué corriente consume?","opts":["3.2 A","4.1 A","2.0 A","6.5 A"],"re":"Vatios de entrada = 746 ÷ 0.80 = 932.5 W; I = 932.5 ÷ 230 = 4.1 A (1 HP = 746 W)."},
  {"id":248,"q":"¿Qué tipo de cable está específicamente listado para enterramiento directo en la tierra sin requerir una canalización protectora?","opts":["Cable tipo NM","Cable tipo AC","Cable tipo MC no marcado para enterramiento directo","Cable tipo UF"],"re":"Según el Artículo 340 del NEC, el cable tipo UF (alimentador subterráneo) está listado y es adecuado para enterramiento directo en la tierra."},
  {"id":249,"q":"¿Cuál es la razón principal por la que se prefiere un destornillador o llave de torque sobre el apriete manual para las terminaciones eléctricas?","opts":["Aplica el par de torsión especificado por el fabricante para asegurar una conexión confiable de baja resistencia","Aumenta la capacidad de corriente del conductor","Elimina la necesidad de un pelacables","Es más rápido que una herramienta común"],"re":"Una herramienta de torque calibrada aplica el valor exacto especificado por el fabricante, evitando conexiones demasiado flojas (sobrecalentamiento) o demasiado apretadas (daño), lo cual se requiere para muchas terminaciones listadas."},
  {"id":250,"q":"Un conductor puesto a tierra (neutro) aislado de 6 AWG o menor debe identificarse con cuál color?","opts":["Verde","Azul","Rojo","Blanco o gris"],"re":"NEC 200.6(A) requiere que los conductores puestos a tierra (neutros) de 6 AWG o menores se identifiquen con un acabado exterior continuo blanco o gris, o tres franjas continuas blancas/grises."},
  {"id":251,"q":"¿Cuántos vatios equivalen a un caballo de fuerza para los cálculos de motores eléctricos?","opts":["550 W","1,000 W","746 W","1,200 W"],"re":"Un caballo de fuerza equivale a 746 vatios, la conversión estándar usada en los cálculos de carga de motores."},
  {"id":252,"q":"Según las reglas de OSHA para cableado temporal en construcción, los cordones y cables flexibles usados para energía temporal deben protegerse contra daños; ¿qué condición haría que un cordón sea inaceptable para uso continuado?","opts":["La cubierta exterior está cortada o partida, exponiendo los conductores internos","El cordón está clasificado para uso rudo o extra rudo","El cordón es de color naranja","El cordón mide más de 25 pies"],"re":"Un cordón con una cubierta exterior dañada que expone los conductores debe retirarse del servicio; la longitud o el color por sí solos no hacen que un cordón sea inaceptable."},
  {"id":253,"q":"El cable tipo NM (con cubierta no metálica) se permite usar en cuál de los siguientes lugares?","opts":["Lugares mojados como enterramiento directo","Embebido en concreto vertido","Expuesto a aceites y otros agentes deteriorantes","Lugares secos de interiores normalmente secos y no corrosivos"],"re":"Según NEC 334.10 y 334.12, el cable tipo NM se permite en lugares normalmente secos y no se permite en lugares mojados, embebido en concreto ni donde esté expuesto a condiciones corrosivas."},
  {"id":254,"q":"El encerramiento y el núcleo de un transformador deben conectarse a cuál conductor por seguridad?","opts":["El conductor no puesto a tierra (vivo)","El conductor de puesta a tierra de equipos","El neutro secundario solo en el lado de la carga","No se requiere conexión"],"re":"Las partes metálicas no conductoras de corriente de un transformador, como su encerramiento y núcleo, deben unirse al conductor de puesta a tierra de equipos para proporcionar una ruta segura de despeje de fallas."},
  {"id":255,"q":"Según la Tabla 430.250 del NEC, un motor trifásico de 460 V, 10 HP tiene una corriente a plena carga de aproximadamente:","opts":["28 A","14 A","21 A","9 A"],"re":"La Tabla 430.250 del NEC indica un motor trifásico de 10 HP, 460 V con 14 A de corriente a plena carga."},
  {"id":256,"q":"Cuando se instalan accesorios en un conduit que entra a un encerramiento en un lugar mojado, ¿qué tipo de accesorio debe usarse?","opts":["Un conector estándar para interiores","Una arandela reductora","Un accesorio hermético a la lluvia o clasificado para lugares mojados","Un accesorio de tornillo prisionero"],"re":"Según NEC 314.15 y 300.5, los accesorios y encerramientos usados en lugares mojados deben estar listados para lugares mojados para prevenir la entrada de humedad."},
  {"id":257,"q":"Para el cableado temporal en una obra de construcción, los cordones flexibles generalmente deben ser de qué tipo para soportar las condiciones de la obra?","opts":["Cordón de lámpara de servicio ligero","Conductores desnudos no trenzados","Alambre de campana de un solo conductor","Listado para uso rudo o extra rudo"],"re":"Los cordones temporales de obra deben estar listados para uso rudo o extra rudo para que la cubierta pueda resistir el maltrato que se encuentra en las obras de construcción."},
  {"id":258,"q":"Durante el arranque, un electricista usa un amperímetro de pinza en cada fase de un alimentador de motor trifásico; ¿qué sugiere con mayor probabilidad un gran desequilibrio entre las corrientes de fase?","opts":["El motor está operando normalmente","El medidor de pinza está leyendo la resistencia de aislamiento","Una posible falla en el devanado, conexión floja o desequilibrio de voltaje","La rotación de fase está invertida"],"re":"Un desequilibrio significativo de corriente entre fases a menudo indica una falla en desarrollo en el devanado, una conexión de alta resistencia (floja) o un desequilibrio de voltaje de suministro que debe investigarse."},
  {"id":259,"q":"Un conductor de puesta a tierra de equipos (EGC), cuando está aislado, se identifica por cuál de los siguientes?","opts":["Blanco o gris","Negro sólido","Verde, o verde con una o más franjas amarillas","Rojo sólido"],"re":"NEC 250.119 permite que un EGC aislado sea verde, o verde con una o más franjas amarillas; también puede ser desnudo."},
  {"id":260,"q":"Al dimensionar los conductores del circuito ramal para un solo motor de servicio continuo, la capacidad de corriente del conductor debe ser al menos qué porcentaje de la corriente a plena carga del motor?","opts":["100%","115%","125%","150%"],"re":"NEC 430.22 requiere que los conductores del circuito ramal del motor tengan una capacidad de corriente de al menos 125% de la corriente a plena carga del motor."},
  {"id":261,"q":"Los cables o canalizaciones instalados paralelos a los miembros estructurales deben retraerse del borde más cercano del miembro estructural por al menos qué distancia para evitar la necesidad de una placa protectora?","opts":["3/4 de pulgada","1 1/4 pulgadas","1 pulgada","1 1/2 pulgadas"],"re":"Según NEC 300.4(D), los cables tendidos paralelos a los miembros estructurales deben estar al menos a 1 1/4 pulg. del borde más cercano, o estar protegidos por una placa de acero."},
  {"id":262,"q":"¿Qué práctica que involucra un cordón de extensión en una obra es un peligro de seguridad reconocido?","opts":["Retirar la pata de puesta a tierra del enchufe del cordón para que entre en un receptáculo de dos ranuras","Usar un cordón listado para uso en exteriores","Usar un cordón con un enchufe moldeado intacto","Enrollar ordenadamente el cordón no usado fuera de las áreas de paso"],"re":"Cortar o retirar la pata de puesta a tierra anula la ruta de puesta a tierra de equipos y es un peligro grave; las otras prácticas son aceptables."},
  {"id":263,"q":"Un factor de demanda se describe mejor como:","opts":["La relación entre la demanda máxima y la carga conectada total","La suma de todas las cargas conectadas","La relación entre el voltaje de placa y el voltaje de operación","El producto del voltaje y la corriente"],"re":"Según el Artículo 100 del NEC, el factor de demanda es la relación entre la demanda máxima de un sistema y la carga conectada total, lo que permite un dimensionamiento realista por debajo del 100% de la carga conectada."},
  {"id":264,"q":"¿Qué canalización tiene la pared más gruesa y pesada y proporciona la mayor protección física para los conductores?","opts":["Tubería no metálica eléctrica (ENT)","Tubería metálica eléctrica (EMT)","Conduit metálico rígido (RMC)","Conduit metálico flexible (FMC)"],"re":"Según el Artículo 344 del NEC, el conduit metálico rígido (RMC) es la canalización de acero de pared más pesada y ofrece la mayor protección física en comparación con el IMC y el EMT."},
  {"id":265,"q":"Antes de aplicar una prueba de megóhmetro de alto voltaje a un circuito, ¿qué debe confirmarse primero?","opts":["El circuito está completamente energizado","El circuito está desenergizado y aislado, y los componentes electrónicos sensibles están desconectados","Hay una carga conectada en el extremo lejano","La rotación de fase es correcta"],"re":"La prueba de resistencia de aislamiento aplica alto voltaje de CC, por lo que el circuito debe estar desenergizado, aislado y cualquier equipo electrónico sensible debe estar desconectado para evitar daños y garantizar la seguridad."},
  {"id":266,"q":"Un cordón de extensión usado para alimentar una herramienta portátil pasa a través de una puerta donde podría ser pellizcado por la puerta; ¿qué requiere generalmente OSHA respecto a los cordones flexibles?","opts":["Los cordones flexibles no deben pasarse a través de puertas, ventanas o aberturas similares donde puedan dañarse","Los cordones pueden pasarse a través de puertas si la puerta se mantiene abierta con el cordón","Los cordones a través de puertas están bien si se pegan con cinta al piso","Solo los cordones con cubierta metálica pueden pasar a través de puertas"],"re":"OSHA prohíbe pasar cordones flexibles a través de puertas, ventanas, agujeros en paredes o aberturas similares donde estén sujetos a daño."},
  {"id":267,"q":"El conduit de PVC Cédula 80 se prefiere sobre el PVC Cédula 40 en cuál aplicación?","opts":["Bajo tierra en áreas sin tráfico","Dentro de paredes interiores secas","Dentro de un ático terminado sin acceso","Donde esté expuesto a daño físico"],"re":"Según NEC 352.10, el PVC Cédula 80 tiene una pared más gruesa y se permite donde el conduit esté expuesto a daño físico, mientras que la Cédula 40 no lo está."},
  {"id":268,"q":"Un tablero tiene 60 kVA de carga conectada con un factor de demanda aplicable de 70%; ¿cuál es la carga de demanda calculada?","opts":["60 kVA","86 kVA","18 kVA","42 kVA"],"re":"Carga de demanda = carga conectada × factor de demanda = 60 × 0.70 = 42 kVA."},
  {"id":269,"q":"Un conductor de puesta a tierra de equipos también puede instalarse como cuál de los siguientes?","opts":["Un conductor aislado blanco","Un conductor aislado gris","Un conductor desnudo","Un conductor aislado azul"],"re":"NEC 250.118 y 250.119 permiten que un conductor de puesta a tierra de equipos sea un conductor desnudo, además de la identificación aislada verde/verde-amarillo."},
  {"id":270,"q":"Dos devanados de transformador buck-boost de 120 V se conectan para aumentar un suministro de 208 V; ¿cuál es la principal ventaja de usar una conexión buck-boost en lugar de un transformador de aislamiento para esta pequeña corrección?","opts":["Proporciona aislamiento completo de la fuente","Es más pequeño y menos costoso porque solo maneja la porción aumentada de la carga","Convierte el suministro a trifásico","Elimina la necesidad de protección contra sobrecorriente"],"re":"Debido a que un buck-boost se conecta como un autotransformador que solo procesa la pequeña diferencia de voltaje, es físicamente más pequeño y menos costoso que un transformador de aislamiento completo de la misma carga."},
  {"id":271,"q":"¿Por qué los cordones flexibles usados como cableado temporal en una obra de construcción no deben usarse como sustituto del cableado fijo (permanente) de una estructura?","opts":["Los cordones flexibles son más costosos que el cableado permanente","Los cordones flexibles no están destinados a instalación permanente y son más propensos a daños y sobrecalentamiento en ese papel","Los cordones flexibles transportan muy poca corriente para cualquier herramienta","Los cordones flexibles son ilegales de fabricar"],"re":"Los cordones flexibles no son un sustituto del cableado fijo porque están sujetos a daño mecánico, no están protegidos dentro de la estructura del edificio y pueden sobrecalentarse cuando se usan permanentemente."},
  {"id":272,"q":"Un conductor o cable instalado a través de un miembro estructural metálico debe protegerse con un buje o ojal donde se requiera porque el borde metálico puede causar qué tipo de daño?","opts":["Caída de voltaje","Interferencia electromagnética","Acumulación excesiva de calor","Abrasión o corte del aislamiento del conductor"],"re":"Según NEC 300.4(B), donde los cables pasan a través de agujeros perforados de fábrica o en campo en miembros estructurales metálicos, los bujes u ojales listados protegen el cable de la abrasión contra los bordes metálicos afilados."},
  {"id":273,"q":"Bajo el método estándar del Artículo 220 del NEC, ¿cuál es el valor de carga de iluminación general asignado por pie cuadrado de una unidad de vivienda?","opts":["1 VA por pie cuadrado","2 VA por pie cuadrado","3 VA por pie cuadrado","5 VA por pie cuadrado"],"re":"La Tabla 220.12 del NEC asigna 3 VA por pie cuadrado para iluminación general en unidades de vivienda."},
  {"id":274,"q":"¿Qué verifica una prueba de continuidad de un conductor de puesta a tierra de equipos durante la puesta en servicio?","opts":["Que hay una ruta metálica completa de baja resistencia de regreso a la fuente","La resistencia exacta a tierra en ohmios","La calidad del aislamiento del conductor","La secuencia de fase del suministro"],"re":"Una prueba de continuidad en el conductor de puesta a tierra de equipos verifica una ruta ininterrumpida de baja resistencia para que la corriente de falla regrese a la fuente y opere el dispositivo de sobrecorriente."},
  {"id":275,"q":"Cuando el cable tipo NM se tiende a través de agujeros perforados en montantes o viguetas de madera, la sujeción adicional a lo largo de esa porción del tramo se considera satisfecha porque los agujeros proporcionan qué?","opts":["Continuidad de puesta a tierra","Soporte y protección en cada penetración","Reducción de capacidad requerida","Compensación de expansión"],"re":"Según NEC 334.30, el cable NM instalado a través de agujeros perforados en miembros estructurales se considera soportado y sujetado por la estructura donde los intervalos no exceden los límites del código."},
  {"id":276,"q":"Las partes vivas de equipos eléctricos que operan a 50 voltios o más generalmente deben protegerse contra el contacto accidental; ¿cuál de los siguientes es un método aceptable de protección?","opts":["Colocar el equipo en una habitación o encerramiento accesible solo a personas calificadas","Pintar las partes vivas de un color brillante","Colocar un letrero de advertencia sin barrera física","Recubrir las partes con una capa delgada de aceite"],"re":"Proteger las partes vivas por ubicación en una habitación, bóveda o encerramiento controlado accesible solo a personas calificadas es un método aceptado; un letrero o pintura por sí solos no son suficientes."},
  {"id":277,"q":"¿Cuál es la carga de iluminación general para una vivienda con 2,000 pies cuadrados de espacio habitable usando el cálculo estándar?","opts":["6,000 VA","4,000 VA","2,000 VA","10,000 VA"],"re":"Iluminación general = área × 3 VA/pie² = 2,000 × 3 = 6,000 VA."},
  {"id":278,"q":"¿Qué color NO se permite usar para identificar un conductor no puesto a tierra (vivo)?","opts":["Blanco","Rojo","Negro","Azul"],"re":"Los conductores no puestos a tierra pueden ser de cualquier color excepto blanco, gris o verde (que están reservados para los conductores puestos a tierra y de puesta a tierra); el blanco está reservado para el conductor puesto a tierra según NEC 200.6/200.7."},
  {"id":279,"q":"Un transformador ideal eleva 240 V a 480 V; si la carga en el lado de 480 V consume 10 A, ¿cuál es la corriente primaria aproximada (despreciando las pérdidas)?","opts":["20 A","10 A","5 A","40 A"],"re":"La potencia de entrada es igual a la potencia de salida para un transformador ideal, entonces la corriente primaria es igual a los VA secundarios divididos por el voltaje primario: (480 V x 10 A) / 240 V es igual a 20 A."},
  {"id":280,"q":"¿Cuál es el espaciamiento máximo para los soportes del conduit metálico rígido (RMC) de tamaño comercial 1/2 a 3/4 instalado expuesto en un tramo horizontal recto?","opts":["6 pies","16 pies","10 pies","12 pies"],"re":"Según la Tabla 344.30(B)(2) del NEC, el RMC de tamaño comercial 1/2 y 3/4 requiere un espaciamiento de soporte que no exceda 10 pies."},
  {"id":281,"q":"¿Cuántos voltamperios requiere el NEC por cada uno de los dos circuitos ramales mínimos de pequeños electrodomésticos en un cálculo de carga de vivienda?","opts":["1,000 VA cada uno","1,500 VA cada uno","2,000 VA cada uno","3,000 VA cada uno"],"re":"NEC 220.52(A) requiere que cada circuito ramal de pequeños electrodomésticos se calcule a 1,500 VA."},
  {"id":282,"q":"El propósito principal de proteger las partes vivas en equipos eléctricos es hacer cuál de los siguientes?","opts":["Mejorar la apariencia de la instalación","Aumentar la clasificación de voltaje de los conductores","Reducir el costo del equipo","Prevenir el contacto accidental de personas y proteger contra descarga eléctrica"],"re":"Proteger las partes vivas tiene como objetivo prevenir el contacto inadvertido de personas, protegiendo así contra descargas eléctricas y quemaduras."},
  {"id":283,"q":"Al diagnosticar con un multímetro, lee 0 voltios a través de un interruptor cerrado que debería estar pasando corriente a una carga en funcionamiento; ¿qué indica esta lectura sobre el interruptor?","opts":["El interruptor está bueno, ya que un interruptor cerrado debería tener poca o ninguna caída de voltaje a través de él","El interruptor está abierto y defectuoso","La carga está en cortocircuito","El voltaje de suministro es demasiado alto"],"re":"Un interruptor correctamente cerrado tiene una caída de voltaje de casi cero a través de él, por lo que leer 0 V a través de él mientras la carga opera indica que los contactos del interruptor están buenos."},
  {"id":284,"q":"Una caja de empalmes debe tener su volumen marcado o ser de tamaño suficiente para que el relleno total de la caja no exceda cuál de los siguientes?","opts":["La mitad del número de abrazaderas de cable","Exactamente el 75 por ciento del volumen de la caja","Dos veces el área del conductor más pequeño","El volumen marcado o calculado de la caja"],"re":"Según NEC 314.16(A) y (B), el volumen total calculado de todo el contenido no debe exceder el volumen marcado o calculado de la caja."},
  {"id":285,"q":"En un cálculo de carga estándar de una unidad de vivienda, el circuito ramal de lavandería se calcula en qué valor?","opts":["1,000 VA","1,500 VA","2,000 VA","1,200 VA"],"re":"NEC 220.52(B) requiere que el circuito ramal de lavandería se calcule a 1,500 VA."},
  {"id":286,"q":"Un GFCI proporciona protección contra cuál peligro específico?","opts":["Sobrecorriente de un cortocircuito entre conductores vivos","Corriente de falla línea a tierra que fluye a través de una persona hacia tierra","Sobrevoltaje de un rayo","Caída de voltaje en un alimentador largo"],"re":"Un GFCI detecta pequeños desequilibrios causados por corriente que se fuga a tierra (como a través de una persona) y se dispara para prevenir una descarga fatal; no es principalmente un dispositivo de sobrecorriente o de sobretensión."},
  {"id":287,"q":"Cuando un conductor blanco en un cable se usa como conductor no puesto a tierra en un lazo de interruptor, ¿qué debe hacer el electricista en las terminaciones?","opts":["Dejarlo blanco ya que está en un cable","Conectarlo solo a la barra de neutro","Reidentificarlo con un color que no sea blanco, gris o verde","Cortarlo y taparlo"],"re":"NEC 200.7(C) permite que un conductor blanco en un cable sirva como conductor no puesto a tierra solo si se reidentifica permanentemente para indicar su uso, marcándolo con un color que no sea blanco, gris o verde."},
  {"id":288,"q":"En un cálculo de relleno de caja, ¿cómo se cuentan los conductores que se originan fuera de la caja y pasan a través de ella sin empalme ni terminación?","opts":["Cada uno se cuenta una vez según su tamaño","Cada uno se cuenta como dos conductores","No se cuentan","Solo se cuenta el más grande"],"re":"Según NEC 314.16(B)(1), cada conductor que pasa a través de la caja sin empalme ni terminación se cuenta una vez como una sola asignación de volumen de conductor."},
  {"id":289,"q":"¿Cuál de las siguientes es una práctica de seguridad correcta al usar un multímetro para medir voltaje en un tablero energizado?","opts":["Seleccionar una clasificación CAT y un medidor clasificados para el circuito, e inspeccionar las puntas antes de usarlas","Configurar primero el medidor en la función de ohmios","Sostener ambas puntas en una mano para estabilidad","Usar un medidor y puntas clasificados por debajo del voltaje del sistema"],"re":"Medir voltaje energizado de manera segura requiere un medidor y puntas con la clasificación CAT adecuada apropiados para el circuito e inspeccionar las puntas en busca de daños antes de usarlas."},
  {"id":290,"q":"Usando el método estándar, la carga combinada de iluminación general, pequeños electrodomésticos y lavandería de una vivienda totaliza 12,000 VA; ¿cuál es la demanda después de aplicar la Tabla 220.42 del NEC (los primeros 3,000 VA al 100%, el resto al 35%)?","opts":["12,000 VA","4,200 VA","6,150 VA","9,000 VA"],"re":"Los primeros 3,000 VA al 100% = 3,000; los 9,000 VA restantes al 35% = 3,150; total = 6,150 VA según la Tabla 220.42."},
  {"id":291,"q":"Cuando hay una o más abrazaderas de cable internas presentes en una caja, ¿cuántas asignaciones de volumen de conductor se agregan por todas las abrazaderas?","opts":["Ninguna, las abrazaderas no se cuentan","Dos sin importar el tamaño del conductor","Una por cada abrazadera presente","Una sola asignación de volumen basada en el conductor más grande en la caja"],"re":"Según NEC 314.16(B)(2), una o más abrazaderas de cable internas cuentan colectivamente como una sola asignación de volumen de conductor basada en el conductor más grande que entra a la caja."},
  {"id":292,"q":"¿Protege un GFCI estándar a una persona contra una descarga recibida al contactar simultáneamente los conductores vivo y neutro (línea a línea)?","opts":["Sí, siempre previene todas las descargas","Sí, pero solo en circuitos de 240 voltios","No, porque la corriente está balanceada y no se detecta desequilibrio a tierra","No, porque los GFCI solo funcionan con corriente continua"],"re":"Si una persona contacta tanto el vivo como el neutro, la corriente regresa a través del neutro y permanece balanceada, por lo que el GFCI no ve desequilibrio de falla a tierra y no se disparará."},
  {"id":293,"q":"Un transformador trifásico de primario en delta, secundario en estrella está energizado; en el secundario en estrella el voltaje de fase mide 277 V, entonces ¿cuál es el voltaje línea a línea esperado?","opts":["Aproximadamente 480 V","Aproximadamente 831 V","Aproximadamente 160 V","277 V"],"re":"En un secundario en estrella el voltaje línea a línea es igual al voltaje de fase por la raíz cuadrada de 3, entonces 277 V por 1.732 es aproximadamente 480 V."},
  {"id":294,"q":"Una vivienda tiene dos circuitos de pequeños electrodomésticos y un circuito de lavandería; ¿qué VA total aportan estos tres circuitos antes de aplicar el factor de demanda?","opts":["3,000 VA","1,500 VA","6,000 VA","4,500 VA"],"re":"Dos circuitos de pequeños electrodomésticos (2 × 1,500) + un circuito de lavandería (1,500) = 3,000 + 1,500 = 4,500 VA."},
  {"id":295,"q":"¿Qué canalización es una tubería no metálica corrugada y flexible, a menudo de color, que está destinada a instalación oculta en trabajos residenciales y comerciales ligeros?","opts":["Conduit metálico intermedio (IMC)","Conduit no metálico flexible hermético a líquidos (LFNC)","Conduit rígido de PVC","Tubería no metálica eléctrica (ENT)"],"re":"Según el Artículo 362 del NEC, la tubería no metálica eléctrica (ENT) es una canalización corrugada flexible, a menudo de color, usada en lugares ocultos."},
  {"id":296,"q":"¿Qué conductor en un receptáculo dúplex estándar debe conectarse al terminal identificado por los tornillos plateados o de color claro?","opts":["El conductor puesto a tierra (neutro)","El conductor no puesto a tierra (vivo)","El conductor de puesta a tierra de equipos","El conductor viajero"],"re":"En un receptáculo, los tornillos plateados/de color claro son los terminales puestos a tierra (neutro); los tornillos de latón son los terminales no puestos a tierra y el tornillo verde es para el EGC, según NEC 200.10 y 250.126."},
  {"id":297,"q":"Después de instalar un receptáculo GFCI en una obra, ¿qué debe hacer el electricista para verificar que funciona correctamente?","opts":["Medir la longitud del cordón","Dejarlo sin probar hasta que llegue un inspector","Verificar el color de la placa frontal","Presionar el botón TEST y confirmar que el dispositivo se dispara, luego presionar RESET"],"re":"Presionar el botón TEST debería disparar el GFCI, confirmando que el mecanismo de protección funciona; luego RESET restaura la energía."},
  {"id":298,"q":"Durante una inspección previa a la energización, ¿cuál es el propósito de verificar que el puente de unión principal esté instalado en el servicio?","opts":["Conectar el conductor puesto a tierra al sistema de puesta a tierra de equipos para que la corriente de falla pueda despejarse","Aislar el neutro de tierra","Aumentar el voltaje a las cargas","Balancear las corrientes de fase"],"re":"El puente de unión principal conecta el conductor puesto a tierra (neutro) al sistema de puesta a tierra de equipos en el servicio, estableciendo la ruta que permite que la corriente de falla opere el dispositivo de sobrecorriente."},
  {"id":299,"q":"Usando la Tabla 220.55 Columna C del NEC, ¿cuál es la carga de demanda para una sola estufa eléctrica doméstica clasificada en 12 kW?","opts":["12 kW","6 kW","10 kW","8 kW"],"re":"La Tabla 220.55 Columna C del NEC da 8 kW para una estufa no mayor de 12 kW."},
  {"id":300,"q":"El conduit metálico flexible (FMC) usado como latiguillo de luminaria para la conexión a una luminaria generalmente se permite que esté sin soporte por una longitud que no exceda qué distancia?","opts":["3 pies","6 pies","4 1/2 pies","8 pies"],"re":"Según NEC 348.30(A), el FMC se permite que esté sin soporte hasta 6 pies desde el terminal de una luminaria para conexiones de derivación (latiguillos de luminaria)."},
  {"id":301,"q":"Un trabajador está usando una herramienta eléctrica portátil con cable en exteriores, en un área húmeda; ¿qué combinación brinda la mejor protección contra descargas eléctricas?","opts":["Una herramienta sin conexión a tierra y sin GFCI","Una herramienta correctamente conectada a tierra o con doble aislamiento, alimentada a través de un GFCI","Una herramienta con la espiga de conexión a tierra removida","Una herramienta conectada a un cable de extensión deshilachado"],"re":"La combinación más segura es una herramienta que esté correctamente conectada a tierra o con doble aislamiento y alimentada a través de protección GFCI, especialmente en lugares húmedos."},
  {"id":302,"q":"¿Cuál instrumento está diseñado específicamente para medir cuántos ohmios de resistencia existen entre un electrodo de puesta a tierra y la tierra circundante?","opts":["Medidor de resistencia de tierra (probador de tierra física)","Multímetro estándar en el rango de ohmios","Megóhmetro","Detector de voltaje sin contacto"],"re":"Un medidor de resistencia de tierra (tierra física) está diseñado para medir la resistencia del electrodo a la tierra, usando métodos de caída de potencial o de pinza que un ohmímetro estándar no puede realizar con precisión."},
  {"id":303,"q":"¿En cuál de las siguientes situaciones NO se requiere la fijación del cable NM?","opts":["Donde el cable se pasa con guía entre puntos de acceso a través de espacios ocultos de edificios terminados y el soporte es impracticable","Donde el cable entra a una caja montada en superficie","Donde el cable corre expuesto a lo largo de la cara de una pared terminada","Donde el cable corre por la parte inferior de las viguetas del piso"],"re":"Según el NEC 334.30(B), no se requiere fijación donde el cable se pasa con guía entre puntos de acceso a través de espacios ocultos de edificios terminados y el soporte es impracticable."},
  {"id":304,"q":"Según el NEC 220.54, ¿a qué valor mínimo debe calcularse una sola secadora eléctrica de ropa doméstica, aun si su placa de datos indica un valor menor?","opts":["3,000 VA","5,000 VA","4,500 VA","1,500 VA"],"re":"El NEC 220.54 exige que una secadora eléctrica doméstica se calcule a 5,000 VA o al valor de placa, lo que sea mayor."},
  {"id":305,"q":"Para controlar una sola luminaria desde dos ubicaciones diferentes, ¿qué arreglo de interruptores se utiliza?","opts":["Dos interruptores de un polo","Un interruptor de 4 vías","Dos interruptores de 3 vías","Dos interruptores de doble polo"],"re":"El control de una sola carga desde dos ubicaciones se logra con un par de interruptores de 3 vías conectados mediante conductores viajeros."},
  {"id":306,"q":"Una caja de salida montada en una pared terminada de material no combustible, como el panel de yeso, debe instalarse de modo que el borde frontal quede retraído no más de qué distancia respecto de la superficie terminada?","opts":["Al ras, sin retraimiento permitido","No más de 1/4 de pulgada por detrás de la superficie","No más de 1 pulgada por detrás de la superficie","No más de 1 1/4 pulgadas por detrás de la superficie"],"re":"Según el NEC 314.20, en paredes de material no combustible la caja puede quedar retraída no más de 1/4 in respecto de la superficie terminada."},
  {"id":307,"q":"Las quemaduras eléctricas por contacto con partes energizadas pueden ser engañosamente graves porque el daño tisular más severo a menudo ocurre ¿dónde?","opts":["Solo en la superficie de la piel","Solo en la ropa de la víctima","Solo en el cabello y las uñas","En el interior profundo del cuerpo, a lo largo de la trayectoria que toma la corriente entre los puntos de entrada y salida"],"re":"La corriente que pasa a través del cuerpo genera calor en lo profundo de los tejidos, por lo que el daño interno a lo largo de la trayectoria de la corriente suele ser mucho peor que las heridas visibles en la superficie."},
  {"id":308,"q":"¿Cuál es el tamaño mínimo de acometida, en amperios, requerido para una sola vivienda unifamiliar según el NEC 230.79(C)?","opts":["100 A","60 A","125 A","150 A"],"re":"El NEC 230.79(C) exige una capacidad mínima de 100 A para el medio de desconexión de la acometida de una vivienda unifamiliar."},
  {"id":309,"q":"¿Cuál es la forma más confiable de verificar que un circuito esté desenergizado antes de comenzar a trabajar, a veces llamada prueba vivo-muerto-vivo?","opts":["Probar el medidor en una fuente viva conocida, probar el circuito, y luego volver a probar la fuente viva conocida","Usar un detector sin contacto una sola vez","Mirar únicamente la posición de la palanca del interruptor","Suponer que está muerto si las luces están apagadas"],"re":"El método vivo-muerto-vivo (probar antes de tocar) confirma que el probador funciona en una fuente viva conocida, muestra que el circuito está muerto y luego vuelve a confirmar que el probador sigue funcionando, comprobando la ausencia de voltaje."},
  {"id":310,"q":"Una caja de salida instalada en una superficie de pared combustible, como el revestimiento de madera, debe instalarse de modo que el borde frontal quede posicionado ¿cómo respecto de la superficie terminada?","opts":["Al ras o sobresaliendo de la superficie terminada","Retraída 1/4 de pulgada","Retraída 1/2 pulgada","Retraída 1 pulgada"],"re":"Según el NEC 314.20, en paredes de material combustible la caja debe quedar al ras o sobresalir de la superficie terminada."},
  {"id":311,"q":"Una vivienda monofásica de 120/240 V tiene una carga de demanda total calculada de 24,000 VA; ¿cuál es la ampacidad mínima de acometida requerida?","opts":["200 A","150 A","125 A","100 A"],"re":"Amperios de acometida = VA ÷ V = 24,000 ÷ 240 = 100 A."},
  {"id":312,"q":"¿Cuál factor determina de forma más directa la magnitud de la corriente que fluirá a través de una persona que entra en contacto con un conductor energizado a un voltaje fijo?","opts":["La estatura de la persona","El color del aislamiento del conductor","La resistencia del cuerpo y de los puntos de contacto en la trayectoria de la corriente","La hora del día"],"re":"Por la ley de Ohm, para un voltaje dado la corriente es igual al voltaje dividido por la resistencia, por lo que una menor resistencia del cuerpo y de los puntos de contacto (por ejemplo, piel mojada) resulta en una corriente más alta y más peligrosa."},
  {"id":313,"q":"Se coloca un amperímetro de pinza alrededor de los tres conductores de fase de un circuito trifásico balanceado al mismo tiempo; ¿qué debería leer idealmente?","opts":["El voltaje de línea a línea","La suma de las tres corrientes de fase","La corriente de una sola fase","Aproximadamente cero, porque las corrientes balanceadas se cancelan"],"re":"Cuando todos los conductores de un conjunto balanceado pasan juntos a través de la pinza, sus campos magnéticos se cancelan, por lo que el medidor lee casi cero; este principio es la base de la detección de fallas a tierra."},
  {"id":314,"q":"Para controlar una sola luminaria desde tres o más ubicaciones, ¿qué combinación de interruptores se requiere?","opts":["Tres interruptores de 3 vías","Tres interruptores de un polo","Tres interruptores de 4 vías","Dos interruptores de 3 vías y uno o más interruptores de 4 vías"],"re":"El control desde tres o más ubicaciones usa dos interruptores de 3 vías en los extremos y uno o más interruptores de 4 vías en el medio, cableados mediante conductores viajeros."},
  {"id":315,"q":"El cable Tipo MC (blindado metálico) instalado expuesto y tendido sobre elementos de estructura debe fijarse a intervalos que no excedan qué distancia?","opts":["3 pies","6 pies","4 pies","8 pies"],"re":"Según el NEC 330.30, el cable Tipo MC debe fijarse a intervalos que no excedan 6 ft."},
  {"id":316,"q":"Al calcular la carga de un alimentador o acometida para una vivienda, los artefactos fijos como un calentador de agua y un lavavajillas se clasifican bajo cuál término del NEC?","opts":["Cargas de artefactos fijados en su lugar","Cargas continuas","Cargas de motor","Cargas de alumbrado general"],"re":"El NEC 220.53 cubre los artefactos fijados en su lugar (fijos), permitiendo un factor de demanda del 75% cuando hay cuatro o más en un alimentador de vivienda."},
  {"id":317,"q":"Al verificar las conexiones de un transformador en el arranque, ¿por qué es importante la polaridad correcta (aditiva vs sustractiva) al poner en paralelo o en banco los transformadores?","opts":["Una polaridad incorrecta puede causar un cortocircuito o un voltaje inadecuado cuando los devanados se interconectan","Solo afecta el color de los bujes","Determina la clase de aislamiento","Cambia la capacidad en kVA"],"re":"La polaridad del transformador debe verificarse para que los devanados interconectados o en paralelo se sumen correctamente; una polaridad invertida puede crear un cortocircuito directo o un voltaje de salida incorrecto."},
  {"id":318,"q":"En una obra de construcción, un receptáculo monofásico de 30 amperios y 125 voltios que no forma parte del cableado permanente y es usado por empleados debe contar con qué protección según OSHA 1926.404?","opts":["No se requiere protección especial","Solo una cubierta tipo seguro","Solo un protector contra sobretensiones","Protección GFCI o cobertura bajo un programa de conductor de puesta a tierra de equipos asegurado"],"re":"OSHA extiende el requisito de GFCI a los receptáculos monofásicos de 125 V de 15, 20 y 30 A que no forman parte del cableado permanente, con el programa de puesta a tierra asegurado como alternativa."},
  {"id":319,"q":"¿Cuál enunciado describe mejor el uso permitido del conduit metálico intermedio (IMC)?","opts":["Solo se permite en lugares interiores secos","Solo se permite bajo tierra","Nunca puede roscarse","Puede usarse en todas las mismas condiciones atmosféricas y ocupaciones que el RMC"],"re":"Según el Artículo 342 del NEC, el IMC es una canalización de acero de pared más delgada permitida en todas las mismas ubicaciones y condiciones que el conduit metálico rígido (RMC)."},
  {"id":320,"q":"Según el NEC 220.53, cuando hay cuatro o más artefactos fijados en su lugar en el mismo alimentador de vivienda, ¿qué factor de demanda puede aplicarse a su carga total de placa?","opts":["50%","75%","65%","100%"],"re":"El NEC 220.53 permite un factor de demanda del 75% para cuatro o más artefactos fijados en su lugar (excluyendo estufas, secadoras, calefacción de espacios y aire acondicionado)."},
  {"id":321,"q":"Durante la puesta en servicio, se toma una lectura de resistencia de aislamiento con megger de inmediato y nuevamente después de un minuto para calcular cuál valor diagnóstico útil?","opts":["Relación de vueltas","Rotación de fases","Índice de polarización (PI)","Resistencia del electrodo de tierra"],"re":"El índice de polarización es la relación entre la lectura de los 10 minutos (o 1 minuto) y la lectura anterior, indicando la condición del aislamiento; una relación más alta generalmente indica un aislamiento mejor y más seco."},
  {"id":322,"q":"Antes de comenzar la RCP en una víctima de descarga eléctrica, ¿cuál de las siguientes es la condición más importante que debe cumplirse?","opts":["Las quemaduras de la víctima han sido vendadas","El disyuntor ha sido reemplazado por uno nuevo","Se le han administrado líquidos a la víctima","La víctima ya no está en contacto con ninguna fuente energizada"],"re":"La RCP no debe comenzar hasta que la víctima esté completamente libre de la fuente energizada; de lo contrario, el rescatista corre el riesgo de recibir también una descarga."},
  {"id":323,"q":"Al determinar el tamaño mínimo de una caja que contiene varios conductores de diferentes tamaños, ¿cuál es el requisito de volumen total correcto?","opts":["El volumen del conductor más grande multiplicado por el número de conductores","La suma de las asignaciones de volumen individuales para cada conductor y componente","Siempre un mínimo de 18 pulgadas cúbicas","El volumen del conductor más pequeño únicamente"],"re":"Según el NEC 314.16(B), el llenado total de la caja es la suma de las asignaciones de volumen individuales para todos los conductores, dispositivos, abrazaderas y conductores de puesta a tierra."},
  {"id":324,"q":"¿Cuántas terminales tiene un interruptor de 3 vías sin contar el tornillo de puesta a tierra?","opts":["Dos","Tres","Cuatro","Cinco"],"re":"Un interruptor de 3 vías tiene tres terminales que conducen corriente: una terminal común (a menudo más oscura) y dos terminales viajeras."},
  {"id":325,"q":"Usando el NEC 220.12, el número mínimo de circuitos ramales de alumbrado general de 15 A, 120 V requeridos para 6,000 VA de carga de alumbrado de vivienda es:","opts":["4 circuitos","2 circuitos","5 circuitos","8 circuitos"],"re":"Cada circuito de 15 A, 120 V soporta 1,800 VA; 6,000 ÷ 1,800 = 3.33, redondeado hacia arriba a 4 circuitos."},
  {"id":326,"q":"El conduit no metálico flexible hermético a líquidos (LFNC) y el conduit metálico flexible hermético a líquidos (LFMC) requieren accesorios listados principalmente para mantener cuál característica de la instalación?","opts":["La integridad hermética a líquidos en las terminaciones","El radio máximo de doblez","La codificación por colores","Solo la continuidad de puesta a tierra"],"re":"Según el NEC 350.42 y 356.42, solo pueden usarse accesorios listados e identificados para el conduit a fin de preservar el sello hermético a líquidos en las conexiones."},
  {"id":327,"q":"¿Cuál es el primer paso correcto para invertir la rotación de un motor trifásico en marcha que se encuentra girando en el sentido incorrecto en el arranque?","opts":["Desenergizar e intercambiar dos cualesquiera de los tres conductores de línea","Aumentar el voltaje de suministro","Agregar un transformador buck-boost","Invertir solamente el conductor de puesta a tierra de equipos"],"re":"La rotación de un motor trifásico se invierte desenergizando el circuito e intercambiando dos cualesquiera de los tres conductores de línea (fase) en las terminales del motor."},
  {"id":328,"q":"¿Por qué la resistencia de la piel humana es un factor importante en la severidad de la descarga eléctrica, y cómo afecta la humedad?","opts":["La humedad aumenta la resistencia de la piel, reduciendo el flujo de corriente","La piel seca siempre permite más corriente que la piel mojada","La humedad no tiene efecto sobre la resistencia de la piel","La humedad reduce la resistencia de la piel, permitiendo que fluya más corriente y aumentando el peligro"],"re":"La piel mojada o sudorosa tiene una resistencia mucho menor que la piel seca, por lo que para el mismo voltaje fluye más corriente a través del cuerpo, haciendo la descarga más peligrosa."},
  {"id":329,"q":"En el cálculo estándar de vivienda, las cargas de demanda de la estufa y la secadora se suman a la demanda de alumbrado/artefactos en qué porcentaje de sus valores de demanda calculados según el NEC?","opts":["35%","100%","75%","40%"],"re":"Después de aplicar los factores de demanda de las Tablas 220.55 y 220.54, los valores de demanda de la estufa y la secadora se suman al 100% al cálculo de acometida/alimentador."},
  {"id":330,"q":"Un tramo de EMT contiene tres dobleces de 90 grados y un doblez de 45 grados entre dos cajas de jalado; ¿cuál es el total de dobleces en grados, y es aceptable?","opts":["315 grados, aceptable","315 grados, no aceptable","405 grados, no aceptable","270 grados, aceptable"],"re":"Tres dobleces de 90 grados (270) más un doblez de 45 grados equivalen a 315 grados, lo cual está dentro del máximo de 360 grados permitido entre puntos de jalado según el NEC 358.26."},
  {"id":331,"q":"Un valor de resistencia del electrodo de tierra más bajo generalmente se considera mejor; ¿cuál condición tiende a reducir la resistencia medida de una varilla de tierra?","opts":["Suelo húmedo y un electrodo más largo o varios electrodos unidos","Suelo seco, arenoso y de alta resistividad","Una abrazadera de tierra floja y corroída","Una varilla más corta clavada solo unas pocas pulgadas de profundidad"],"re":"El suelo húmedo y el aumento del área superficial del electrodo, como una varilla más larga o varias varillas unidas, reducen la resistencia de contacto con la tierra y mejoran el sistema de puesta a tierra."},
  {"id":332,"q":"Cuando una herramienta eléctrica portátil cae al agua mientras aún está conectada, ¿cuál es la primera respuesta correcta?","opts":["Meter la mano al agua y sacar la herramienta tirando de su cable","Desenergizar el circuito en el disyuntor o desconectarla sin tocar el agua, y luego recuperar la herramienta","Seguir usando la herramienta una vez que se seque","Verter más agua sobre ella para enjuagarla"],"re":"La herramienta energizada puede volver peligrosa el agua; primero retire la energía de forma segura sin tocar el agua, luego recupere e inspeccione la herramienta antes de cualquier uso posterior."},
  {"id":333,"q":"¿Cuántas terminales que conducen corriente tiene un interruptor de 4 vías sin contar el tornillo de puesta a tierra?","opts":["Dos","Cuatro","Tres","Seis"],"re":"Un interruptor de 4 vías tiene cuatro terminales, dispuestas como dos pares de viajeros, y se instala entre dos interruptores de 3 vías."},
  {"id":334,"q":"Un tablero trifásico de 208 V alimenta una carga balanceada de 36 kVA; ¿cuál es la corriente de línea aproximada en cada fase?","opts":["173 A","100 A","115 A","60 A"],"re":"IL = kVA × 1000 ÷ (√3 × VL) = 36,000 ÷ (1.732 × 208) = 36,000 ÷ 360.3 = 100 A."},
  {"id":335,"q":"Donde un cable se instala en una muesca cortada en la cara de un montante de madera, ¿qué se requiere para proteger el cable de tornillos y clavos?","opts":["Nada, una muesca siempre es aceptable","Rellenar la muesca con sellador","Pintar el cable de un color brillante","Una placa de acero de al menos 1/16 de pulgada de espesor instalada a lo ancho de la cara de la muesca"],"re":"Según el NEC 300.4(A)(2), los cables instalados en muescas en madera deben protegerse con una placa de acero de al menos 1/16 in de espesor a lo ancho de la cara de la muesca."},
  {"id":336,"q":"¿Cuál secuencia describe mejor el orden correcto de puesta en servicio antes de poner en operación un nuevo alimentador?","opts":["Energizar primero, luego verificar el torque y la puesta a tierra","Verificar el torque de las terminaciones y la puesta a tierra/unión, realizar pruebas de resistencia de aislamiento, y luego energizar y medir voltajes","Medir la rotación de fases solo después de aplicar plena carga","Aplicar carga, luego verificar el conductor de puesta a tierra de equipos"],"re":"La puesta en servicio correcta se realiza primero desenergizado: verificar el torque y la puesta a tierra/unión, realizar pruebas de resistencia de aislamiento, y solo entonces energizar para medir los voltajes de operación."},
  {"id":337,"q":"¿Cuál es la principal ventaja de seguridad de una herramienta portátil con doble aislamiento cuando el conductor de puesta a tierra de equipos del suministro podría no ser confiable?","opts":["Puede usarse en cualquier voltaje sin límite","Sus dos capas de aislamiento independientes protegen al usuario incluso sin un conductor de puesta a tierra","Nunca requiere mantenimiento","Aumenta automáticamente su propia capacidad de corriente"],"re":"El doble aislamiento proporciona una segunda barrera independiente entre las partes vivas y el usuario, brindando protección contra descargas que no depende de un conductor de puesta a tierra externo."},
  {"id":338,"q":"La carga neta calculada de una vivienda es de 27,600 VA en una acometida monofásica de 240 V; ¿cuál es la capacidad mínima de acometida requerida de entre los tamaños estándar?","opts":["100 A","150 A","125 A","200 A"],"re":"27,600 ÷ 240 = 115 A; el siguiente tamaño estándar de acometida/sobrecorriente hacia arriba es 125 A."},
  {"id":339,"q":"¿Cuál es el espaciamiento máximo de soporte generalmente requerido para el tubo metálico eléctrico (EMT) a lo largo de un tramo recto expuesto?","opts":["6 pies","8 pies","12 pies","10 pies"],"re":"Según el NEC 358.30(A), el EMT debe soportarse a intervalos que no excedan 10 ft a lo largo del tramo."},
  {"id":340,"q":"Al probar un circuito ramal desenergizado con un ohmímetro, una lectura de resistencia infinita (OL) entre los dos extremos de un solo conductor indica cuál condición?","opts":["Un circuito abierto","Un cortocircuito","Una falla a tierra","Continuidad normal"],"re":"Una resistencia infinita a través de un conductor significa que la corriente no puede pasar, lo cual es la definición de un circuito abierto. Una buena continuidad leería cerca de cero ohmios."},
  {"id":341,"q":"En un interruptor de 3 vías, la terminal única que se conecta ya sea a la línea o a la carga se denomina comúnmente ¿qué?","opts":["Terminal común","Terminal de puesta a tierra","Terminal viajera","Terminal neutra"],"re":"La terminal común de un interruptor de 3 vías (usualmente un tornillo de color oscuro o negro) se conecta a la línea (fuente) en un interruptor y a la carga en el otro."},
  {"id":342,"q":"¿Cuál es la longitud mínima de una sola varilla de tierra que debe estar en contacto con el suelo para servir como electrodo de puesta a tierra?","opts":["6 ft","10 ft","8 ft","4 ft"],"re":"El NEC 250.52(A)(5) exige que un electrodo de varilla tenga al menos 8 ft de longitud en contacto con el suelo."},
  {"id":343,"q":"Dos estufas domésticas de 12 kW en el mismo alimentador tienen una demanda de 11 kW según la Columna C de la Tabla 220.55; esto demuestra que el factor de demanda para estufas:","opts":["Aumenta la carga calculada por encima de la placa","Reduce la carga combinada por debajo de la suma de los valores de placa","No tiene efecto sobre múltiples estufas","Aplica solo a cocinas comerciales"],"re":"Dos estufas de 12 kW suman 24 kW de placa, pero la Columna C de la Tabla 220.55 permite solo 11 kW, mostrando que el factor de demanda reduce la carga por debajo del total conectado."},
  {"id":344,"q":"Según el NEC 110.26(A)(1), ¿cuál es la profundidad mínima del espacio de trabajo requerida frente a equipo eléctrico que opera a 0-150 voltios a tierra, donde hay partes vivas expuestas en un lado y no hay partes vivas ni puestas a tierra en el otro lado?","opts":["2 pies","3 pies","3.5 pies","4 pies"],"re":"El NEC 110.26(A)(1) Condición 1 exige una profundidad mínima de espacio de trabajo de 3 pies para equipo a 0-150 V a tierra."},
  {"id":345,"q":"Un solo electrodo de varilla que no tiene una resistencia a tierra de 25 ohmios o menos debe complementarse con al menos cuántos electrodos adicionales?","opts":["Dos electrodos adicionales","Un electrodo adicional","Tres electrodos adicionales","No se requiere ningún electrodo adicional"],"re":"El NEC 250.53(A)(2) exige que un solo electrodo de varilla que exceda 25 ohmios se complemente con un electrodo adicional."},
  {"id":346,"q":"Un dispositivo GFCI Clase A estándar está diseñado para dispararse cuando la diferencia entre las corrientes de la fase y el neutro alcanza aproximadamente qué valor?","opts":["20 A","5 A","30 mA","5 mA"],"re":"Un GFCI Clase A se dispara con una corriente de falla a tierra de aproximadamente 4 a 6 mA, nominalmente 5 mA, para proteger a las personas de una descarga."},
  {"id":347,"q":"¿Cuál es la corriente aproximada a plena carga de una carga trifásica de 480 V que entrega 100 kW con un factor de potencia de 1.0?","opts":["100 A","208 A","120 A","150 A"],"re":"IL = P ÷ (√3 × VL × PF) = 100,000 ÷ (1.732 × 480 × 1.0) = 100,000 ÷ 831.4 = 120 A."},
  {"id":348,"q":"Según el NEC 110.26(A)(3), ¿cuál es la altura libre mínima requerida (altura del techo) del espacio de trabajo alrededor del equipo de acometida, tableros o centros de control de motores con capacidad de 1200 amperios o menos?","opts":["7 pies 6 pulgadas","6 pies","7 pies","6 pies 6 pulgadas"],"re":"El NEC 110.26(A)(3) exige una altura libre mínima de 6.5 pies (6 ft 6 in) para el espacio de trabajo alrededor del equipo eléctrico."},
  {"id":349,"q":"Cuando se usan dos varillas de tierra para formar el electrodo de puesta a tierra, ¿cuál es el espaciamiento mínimo requerido entre ellas?","opts":["3 ft de separación","6 ft de separación","8 ft de separación","10 ft de separación"],"re":"El NEC 250.53(A)(3) exige que los electrodos de varilla que forman parte de un arreglo estén espaciados al menos 6 ft entre sí."},
  {"id":350,"q":"Usando la Tabla 310.16 del NEC en la columna de 60°C, ¿cuál es la ampacidad permitida de un conductor de cobre 12 AWG?","opts":["15 A","20 A","25 A","30 A"],"re":"Según la Tabla 310.16 del NEC, el cobre 12 AWG en la columna de terminación de 60°C tiene una ampacidad permitida de 20 A."},
  {"id":351,"q":"Un interruptor que controla el alumbrado en una vivienda generalmente no debe interrumpir cuál conductor?","opts":["El conductor no puesto a tierra (fase)","El conductor viajero","El conductor puesto a tierra (neutro)","El conductor de retorno del interruptor"],"re":"El NEC 404.2(B) exige que los interruptores controlen el conductor no puesto a tierra; el conductor puesto a tierra (neutro) generalmente no debe interrumpirse (con excepciones limitadas)."},
  {"id":352,"q":"Un electricista nota que las luces incandescentes se atenúan notablemente cada vez que un motor grande arranca en el mismo circuito; este síntoma apunta de forma más directa a cuál problema?","opts":["Caída de voltaje excesiva por un conductor subdimensionado o sobrecargado","Una falla a tierra en el circuito de alumbrado","Un dispositivo GFCI defectuoso","Polaridad invertida en el receptáculo"],"re":"La atenuación durante una alta demanda de corriente indica caída de voltaje, comúnmente causada por conductores subdimensionados, tramos largos o conexiones flojas que no pueden suministrar la corriente de arranque."},
  {"id":353,"q":"Según el NEC 110.26(A)(2), el ancho mínimo del espacio de trabajo frente al equipo eléctrico debe ser el ancho del equipo o qué dimensión mínima, lo que sea mayor?","opts":["24 pulgadas","30 pulgadas","42 pulgadas","36 pulgadas"],"re":"El NEC 110.26(A)(2) exige que el ancho del espacio de trabajo sea un mínimo de 30 pulgadas o el ancho del equipo, lo que sea mayor."},
  {"id":354,"q":"Un electrodo embebido en concreto (Ufer) debe consistir en al menos 20 ft de conductor de cobre desnudo no menor que cuál tamaño?","opts":["4 AWG","8 AWG","6 AWG","2 AWG"],"re":"El NEC 250.52(A)(3) permite un electrodo embebido en concreto usando al menos 20 ft de conductor de cobre desnudo no menor que 4 AWG."},
  {"id":355,"q":"¿Cuál es la ampacidad permitida de un conductor de cobre 10 AWG en la columna de 60°C de la Tabla 310.16 del NEC?","opts":["30 A","25 A","20 A","40 A"],"re":"La Tabla 310.16 del NEC indica el cobre 10 AWG a 30 A en la columna de 60°C."},
  {"id":356,"q":"Un dispositivo AFCI está diseñado específicamente para detectar y responder a cuál condición peligrosa?","opts":["Sobretensión por sobretensiones de la red eléctrica","Pequeñas corrientes de falla a tierra hacia la tierra","Fallas de arco en el cableado y las conexiones","Desbalance de fases entre las líneas"],"re":"Un AFCI detecta la firma de corriente de alta frecuencia de una falla de arco, como la proveniente de cableado dañado o flojo, e interrumpe el circuito para prevenir incendios."},
  {"id":357,"q":"Cuando un electrodo embebido en concreto utiliza barras de refuerzo de acero recubiertas eléctricamente conductoras, las barras deben tener al menos cuál diámetro?","opts":["1/4 in","1/2 in","3/8 in","5/8 in"],"re":"El NEC 250.52(A)(3) exige que las barras de refuerzo usadas como electrodo embebido en concreto tengan al menos 1/2 in de diámetro."},
  {"id":358,"q":"Según el NEC 110.26(A)(2), el espacio de trabajo de 30 pulgadas de ancho frente a un tablero puede medirse de cuál manera?","opts":["Solo centrado en el tablero","Solo desde el borde izquierdo del equipo","Medido en diagonal a través de la cara del equipo","Ya sea centrado en el equipo o desplazado, siempre que se logre un ancho de 30 pulgadas"],"re":"El NEC 110.26(A)(2) permite que el ancho de 30 pulgadas se mida ya sea centrado en el equipo o desplazado, siempre que se mantenga el ancho completo de 30 pulgadas."},
  {"id":359,"q":"Según el NEC 240.6(A), ¿cuál de los siguientes NO es una capacidad estándar en amperios para un fusible o disyuntor de tiempo inverso?","opts":["35 A","45 A","70 A","55 A"],"re":"Según el NEC 240.6(A), 55 A no es una capacidad estándar; las capacidades estándar saltan de 50 A a 60 A."},
  {"id":360,"q":"Un interruptor de acción rápida de uso general instalado en una caja metálica debe generalmente contar con qué conexión por seguridad?","opts":["Una conexión al conductor puesto a tierra (neutro)","Una conexión de puesta a tierra de equipos al yugo del interruptor","Un dispositivo de protección contra sobretensiones","Un conductor de tierra aislada"],"re":"El NEC 404.9(B) exige que los interruptores de acción rápida, incluyendo los de placa frontal metálica, estén efectivamente puestos a tierra conectando el conductor de puesta a tierra de equipos al yugo o soporte metálico del interruptor."},
  {"id":361,"q":"Un disyuntor se dispara de inmediato y violentamente en el instante en que se restablece, sin ninguna carga conectada; este comportamiento sugiere con mayor fuerza cuál falla?","opts":["Una sobrecarga gradual","Disparo térmico normal por calor","Una conexión floja de alta resistencia","Un cortocircuito directo (fase a neutro o fase a tierra)"],"re":"Un disparo instantáneo sin carga apunta a un cortocircuito, donde una corriente de falla muy alta activa el disparo magnético instantáneo del disyuntor. Una sobrecarga se dispara lentamente bajo carga."},
  {"id":362,"q":"Una tubería metálica de agua subterránea usada como electrodo de puesta a tierra debe estar en contacto directo con la tierra durante al menos cuántos pies?","opts":["5 ft","20 ft","8 ft","10 ft"],"re":"El NEC 250.52(A)(1) exige que una tubería metálica de agua subterránea esté en contacto directo con la tierra durante 10 ft o más para calificar como electrodo."},
  {"id":363,"q":"Según el NEC 110.26(E)(1), el espacio dedicado de equipo sobre un tablero o cuadro de distribución debe extenderse desde la parte superior del equipo hasta una altura de cuántos pies sobre el equipo, o hasta el techo estructural, lo que sea más bajo?","opts":["3 pies","6.5 pies","6 pies","10 pies"],"re":"El NEC 110.26(E)(1)(a) exige que el espacio eléctrico dedicado se extienda 6 pies sobre el equipo o hasta el techo estructural, lo que sea más bajo."},
  {"id":364,"q":"Una carga continua consume 16 A; ¿cuál es la capacidad mínima del OCPD del circuito ramal requerida antes de aplicar cualquier ajuste por temperatura o agrupamiento?","opts":["20 A","18 A","16 A","25 A"],"re":"Según el NEC 210.20(A), el OCPD debe ser al menos el 125% de la carga continua: 16 A × 1.25 = 20 A."},
  {"id":365,"q":"Una tubería metálica de agua subterránea usada como electrodo de puesta a tierra siempre debe complementarse con cuál de los siguientes?","opts":["Un electrodo de puesta a tierra adicional","Un descargador de sobretensiones","Un segundo medidor de agua","Un conductor de acometida más grande"],"re":"El NEC 250.53(D)(2) exige que el electrodo de tubería metálica de agua subterránea se complemente con un electrodo adicional de un tipo especificado en 250.52."},
  {"id":366,"q":"En un circuito ramal multiconductor, ¿cuál es el peligro principal si el neutro compartido se afloja o se abre mientras el circuito está energizado?","opts":["Los disyuntores se dispararán de inmediato por sobrecarga","El GFCI fallará la prueba","Las cargas conectadas pueden quedar expuestas a voltajes anormalmente altos o bajos","El conductor de puesta a tierra conduce toda la corriente de carga"],"re":"Con un neutro compartido abierto, las cargas de línea a neutro quedan conectadas en serie a través de las dos líneas, por lo que el voltaje se divide de forma desigual y puede dañar el equipo."},
  {"id":367,"q":"Dentro del espacio dedicado de equipo sobre un tablero requerido por el NEC 110.26(E), ¿cuál de los siguientes está permitido específicamente por el Código?","opts":["Tubería ajena, como una línea de agua","Un ducto de HVAC que atraviesa el espacio","Una bandeja de drenaje de equipo ubicado arriba","Tubería de protección contra incendios (rociadores) para el área"],"re":"El NEC 110.26(E)(1)(b) prohíbe los sistemas ajenos (tuberías, ductos, etc.) en el espacio dedicado, pero permite específicamente la tubería de protección contra incendios (rociadores) para el área."},
  {"id":368,"q":"Según el Capítulo 9, Tabla 1 del NEC, ¿cuál es el porcentaje máximo del área de sección transversal del conduit que puede llenarse cuando se instalan más de dos conductores en una canalización?","opts":["31%","60%","53%","40%"],"re":"El Capítulo 9, Tabla 1 del NEC limita el llenado al 40% para más de dos conductores en un conduit o tubo."},
  {"id":369,"q":"Cuando se instala un medidor de agua en una tubería metálica de agua subterránea usada como electrodo, ¿qué debe proporcionarse para mantener la continuidad eléctrica?","opts":["Una unión dieléctrica","Un espaciador de plástico","Solo una segunda varilla de tierra","Un puente de unión alrededor del medidor"],"re":"El NEC 250.53(D)(1) exige un puente de unión alrededor de componentes aislantes como un medidor de agua para asegurar la continuidad del electrodo."},
  {"id":370,"q":"Un receptáculo dúplex estándar de 15 amperios y 125 voltios en un circuito ramal de 20 amperios que sirve a múltiples salidas está permitido por cuál razón?","opts":["Un receptáculo de 15 amperios nunca se permite en un circuito de 20 amperios","La Tabla 210.21(B)(3) del NEC permite receptáculos de 15 amperios en un circuito de 20 amperios con dos o más salidas","Solo se permiten receptáculos sencillos","Solo si el receptáculo es GFCI"],"re":"La Tabla 210.21(B)(3) del NEC permite que se usen receptáculos con capacidad de 15 amperios en circuitos ramales de 20 amperios donde se alimentan dos o más receptáculos."},
  {"id":371,"q":"¿Cuál es la forma correcta de verificar que un receptáculo GFCI esté funcionando correctamente?","opts":["Presionar el botón TEST y confirmar que el dispositivo se dispara y retira la energía","Leer el voltaje de línea con el dispositivo energizado","Medir la resistencia entre las terminales de línea","Aplicar una carga de 30 mA y confirmar que se mantiene"],"re":"Presionar el botón TEST crea un pequeño desbalance simulado; un GFCI en buen estado debe dispararse y desenergizar la salida, tras lo cual RESET restablece la energía."},
  {"id":372,"q":"¿Cuál es el porcentaje máximo de llenado de conduit permitido para un solo conductor según el Capítulo 9, Tabla 1 del NEC?","opts":["31%","53%","40%","60%"],"re":"El Capítulo 9, Tabla 1 del NEC permite un llenado del 53% para un conductor en una canalización."},
  {"id":373,"q":"Según el NEC 110.27(A), las partes vivas de equipo eléctrico que operan a 50 voltios o más deben protegerse contra el contacto accidental mediante cuál de los siguientes métodos?","opts":["Pintar las partes vivas con pintura aislante","Ubicación en un cuarto accesible solo para personas calificadas","Colocar un letrero de advertencia a 10 pies de distancia","Aplicar grasa dieléctrica a los conductores"],"re":"El NEC 110.27(A) permite proteger las partes vivas mediante su ubicación en un cuarto, bóveda o gabinete accesible solo para personas calificadas, entre otros métodos listados."},
  {"id":374,"q":"Donde el extremo superior de una varilla de tierra está expuesto y sujeto a daño físico, ¿cómo debe instalarse para evitar requisitos de protección adicionales?","opts":["Al menos 6 in sobre el nivel del suelo","Al ras o por debajo del nivel del suelo","Pintada con pintura roja","Envuelta en cinta"],"re":"El NEC 250.53(G) exige que la varilla se instale al ras o por debajo del suelo, a menos que el extremo sobre el suelo y la conexión estén protegidos."},
  {"id":375,"q":"Un motor funciona con dificultad y se detiene bajo carga, y las mediciones muestran un voltaje en terminales muy por debajo del valor de placa durante la operación; la causa más probable es:","opts":["Un disyuntor AFCI defectuoso","Caída de voltaje excesiva en los conductores de suministro","Un dispositivo de sobrecorriente sobredimensionado","Línea y neutro invertidos"],"re":"Un voltaje bajo en terminales bajo carga reduce el par del motor, causando una operación lenta y detenciones; este es un síntoma clásico de caída de voltaje por conductores subdimensionados o sobrecargados."},
  {"id":376,"q":"Todos los electrodos de puesta a tierra presentes en un edificio, como una varilla de tierra y un electrodo embebido en concreto, deben:","opts":["Conectarse solo a la barra de neutro","Mantenerse eléctricamente aislados entre sí","Unirse entre sí para formar un sistema de electrodos de puesta a tierra","Usarse uno a la vez en días alternos"],"re":"El NEC 250.50 exige que todos los electrodos presentes se unan entre sí para formar el sistema de electrodos de puesta a tierra."},
  {"id":377,"q":"Según el Capítulo 9, Tabla 1 del NEC, ¿cuál es el porcentaje máximo de llenado de conduit cuando se instalan exactamente dos conductores en una canalización?","opts":["26%","31%","40%","53%"],"re":"El Capítulo 9, Tabla 1 del NEC limita dos conductores en una canalización a un llenado del 31%."},
  {"id":378,"q":"Según el NEC 110.27(A), ¿a qué nivel de voltaje las partes vivas de equipo eléctrico generalmente requieren protección contra el contacto accidental?","opts":["50 voltios o más","30 voltios o más","24 voltios o más","120 voltios o más"],"re":"El NEC 110.27(A) exige que las partes vivas que operan a 50 voltios o más se protejan contra el contacto accidental."},
  {"id":379,"q":"Un solo receptáculo instalado en un circuito ramal individual debe tener una capacidad en amperios que sea al menos de qué valor en relación con el circuito ramal?","opts":["La mitad de la capacidad del circuito ramal","Un tercio de la capacidad del circuito ramal","Exactamente 15 amperios sin importar el circuito","Igual o mayor que la capacidad del circuito ramal"],"re":"El NEC 210.21(B)(1) exige que un solo receptáculo en un circuito ramal individual tenga una capacidad en amperios no menor que la del circuito ramal."},
  {"id":380,"q":"Una lectura de ohmímetro de casi cero ohmios entre un conductor no puesto a tierra (fase) y el conductor de puesta a tierra de equipos en un circuito desenergizado indica ¿qué?","opts":["Una falla a tierra o corto a tierra","Un neutro abierto","Resistencia de aislamiento normal","Un conductor sobrecargado"],"re":"Una resistencia de casi cero entre la fase y el conductor de puesta a tierra significa que están conectados de forma no intencional, lo cual es una falla a tierra. Un aislamiento sano lee una resistencia muy alta."},
  {"id":381,"q":"¿Cuál es el tamaño máximo de conductor de electrodo de puesta a tierra de cobre requerido cuando el único electrodo es una sola varilla de tierra?","opts":["4 AWG","8 AWG","6 AWG","2 AWG"],"re":"El NEC 250.66(A) establece que el GEC a un electrodo de varilla no requiere ser mayor que 6 AWG de cobre."},
  {"id":382,"q":"Para los cálculos de llenado de caja según el NEC 314.16(B), ¿qué asignación de volumen se asigna a cada conductor 14 AWG?","opts":["2.00 in³","1.50 in³","2.25 in³","2.50 in³"],"re":"La Tabla 314.16(B) del NEC asigna 2.00 pulgadas cúbicas por conductor 14 AWG."},
  {"id":383,"q":"Un electricista debe trabajar en la cara de un tablero de 480 voltios con partes vivas expuestas en un lado y una pared de bloques de concreto puesta a tierra directamente detrás; ¿cuál condición y profundidad de espacio de trabajo del NEC 110.26(A)(1) aplica?","opts":["Condición 1, 3 pies","Condición 3, 4 pies","Condición 2, 3.5 pies","Condición 2, 3 pies"],"re":"Para 151-600 V a tierra con partes vivas expuestas en un lado y partes puestas a tierra (concreto) en el otro, esta es la Condición 2, que requiere 3.5 pies según la Tabla 110.26(A)(1) del NEC."},
  {"id":384,"q":"¿Cuál es el tamaño máximo de conductor de electrodo de puesta a tierra de cobre requerido cuando la conexión es a un electrodo embebido en concreto?","opts":["4 AWG","6 AWG","8 AWG","3 AWG"],"re":"El NEC 250.66(B) establece que el GEC a un electrodo embebido en concreto no requiere ser mayor que 4 AWG de cobre."},
  {"id":385,"q":"Un disyuntor de 15 amperios se dispara después de aproximadamente 10 a 15 minutos de operar varios artefactos, pero se restablece y se mantiene bien cuando se usan menos cargas; este patrón indica:","opts":["Un cortocircuito atornillado","Una falla a tierra","Una sobrecarga sostenida","Un sensor AFCI defectuoso"],"re":"Un disparo retardado que se correlaciona con el número de cargas es la firma de una sobrecarga térmica, donde la corriente excede modestamente la capacidad y calienta el elemento bimetálico con el tiempo."},
  {"id":386,"q":"¿Qué asignación de volumen por conductor individual asigna la Tabla 314.16(B) del NEC a un conductor 12 AWG?","opts":["2.25 in³","2.00 in³","2.50 in³","3.00 in³"],"re":"La Tabla 314.16(B) del NEC asigna 2.25 pulgadas cúbicas por cada conductor 12 AWG."},
  {"id":387,"q":"¿Cuál grado de receptáculo está construido bajo un estándar más alto de impacto, fuerza de retención y durabilidad para aplicaciones exigentes?","opts":["Grado residencial","Grado estándar","Grado decorativo","Grado hospitalario"],"re":"Los receptáculos de grado hospitalario están construidos bajo estándares más altos (identificados por un punto verde) para una mayor durabilidad, retención de contacto y confiabilidad que los grados residencial o estándar."},
  {"id":388,"q":"Según el NEC 110.26(C), se requiere al menos una entrada que dé acceso y salida del espacio de trabajo alrededor del equipo eléctrico principalmente para proteger contra cuál peligro?","opts":["Sobrecalentamiento del equipo","Acceso no autorizado por parte del público","Que los trabajadores queden atrapados cerca de equipo energizado durante una emergencia","Intrusión de humedad en el tablero"],"re":"Los requisitos de entrada/salida del NEC 110.26(C) aseguran que un trabajador pueda escapar rápidamente del espacio de trabajo en caso de un arco eléctrico u otra emergencia."},
  {"id":389,"q":"Un conductor de electrodo de puesta a tierra que es la única conexión a una sola varilla de tierra y que se tiende al aire libre debe protegerse si es menor que cuál tamaño?","opts":["8 AWG","10 AWG","4 AWG","6 AWG"],"re":"El NEC 250.64(B) permite que un GEC de cobre de 6 AWG o mayor se tienda a lo largo de la superficie sin protección metálica donde no esté sujeto a daño físico severo."},
  {"id":390,"q":"Durante un estudio de imágenes térmicas de un tablero energizado, una terminal de disyuntor aparece significativamente más caliente que las terminales adyacentes idénticas que conducen una corriente similar; este punto caliente indica con mayor probabilidad:","opts":["Una conexión floja o de alta resistencia","Un conductor sobredimensionado","Un GFCI disparado","Una conexión perfectamente torqueada"],"re":"Un punto caliente localizado en una terminación usualmente significa una conexión floja o corroída que crea resistencia adicional, la cual genera calor bajo carga y puede llevar a una falla o incendio."},
  {"id":391,"q":"Una caja de dispositivo contiene seis conductores 12 AWG que conducen corriente sin ningún otro elemento de llenado; ¿qué volumen total de caja requiere el NEC 314.16(B)?","opts":["12.0 in³","15.0 in³","13.5 in³","18.0 in³"],"re":"Seis conductores 12 AWG a 2.25 in³ cada uno equivalen a 13.5 pulgadas cúbicas según la Tabla 314.16(B) del NEC."},
  {"id":392,"q":"Para una acometida con conductores de acometida no puestos a tierra de cobre 2 AWG, ¿cuál es el tamaño mínimo de conductor de electrodo de puesta a tierra de cobre según la Tabla 250.66?","opts":["10 AWG","4 AWG","6 AWG","8 AWG"],"re":"La Tabla 250.66 requiere un GEC de cobre 8 AWG para conductores de acometida de cobre 2 AWG."},
  {"id":393,"q":"Según el NEC 110.26(C)(2), para equipo con capacidad de 1200 amperios o más y de más de 6 pies de ancho, ¿cuántas entradas al espacio de trabajo (una en cada extremo) se requieren generalmente a menos que se cumplan excepciones específicas?","opts":["No se requiere entrada","Solo una entrada","Tres entradas","Dos entradas"],"re":"El NEC 110.26(C)(2) exige dos puntos de entrada/salida, uno en cada extremo, para equipo grande con capacidad de 1200 A o más y de más de 6 pies de ancho."},
  {"id":394,"q":"Según el NEC 314.16(B), ¿cuántas asignaciones de volumen cuentan colectivamente todos los conductores de puesta a tierra de equipos que entran a una caja?","opts":["Una por cada conductor de puesta a tierra","Cero","Una, basada en el conductor de puesta a tierra más grande","Dos en total"],"re":"El NEC 314.16(B)(5) cuenta todos los conductores de puesta a tierra de equipos como una sola asignación de volumen basada en el conductor más grande de ese tipo."},
  {"id":395,"q":"Al comenzar a diagnosticar un receptáculo muerto, ¿cuál paso debería realizarse lógicamente PRIMERO?","opts":["Reemplazar el receptáculo","Reemplazar el tablero de acometida","Tender cable nuevo hasta la salida","Verificar el problema y revisar si hay un disyuntor o GFCI disparado"],"re":"Una buena secuencia de diagnóstico comienza confirmando el síntoma y revisando primero las causas más simples y probables, como un disyuntor disparado o un GFCI aguas arriba, antes de un trabajo invasivo."},
  {"id":396,"q":"Para una acometida con conductores de acometida no puestos a tierra de cobre 1/0 AWG, ¿cuál es el tamaño mínimo de conductor de electrodo de puesta a tierra de cobre según la Tabla 250.66?","opts":["8 AWG","6 AWG","4 AWG","2 AWG"],"re":"La Tabla 250.66 requiere un GEC de cobre 6 AWG para conductores de acometida de cobre mayores que 2 AWG hasta 1/0 AWG."},
  {"id":397,"q":"Para los clósets de ropa tipo almacenamiento, una luminaria incandescente o LED montada en superficie con la lámpara completamente cerrada debe mantener una distancia mínima de cuánto desde el espacio de almacenamiento más cercano?","opts":["6 pulgadas","18 pulgadas","12 pulgadas","24 pulgadas"],"re":"El NEC 410.16(C) exige una distancia mínima de 12 in entre una luminaria incandescente/LED completamente cerrada montada en superficie y el punto más cercano de un espacio de almacenamiento del clóset."},
  {"id":398,"q":"Según el NEC 110.26(D), ¿qué debe proporcionarse en el espacio de trabajo alrededor del equipo de acometida, cuadros de distribución, tableros y centros de control de motores instalados en interiores?","opts":["Un extintor de incendios","Un tapete de puesta a tierra","Iluminación","Un teléfono"],"re":"El NEC 110.26(D) exige que se proporcione iluminación para todos los espacios de trabajo alrededor del equipo de acometida, cuadros de distribución, tableros y centros de control de motores ubicados en interiores."},
  {"id":399,"q":"Al dimensionar los conductores de un circuito ramal, el NEC recomienda que la caída de voltaje generalmente no exceda qué porcentaje solo para el circuito ramal?","opts":["1%","3%","5%","8%"],"re":"La Nota Informativa del NEC 210.19 recomienda una caída de voltaje máxima del 3% en un circuito ramal, con un 5% total para el alimentador más el circuito ramal."},
  {"id":400,"q":"En un circuito de 120 voltios, un voltímetro lee 120 V de fase a tierra pero 0 V de fase a neutro; esta lectura indica con mayor probabilidad:","opts":["Un corto entre fase y neutro","Una falla a tierra sólida","Un circuito normal que funciona correctamente","Un neutro abierto"],"re":"Voltaje pleno a tierra pero sin voltaje a neutro significa que la trayectoria del neutro está interrumpida; el medidor completa el circuito a través de tierra, confirmando un neutro abierto."},
  {"id":401,"q":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito derivado de 15 amperios según la Tabla 250.122?","opts":["12 AWG","10 AWG","14 AWG","16 AWG"],"re":"La Tabla 250.122 requiere un EGC de cobre de 14 AWG para un dispositivo de sobrecorriente con clasificación de 15 amperios."},
  {"id":402,"q":"El NEC recomienda que la caída de tensión combinada del alimentador y el circuito derivado hasta la salida más lejana no exceda qué porcentaje total?","opts":["3%","5%","8%","10%"],"re":"Las Notas Informativas del NEC recomiendan que la caída de tensión total del alimentador más el circuito derivado no exceda el 5%."},
  {"id":403,"q":"Según el NEC 110.26(B), el espacio de trabajo requerido frente al equipo eléctrico debe mantenerse despejado y NO puede usarse para cuál propósito?","opts":["Acceso temporal durante la instalación","Paso de personas calificadas","Almacenamiento de materiales y equipos","Montaje del artefacto de iluminación requerido"],"re":"El NEC 110.26(B) requiere que el espacio de trabajo esté despejado y prohíbe su uso para almacenamiento; cuando las partes vivas normalmente encerradas quedan expuestas, el espacio debe estar debidamente resguardado."},
  {"id":404,"q":"En un circuito derivado multiconductor de 120/240 voltios correctamente balanceado, la corriente que transporta el neutro compartido es igual a:","opts":["La suma de las dos corrientes de línea","El doble de la corriente de línea mayor","La diferencia entre las dos corrientes de línea","Siempre cero, independientemente de la carga"],"re":"Cuando las dos patas no aterrizadas están en fases opuestas, el neutro transporta solo la corriente desbalanceada (la diferencia), por lo que el neutro se comparte de forma segura cuando se conecta correctamente."},
  {"id":405,"q":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito derivado de 20 amperios según la Tabla 250.122?","opts":["14 AWG","12 AWG","10 AWG","8 AWG"],"re":"La Tabla 250.122 requiere un EGC de cobre de 12 AWG para un dispositivo de sobrecorriente con clasificación de 20 amperios."},
  {"id":406,"q":"Una luminaria fluorescente montada en superficie en la pared o el techo de un clóset de ropa debe mantener un espacio libre mínimo de cuánto desde el espacio de almacenamiento más cercano?","opts":["6 pulgadas","3 pulgadas","12 pulgadas","18 pulgadas"],"re":"El NEC 410.16(C) permite luminarias fluorescentes montadas en superficie en clósets de ropa con un espacio libre mínimo de 6 in desde el punto más cercano de un espacio de almacenamiento."},
  {"id":407,"q":"Las terminaciones de conductores en equipos con clasificación de 100 A o menos generalmente se basan en cuál columna de temperatura, a menos que el equipo esté listado y marcado de otra manera?","opts":["75°C","60°C","90°C","105°C"],"re":"Según el NEC 110.14(C)(1)(a), las terminaciones para circuitos de 100 A o menos se basan por defecto en la columna de 60°C, a menos que estén marcadas para una temperatura mayor."},
  {"id":408,"q":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito de 60 amperios según la Tabla 250.122?","opts":["8 AWG","10 AWG","12 AWG","6 AWG"],"re":"La Tabla 250.122 requiere un EGC de cobre de 10 AWG para un dispositivo de sobrecorriente con clasificación de 60 amperios."},
  {"id":409,"q":"Para una acometida aérea de conductores de 120/240 voltios que cruza sobre una entrada de vehículos residencial no sujeta a tráfico de camiones, ¿cuál es el espacio libre vertical mínimo sobre la entrada de vehículos requerido por el NEC?","opts":["10 pies","15 pies","12 pies","18 pies"],"re":"Según el NEC 230.24(B), los conductores de acometida que no excedan 300 V a tierra requieren 12 pies de espacio libre sobre propiedad residencial y entradas de vehículos no sujetas a tráfico de camiones."},
  {"id":410,"q":"Si al presionar el botón TEST de un tomacorriente GFCI este NO se dispara, la conclusión correcta es:","opts":["El GFCI funciona perfectamente","La carga aguas abajo es demasiado pequeña","La tensión del circuito es demasiado alta","El GFCI está defectuoso y debe reemplazarse"],"re":"Un GFCI que no se dispara con su botón TEST ha perdido su función protectora y debe reemplazarse, ya que no puede interrumpir una falla a tierra real."},
  {"id":411,"q":"Incluso cuando se instalan conductores con clasificación de 90°C, ¿cuál es el uso principal permitido de la columna de ampacidad de 90°C en la Tabla 310.16 del NEC?","opts":["Para la ampacidad de terminación final","Solo para cálculos de carga","Como ampacidad inicial para aplicar factores de ajuste y corrección","No puede usarse en absoluto"],"re":"Según el NEC 110.14(C), la columna de 90°C se usa como punto de partida para la reducción (derating), pero la ampacidad final no debe exceder la clasificación de temperatura de la terminación."},
  {"id":412,"q":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito de 100 amperios según la Tabla 250.122?","opts":["10 AWG","8 AWG","6 AWG","4 AWG"],"re":"La Tabla 250.122 requiere un EGC de cobre de 8 AWG para un dispositivo de sobrecorriente con clasificación de 100 amperios."},
  {"id":413,"q":"Según el NEC 230.24(B), ¿cuál es el espacio libre vertical mínimo para los conductores de acometida aérea sobre una calle pública, callejón o camino sujeto a tráfico de camiones?","opts":["12 pies","15 pies","22 pies","18 pies"],"re":"El NEC 230.24(B)(4) requiere 18 pies de espacio libre sobre calles públicas, callejones, caminos y otras áreas sujetas a tráfico de camiones."},
  {"id":414,"q":"¿Cuál práctica de mantenimiento ayuda mejor a prevenir el calentamiento por conexiones flojas en las terminaciones de tableros y dispositivos con el tiempo?","opts":["Reapretar periódicamente las conexiones a las especificaciones del fabricante","Dejar las terminales ligeramente flojas para la expansión térmica","Pintar todas las terminales para prevenir la corrosión","Aumentar el tamaño del interruptor para reducir el calor"],"re":"Las conexiones pueden aflojarse por los ciclos térmicos y la vibración; la inspección periódica y el reapriete al valor especificado mantienen baja la resistencia y previenen la acumulación de calor."},
  {"id":415,"q":"¿Qué tipo de luminaria NO está permitido instalar en un clóset de ropa?","opts":["Una luminaria incandescente con lámpara abierta o expuesta","Artefacto fluorescente empotrado","Artefacto LED montado en superficie","Un artefacto incandescente montado en superficie completamente cerrado"],"re":"El NEC 410.16(B) prohíbe las luminarias incandescentes con lámparas abiertas o parcialmente cerradas y las luminarias colgantes en clósets de ropa debido al riesgo de incendio."},
  {"id":416,"q":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito derivado de 40 amperios según la Tabla 250.122?","opts":["12 AWG","14 AWG","8 AWG","10 AWG"],"re":"La Tabla 250.122 requiere un EGC de cobre de 10 AWG para un dispositivo de sobrecorriente con clasificación de 40 amperios."},
  {"id":417,"q":"¿Cuál es la ampacidad permitida de un conductor de cobre de 14 AWG en la columna de 60°C de la Tabla 310.16 del NEC?","opts":["10 A","15 A","20 A","25 A"],"re":"La Tabla 310.16 del NEC indica 15 A para el cobre de 14 AWG en la columna de 60°C."},
  {"id":418,"q":"Según el NEC 230.24(A), los conductores de acometida aérea deben mantener un espacio libre mínimo de cuántos pies sobre la superficie del techo en el caso general antes de que apliquen las excepciones de espacio libre reducido?","opts":["3 pies","8 pies","6 pies","10 pies"],"re":"El NEC 230.24(A) generalmente requiere que los conductores tengan un espacio libre no menor a 8 pies sobre la superficie del techo, con varias excepciones de espacio libre reducido."},
  {"id":419,"q":"Dos circuitos de tomacorrientes de 120 voltios alimentados desde la MISMA fase se conectan para compartir un neutro; la consecuencia más grave es:","opts":["El neutro transporta solo la diferencia de las dos corrientes","El conductor de puesta a tierra se energiza","Los circuitos no se energizarán en absoluto","El neutro compartido puede sobrecargarse porque las corrientes se suman en lugar de restarse"],"re":"Cuando ambos conductores vivos están en la misma fase, las corrientes del neutro se suman en lugar de cancelarse, por lo que el único neutro puede verse forzado a transportar más que su corriente nominal y sobrecalentarse."},
  {"id":420,"q":"Cuando un conductor de puesta a tierra de equipos se aumenta de tamaño porque los conductores no aterrizados se aumentaron, ¿de qué manera debe aumentarse el EGC?","opts":["No necesita aumentarse","Exactamente un tamaño AWG","Duplicarse en tamaño","Proporcionalmente al aumento del área en mils circulares de los conductores no aterrizados"],"re":"El NEC 250.122(B) requiere que el EGC se aumente proporcionalmente al aumento del área en mils circulares de los conductores no aterrizados."},
  {"id":421,"q":"Se alimenta una carga no continua de 24 A; al seleccionar el siguiente OCPD estándar según el NEC 240.6(A), ¿qué tamaño de dispositivo de sobrecorriente es apropiado?","opts":["20 A","35 A","30 A","25 A"],"re":"Según el NEC 240.6(A), 25 A es una clasificación estándar y acomoda la carga no continua de 24 A."},
  {"id":422,"q":"Un interruptor AFCI sigue disparándose en un circuito, pero un probador de enchufe y una inspección visual no muestran falla a tierra ni cortocircuito evidente; ¿cuál es un siguiente paso razonable de diagnóstico?","opts":["Reemplazar inmediatamente todo el tablero","Inspeccionar en busca de cable dañado, terminaciones flojas o conexiones propensas a arqueo en ese circuito","Aumentar la clasificación de amperaje del interruptor","Desconectar el conductor de puesta a tierra de equipos"],"re":"Dado que los AFCI responden al arqueo, los disparos repetidos justifican inspeccionar en busca de aislamiento dañado, grapas que atraviesen el cable o conexiones flojas que produzcan firmas de arco."},
  {"id":423,"q":"Según el NEC 230.24(B)(1), los conductores de acometida limitados a 150 voltios a tierra requieren un espacio libre vertical mínimo de cuántos pies sobre el nivel terminado, aceras o plataformas accesibles solo a peatones?","opts":["10 pies","8 pies","12 pies","15 pies"],"re":"El NEC 230.24(B)(1) requiere 10 pies de espacio libre sobre el nivel terminado, aceras o superficies accesibles desde las cuales podrían alcanzarse, para conductores limitados a 150 V a tierra."},
  {"id":424,"q":"Cuando un solo conductor de puesta a tierra de equipos se instala con múltiples circuitos en la misma canalización, debe dimensionarse según cuál dispositivo de sobrecorriente?","opts":["El dispositivo de sobrecorriente más grande que protege los conductores en la canalización","El más pequeño del grupo","El promedio de todos los dispositivos","El primer circuito instalado"],"re":"El NEC 250.122(C) requiere que un solo EGC para múltiples circuitos se dimensione para el dispositivo de sobrecorriente más grande en la canalización."},
  {"id":425,"q":"Una luminaria utilizada como canalización para conductores de circuito está permitida solo cuando es qué?","opts":["Pintada para combinar con el techo","Instalada por debajo de 8 ft","Listada y marcada para uso como canalización","Clasificada para ubicaciones húmedas"],"re":"El NEC 410.64 permite que las luminarias se usen como canalización para conductores de circuito solo cuando están listadas y marcadas para uso como canalización (o cuando están diseñadas para ensamblaje de extremo a extremo)."},
  {"id":426,"q":"Una carga continua requiere conductores dimensionados a un mínimo de 22 A después del factor de 125%; usando la columna de 75°C de la Tabla 310.16, ¿qué conductor de cobre mínimo satisface este requisito de 22 A?","opts":["14 AWG","10 AWG","12 AWG","8 AWG"],"re":"En la columna de 75°C, el 12 AWG es 25 A pero está limitado a 20 A por el NEC 240.4(D); el 10 AWG a 35 A es el conductor más pequeño que proporciona al menos 22 A."},
  {"id":427,"q":"El puente de unión principal, que conecta el conductor puesto a tierra (neutro) al sistema de puesta a tierra de equipos, se instala en cuál ubicación?","opts":["En cada subtablero","Solo en el medio de desconexión de la acometida","En el tomacorriente más lejano","En cada electrodo de puesta a tierra"],"re":"El NEC 250.24(B) y 250.28 requieren que el puente de unión principal se instale en el medio de desconexión de la acometida."},
  {"id":428,"q":"Al usar un voltímetro para localizar una apertura en una cadena en serie de tres cargas que están todas sin energía, ¿dónde aparecerá la tensión completa de la fuente?","opts":["A través de cada carga por igual","A través del punto de apertura (interrupción)","A través del conductor de puesta a tierra","En ningún lugar, el medidor lee cero en todas partes"],"re":"En un circuito en serie con una apertura, toda la tensión de la fuente cae a través de la interrupción porque no fluye corriente, por lo que medir la tensión completa a través de un componente revela la apertura."},
  {"id":429,"q":"Tratando la cobertura como un asunto de seguridad, ¿cuál es la profundidad de enterramiento mínima requerida por la Tabla 300.5 del NEC para cable UF enterrado directamente que alimenta un circuito derivado residencial de 120 voltios o menos protegido por un GFCI de 20 amperios, en una zanja sin otra protección?","opts":["6 pulgadas","12 pulgadas","18 pulgadas","24 pulgadas"],"re":"La Tabla 300.5 del NEC permite 12 pulgadas de cobertura para circuitos derivados residenciales con clasificación de 120 V o menos y protegidos por un GFCI a 20 amperios o menos."},
  {"id":430,"q":"Según el NEC 240.4(D), ¿cuál es la protección máxima contra sobrecorriente generalmente permitida para un conductor de cobre de 14 AWG, independientemente de su ampacidad de 90°C?","opts":["15 A","20 A","25 A","30 A"],"re":"El NEC 240.4(D) limita el cobre de 14 AWG a un dispositivo de sobrecorriente máximo de 15 A."},
  {"id":431,"q":"En un subtablero ubicado en un gabinete separado aguas abajo de la acometida, el conductor neutro (puesto a tierra) debe estar:","opts":["Unido al gabinete con un tornillo de unión","Aislado del bus de puesta a tierra de equipos y del gabinete","Conectado solo a una varilla de tierra local","Conectado solo al bus de puesta a tierra de equipos"],"re":"El NEC 250.24(A)(5) prohíbe la conexión neutro-tierra en el lado de la carga de la acometida; el neutro debe estar aislado en un subtablero."},
  {"id":432,"q":"Los conductores y terminaciones que se sienten calientes y muestran decoloración en un tomacorriente bajo carga normal resultan más comúnmente de:","opts":["Un neutro abierto en otro lugar","Un conductor correctamente dimensionado","Un conductor subdimensionado o conectado de forma floja","Un GFCI correctamente disparado"],"re":"El calor y la decoloración indican resistencia excesiva, típicamente por un conductor subdimensionado o una conexión floja y mal hecha que disipa potencia como calor."},
  {"id":433,"q":"Un atenuador (dimmer) incandescente estándar es generalmente adecuado para controlar cuál tipo de carga?","opts":["Una carga de iluminación resistiva (incandescente)","Una carga de tomacorriente","Una carga de motor estándar","Un balasto fluorescente no clasificado para atenuación"],"re":"Un atenuador estándar está diseñado para cargas de iluminación incandescente resistiva (y compatibles listadas); no debe usarse en motores ni balastos no atenuables, a menos que esté específicamente clasificado."},
  {"id":434,"q":"Según el NEC 240.4(D), ¿cuál es el dispositivo de sobrecorriente estándar máximo permitido para proteger un conductor de cobre de 12 AWG?","opts":["15 A","25 A","20 A","30 A"],"re":"El NEC 240.4(D) limita el cobre de 12 AWG a un dispositivo de sobrecorriente máximo de 20 A."},
  {"id":435,"q":"Según la Tabla 300.5 del NEC, ¿cuál es la profundidad de enterramiento (cobertura) mínima general para cables o conductores enterrados directamente con clasificación de 0-1000 voltios donde no aplica ninguna reducción especial permitida?","opts":["12 pulgadas","24 pulgadas","18 pulgadas","30 pulgadas"],"re":"La Columna 1 de la Tabla 300.5 del NEC especifica 24 pulgadas de cobertura como el mínimo general para conductores enterrados directamente con clasificación de 0-1000 voltios."},
  {"id":436,"q":"La conexión entre el conductor puesto a tierra (neutro) y los conductores de puesta a tierra de equipos está permitida en cuál punto único en una acometida típica?","opts":["Solo en la base del medidor","En cada tablero de circuitos derivados","En el equipo de acometida principal","En cada caja de empalme"],"re":"El NEC 250.24(A)(5) limita la unión neutro-tierra al equipo de acometida; las conexiones aguas abajo no están permitidas."},
  {"id":437,"q":"Un tablero alimenta una carga continua de 40 A; ¿qué clasificación mínima de OCPD se requiere para satisfacer la regla del 125% de carga continua?","opts":["50 A","45 A","40 A","60 A"],"re":"40 A × 1.25 = 50 A, y 50 A es una clasificación estándar según el NEC 240.6(A)."},
  {"id":438,"q":"Un GFCI protege contra descargas eléctricas comparando la corriente en cuáles dos conductores?","opts":["El vivo y el conductor de puesta a tierra de equipos","Las dos patas no aterrizadas de un circuito de 240 voltios","Los conductores no aterrizado (vivo) y puesto a tierra (neutro)","El neutro y el conductor de puesta a tierra"],"re":"Un GFCI compara continuamente la corriente del vivo y del neutro; cualquier diferencia significa que hay corriente fugándose por otra trayectoria (una falla a tierra), y se dispara a aproximadamente 5 mA."},
  {"id":439,"q":"Según la Tabla 300.5 del NEC, ¿cuál es la cobertura mínima para conductores instalados en conduit metálico rígido (RMC) o conduit metálico intermedio (IMC) con clasificación de 0-1000 voltios, enterrados en una ubicación no sujeta a tráfico vehicular?","opts":["18 pulgadas","12 pulgadas","6 pulgadas","24 pulgadas"],"re":"La Columna 3 de la Tabla 300.5 del NEC permite 6 pulgadas de cobertura para conductores en RMC o IMC, ya que estas canalizaciones proporcionan una protección física robusta."},
  {"id":440,"q":"Las canalizaciones metálicas, charolas portacables y gabinetes utilizados como conductores de puesta a tierra de equipos deben estar efectivamente unidos principalmente para asegurar qué?","opts":["Costo de instalación reducido","Una apariencia decorativa","Una trayectoria de corriente de falla de baja impedancia","Mayor ampacidad del conductor"],"re":"El NEC 250.4(A)(5) y 250.96 requieren la unión para proporcionar una trayectoria efectiva de baja impedancia que despeje las fallas a tierra."},
  {"id":441,"q":"Cuando un solo conductor de puesta a tierra de equipos y conductores de diferentes tamaños ocupan una caja, ¿qué tamaño de conductor determina la asignación de volumen para ese conductor de puesta a tierra según el NEC 314.16(B)(5)?","opts":["El conductor de puesta a tierra más pequeño","Un promedio de todos los conductores","El conductor de puesta a tierra de equipos más grande","Siempre 14 AWG"],"re":"El NEC 314.16(B)(5) basa la asignación del conductor único de puesta a tierra en el conductor de puesta a tierra de equipos más grande presente."},
  {"id":442,"q":"Un interruptor con sensor de ocupación utilizado para controlar la iluminación según el movimiento detectado opera más comúnmente bajo cuál principio?","opts":["Medición de la temperatura del conductor","Detección de fallas a tierra","Detección de caída de tensión de línea","Detección de movimiento por infrarrojo pasivo o ultrasonido"],"re":"Los sensores de ocupación típicamente usan detección de movimiento por infrarrojo pasivo (PIR), ultrasonido o tecnología dual para encender la iluminación cuando un espacio está ocupado y apagarla después de que se desocupa."},
  {"id":443,"q":"¿Cuál instrumento es el más apropiado para medir la resistencia de aislamiento para confirmar un sospechoso cortocircuito de alta resistencia entre conductores?","opts":["Un amperímetro de gancho","Un detector de tensión sin contacto","Un probador de enchufe para tomacorrientes","Un probador de resistencia de aislamiento (megóhmetro)"],"re":"Un megóhmetro aplica una alta tensión de prueba en CC para revelar la ruptura del aislamiento y las fugas que un óhmetro común podría pasar por alto, lo que lo hace ideal para fallas de aislamiento."},
  {"id":444,"q":"Donde una canalización metálica que contiene conductores de acometida entra a un gabinete con perforaciones (knockouts) concéntricas o excéntricas, la conexión debe hacerse con:","opts":["Solo una contratuerca estándar","Solo un buje plástico","Cinta sobre la perforación","Accesorios tipo unión, como bujes de unión o contratuercas de unión"],"re":"El NEC 250.92(B) requiere accesorios tipo unión para canalizaciones de acometida en gabinetes con perforaciones concéntricas o excéntricas."},
  {"id":445,"q":"Según el NEC 110.16(A), los equipos eléctricos como tableros de distribución y tableros en lugares distintos a unidades de vivienda que probablemente requieran examinación mientras están energizados deben marcarse en campo o en fábrica para advertir sobre cuál peligro?","opts":["Interferencia electromagnética","Monóxido de carbono","Arco eléctrico (arc flash)","Exposición a radiación"],"re":"El NEC 110.16(A) requiere una marca aplicada en campo o en fábrica que advierta a las personas calificadas sobre los peligros potenciales de arco eléctrico (arc flash)."},
  {"id":446,"q":"En un cálculo de llenado de caja, ¿cuántas asignaciones de volumen cuenta cada yugo o brida que sostiene un dispositivo (como un interruptor o tomacorriente) según el NEC 314.16(B)(4)?","opts":["Una, basada en el conductor más grande conectado a él","Dos, basadas en el conductor más grande conectado a él","Una por terminal","Ninguna"],"re":"El NEC 314.16(B)(4) cuenta cada yugo o brida como dos asignaciones de volumen basadas en el conductor más grande conectado al dispositivo."},
  {"id":447,"q":"Un puente de unión utilizado en el lado de alimentación de la acometida (un puente de unión del lado de alimentación) se dimensiona según cuál tabla?","opts":["Tabla 250.122","Tabla 310.16","Tabla 250.66","Tabla 300.5"],"re":"El NEC 250.102(C) dimensiona los puentes de unión del lado de alimentación usando la Tabla 250.66 según el tamaño del conductor de acometida."},
  {"id":448,"q":"Antes de tomar mediciones de resistencia con un óhmetro para encontrar una apertura o un cortocircuito, el circuito debe estar:","opts":["Totalmente energizado a la tensión nominal","Cargado a la corriente plena de placa","Conectado a un generador en funcionamiento","Desenergizado y verificado sin tensión"],"re":"Los óhmetros suministran su propia corriente de prueba y pueden dañarse o dar lecturas falsas si se aplican a un circuito vivo, por lo que el circuito debe estar desenergizado y confirmado sin tensión primero."},
  {"id":449,"q":"Según el NEC 110.24(A), el equipo de acometida en lugares distintos a unidades de vivienda debe marcarse de forma legible en campo con cuál de la siguiente información?","opts":["El número de licencia de contratista del instalador","La carga total conectada en kVA","La fecha de la próxima inspección","La máxima corriente de falla disponible"],"re":"El NEC 110.24(A) requiere que el equipo de acometida se marque en campo con la máxima corriente de falla disponible, incluyendo la fecha en que se realizó el cálculo."},
  {"id":450,"q":"¿Cuál condición permite que una arandela reductora se utilice como el único medio de unión para una canalización de acometida?","opts":["Ninguna; las arandelas reductoras no están permitidas como único medio de unión para canalizaciones de acometida","Cuando el conductor es de cobre","Cuando está pintada","Cuando la canalización es de PVC"],"re":"El NEC 250.92(B) no permite las arandelas reductoras estándar como medio de unión para canalizaciones de acometida; se requieren dispositivos de unión listados."},
  {"id":451,"q":"Todas las abrazaderas internas para cable presentes en una caja cuentan colectivamente como cuántas asignaciones de volumen según el NEC 314.16(B)(2)?","opts":["Una por abrazadera","Dos en total","Una, basada en el conductor más grande de la caja","Cero"],"re":"El NEC 314.16(B)(2) cuenta todas las abrazaderas para cable juntas como una sola asignación de volumen basada en el conductor más grande presente."},
  {"id":452,"q":"Muchos atenuadores electrónicos y sensores de ocupación modernos requieren que cuál conductor esté presente en la caja del interruptor para alimentar su electrónica interna?","opts":["Un segundo conductor no aterrizado","Solo un puente de unión","Un conductor de tierra aislada","Un conductor puesto a tierra (neutro)"],"re":"Muchos atenuadores electrónicos y sensores requieren un conductor puesto a tierra (neutro) en el dispositivo para alimentar su electrónica; el NEC 404.2(C) generalmente requiere un neutro en las ubicaciones de interruptores para soportar tales dispositivos."},
  {"id":453,"q":"Un propietario reporta que un interruptor GFCI se dispara solo cuando llueve y hay un cable de extensión exterior conectado; la causa más probable es:","opts":["Una simple sobrecarga térmica","Humedad que causa fuga de corriente a tierra","Solo una conexión invertida de línea y carga","Un tablero de acometida subdimensionado"],"re":"El disparo de un GFCI correlacionado con el clima típicamente resulta de la intrusión de agua que crea una pequeña corriente de fuga a tierra que excede el umbral de disparo de 5 mA."},
  {"id":454,"q":"Según el NEC 110.22(A), cada medio de desconexión debe marcarse de forma legible para indicar su propósito, a menos que cuál condición sea verdadera?","opts":["Tiene una clasificación menor a 100 amperios","Está instalado por un electricista licenciado","Está ubicado a la vista del equipo que controla y el propósito es evidente","Es un interruptor de caja moldeada"],"re":"El NEC 110.22(A) requiere que cada medio de desconexión se marque de forma legible para identificar su propósito, a menos que esté ubicado y dispuesto de manera que el propósito sea evidente."},
  {"id":455,"q":"¿Cuál es la profundidad de enterramiento mínima para cable UF enterrado directamente o conductores con clasificación de 0 a 1000 voltios bajo un césped residencial, según la Tabla 300.5?","opts":["12 in","18 in","24 in","6 in"],"re":"La Columna 1 de la Tabla 300.5 requiere 24 in de cobertura para cables y conductores enterrados directamente que no estén en canalización."},
  {"id":456,"q":"¿Cuál término de estimación se refiere a la lista detallada de todos los materiales, dispositivos y accesorios contados a partir de los planos necesarios para completar un trabajo?","opts":["Despiece de materiales (takeoff)","Unidad de mano de obra","Asignación de gastos generales","Orden de cambio"],"re":"Un despiece de materiales (takeoff) es el conteo detallado de materiales y dispositivos derivado de los documentos de construcción."},
  {"id":457,"q":"La caída de tensión excesiva en un tramo largo de circuito derivado se reduce mejor:","opts":["Aumentando el tamaño del conductor (calibre de cable más grande)","Instalando un dispositivo de sobrecorriente más grande","Agregando más cargas al circuito","Disminuyendo la tensión de alimentación"],"re":"La caída de tensión es proporcional a la resistencia y la longitud del conductor; aumentar el tamaño del cable reduce la resistencia y disminuye la caída para una corriente dada."},
  {"id":458,"q":"¿Cuál es la profundidad de enterramiento mínima para conductores instalados en conduit rígido no metálico (PVC) aprobado para enterramiento directo, de 0 a 1000 voltios, según la Tabla 300.5?","opts":["18 in","24 in","6 in","12 in"],"re":"La Columna 4 de la Tabla 300.5 requiere 18 in de cobertura para conductores en canalizaciones no metálicas listadas para enterramiento directo."},
  {"id":459,"q":"Según el NEC 408.4(A), cada circuito y modificación de circuito en un tablero debe identificarse de forma legible en cuanto a su propósito claro, evidente y específico mediante cuál medio?","opts":["Un diagrama pegado en la pared más cercana","Un directorio de circuitos ubicado en la cara o el interior de la puerta del tablero","Una explicación verbal al propietario del edificio","Una etiqueta solo en los conductores de acometida principal"],"re":"El NEC 408.4(A) requiere un directorio de circuitos o identificación de circuitos ubicado en la cara o el interior de la puerta del tablero, lo que apoya la identificación segura de las desconexiones."},
  {"id":460,"q":"En la estimación eléctrica, una 'unidad de mano de obra' representa más directamente cuál de las siguientes opciones?","opts":["El precio de un artículo de material","Los gastos generales totales del proyecto","El tiempo estimado para instalar un artículo específico","El porcentaje de recargo sobre los materiales"],"re":"Una unidad de mano de obra es el tiempo de instalación estimado estandarizado (a menudo en horas) asignado a la instalación de un artículo en particular."},
  {"id":461,"q":"Al terminar un conductor de 12 AWG bajo el tornillo de un dispositivo, la conexión debe apretarse según cuál pauta?","opts":["Lo más apretado posible con la máxima fuerza","Hasta que la cabeza del tornillo se barra","Solo apretado a mano sin herramienta","Al valor de torque especificado por el fabricante"],"re":"El NEC 110.14(D) requiere que las terminaciones se aprieten al valor de torque especificado por el fabricante, típicamente usando una herramienta de torque calibrada, para asegurar una conexión confiable."},
  {"id":462,"q":"Mientras la palanca del interruptor permanece en la posición ON pero no llega energía al circuito, la primera medición más apropiada es:","opts":["La resistencia de la carga con energía aplicada","El torque en los tornillos de la barra de neutro","La resistencia de aislamiento del gabinete del tablero","La tensión en la terminal de carga del interruptor a neutro"],"re":"Medir la tensión en la salida del interruptor le indica si el interruptor está realmente entregando energía, lo que separa lógicamente un interruptor defectuoso de un problema de cableado aguas abajo."},
  {"id":463,"q":"¿Cuál es la cobertura mínima para un circuito derivado residencial con clasificación de 120 voltios o menos y 20 amperios o menos, protegido por GFCI, según la Tabla 300.5?","opts":["24 in","18 in","6 in","12 in"],"re":"La Columna 5 de la Tabla 300.5 permite 6 in de cobertura para circuitos residenciales de 120 voltios, 20 amperios o menos protegidos por GFCI."},
  {"id":464,"q":"La caída de tensión en un circuito monofásico es directamente proporcional a cuál combinación de factores?","opts":["Solo el área de la sección transversal del conductor","El porcentaje de llenado del conduit","La tensión y la clasificación de aislamiento del conductor","La corriente y la longitud de un solo sentido del circuito"],"re":"La caída de tensión monofásica aumenta tanto con la corriente de carga como con la longitud del circuito (VD = 2 × K × I × L / CM)."},
  {"id":465,"q":"Al tomar mediciones de tensión en un tablero de distribución trifásico de 480 voltios dentro de un edificio comercial, ¿cuál clasificación de categoría de medición (CAT) deben tener como mínimo el multímetro digital y sus puntas?","opts":["CAT I","CAT II","CAT III","CAT 0"],"re":"CAT III es la clasificación mínima para mediciones en instalaciones fijas como tableros de distribución y circuitos derivados en edificios comerciales; CAT IV se usa en la entrada de acometida."},
  {"id":466,"q":"¿Cuál es la cobertura mínima requerida para conductores en conduit metálico rígido (RMC) enterrados directamente en la tierra, de 0 a 1000 voltios, según la Tabla 300.5?","opts":["18 in","12 in","24 in","6 in"],"re":"La Columna 2 de la Tabla 300.5 requiere 6 in de cobertura para conduit metálico rígido y conduit metálico intermedio."},
  {"id":467,"q":"Una ventaja clave de la imagen térmica durante el mantenimiento eléctrico es que permite al técnico:","opts":["Desenergizar el equipo antes de la inspección","Detectar conexiones sobrecalentadas sin contacto mientras el sistema está bajo carga","Medir valores exactos de resistencia del circuito","Reemplazar la necesidad de especificaciones de torque"],"re":"La termografía infrarroja encuentra calor anormal por conexiones flojas o defectuosas en equipos energizados y cargados sin contacto físico, lo que permite una intervención temprana."},
  {"id":468,"q":"Para reducir la caída de tensión en un circuito derivado largo sin cambiar la carga ni la longitud, ¿cuál es el método más directo?","opts":["Aumentar la clasificación del OCPD","Disminuir el tamaño del conductor","Aumentar el tamaño del conductor","Usar un conduit más pequeño"],"re":"Aumentar el tamaño del conductor (mayor área en mils circulares) reduce la resistencia y, por lo tanto, disminuye la caída de tensión."},
  {"id":469,"q":"Un electricista necesita medir la tensión en el lado de línea de la desconexión principal de acometida de un edificio comercial; ¿cuál clasificación CAT es la más apropiada para el medidor en esta ubicación?","opts":["CAT I","CAT II","CAT IV","CAT III"],"re":"CAT IV está destinada para mediciones en el origen de la instalación, como la entrada de acometida y el lado de línea de la desconexión principal, donde la energía de falla disponible es más alta."},
  {"id":470,"q":"Los orificios de inserción 'back-wire' en la parte posterior de muchos tomacorrientes residenciales de 15 amperios están generalmente limitados a conductores de qué tamaño?","opts":["Solo 12 AWG sólido","Solo 14 AWG sólido","10 AWG trenzado","8 AWG sólido"],"re":"Las terminales de inserción sin tornillo (back-wire) en los tomacorrientes estándar de 15 amperios están típicamente listadas solo para 14 AWG de cobre sólido; los conductores más grandes deben usar las terminales de tornillo."},
  {"id":471,"q":"Los conductores y cables enterrados directamente que emergen del nivel del suelo deben protegerse con un gabinete o canalización que se extienda desde la profundidad de cobertura requerida hasta al menos qué altura sobre el nivel terminado?","opts":["4 ft","6 ft","8 ft","3 ft"],"re":"El NEC 300.5(D)(1) requiere protección desde la profundidad de cobertura requerida hasta al menos 8 ft sobre el nivel terminado."},
  {"id":472,"q":"Para aislar si un interruptor que se dispara es causado por una falla de cableado o por un electrodoméstico conectado, un paso de diagnóstico acertado es:","opts":["Desconectar todas las cargas y reiniciar; si se mantiene, reconectar las cargas una a la vez","Aumentar la clasificación del interruptor y volver a probar","Reemplazar el bus de neutro","Puentear el interruptor con un cable"],"re":"Desconectar las cargas y reconectarlas una a la vez reduce lógicamente la falla ya sea al cableado o a un dispositivo específico, siguiendo un método sistemático de aislamiento."},
  {"id":473,"q":"Una carga continua de 30 A es alimentada por conductores que terminan en equipo de 75°C; ¿qué tamaño mínimo de conductor de cobre se requiere de la columna de 75°C de la Tabla 310.16 para transportar el 125% de la carga?","opts":["6 AWG","4 AWG","8 AWG","10 AWG"],"re":"30 A × 1.25 = 37.5 A; en la columna de 75°C, el cobre de 8 AWG (50 A) es el conductor más pequeño que cumple con esto, ya que el 10 AWG es solo 35 A."},
  {"id":474,"q":"Con respecto a las clasificaciones de categoría de medición, ¿por qué un medidor clasificado CAT III 600 V puede ser más seguro que un medidor clasificado CAT II 1000 V al medir en un tablero de distribución?","opts":["El medidor CAT II no puede leer físicamente 600 voltios","La clasificación de tensión en estado estable es el único factor que importa para la seguridad","CAT II siempre significa un medidor de mayor calidad","La clasificación CAT III refleja una mayor resistencia a sobretensiones transitorias para esa ubicación, lo cual importa más que el número de tensión en estado estable"],"re":"La clasificación CAT refleja la capacidad del medidor para resistir sobretensiones transitorias y la energía de falla disponible en una ubicación dada; un número CAT más alto adecuado para la ubicación es más protector que una clasificación de tensión en estado estable más alta en una categoría inferior."},
  {"id":475,"q":"Cuando un cable enterrado directamente se instala debajo de un edificio, debe estar:","opts":["Enterrado a 36 in sin importar nada","Instalado en una canalización","Dejado sin ninguna protección","Empalmado cada 10 ft"],"re":"La Tabla 300.5 y 300.5(C) requieren que los cables que pasan debajo de un edificio se instalen en una canalización que se extienda más allá del edificio."},
  {"id":476,"q":"Leer 240 voltios entre las dos patas no aterrizadas pero solo 95 voltios en una pata a neutro y 145 voltios en la otra pata a neutro en un circuito multiconductor indica:","opts":["Una condición balanceada normal","Un cortocircuito entre las patas","Un neutro abierto o perdido que causa una división de tensión desigual","Un dispositivo GFCI defectuoso"],"re":"La tensión total de línea a línea es correcta, pero las lecturas desiguales de línea a neutro que aún suman 240 V revelan un neutro abierto que permite que la tensión se divida según la impedancia de la carga."},
  {"id":477,"q":"Cuando la ampacidad de un conductor no corresponde a una clasificación de OCPD estándar y el circuito no es un circuito derivado de tomacorrientes de múltiples salidas, el NEC 240.4(B) permite qué acción para clasificaciones de 800 A o menos?","opts":["Usar solo el siguiente OCPD estándar inferior","Redondear la ampacidad a los 5 A más cercanos","Usar el siguiente OCPD estándar superior","No se permite ajuste de OCPD"],"re":"El NEC 240.4(B) permite la siguiente clasificación de OCPD estándar superior cuando la ampacidad del conductor no coincide con un tamaño estándar, sujeto al límite de 800 A y otras condiciones."},
  {"id":478,"q":"Una cinta de advertencia colocada en la zanja sobre una acometida subterránea generalmente debe ubicarse al menos a qué distancia por encima de los conductores?","opts":["12 in por encima de la instalación subterránea","Directamente sobre los conductores","Solo en la superficie","24 in por encima de los conductores"],"re":"El NEC 300.5(D)(3) requiere una cinta de advertencia al menos 12 in por encima de los conductores de acometida subterráneos no encapsulados en concreto."},
  {"id":479,"q":"Al enlazar un conductor sólido bajo el tornillo de sujeción de un dispositivo, el lazo debe formarse de modo que envuelva el tornillo en cuál dirección?","opts":["En sentido antihorario","En sentido horario, la dirección en que se aprieta el tornillo","Recto sin formar un lazo","No importa"],"re":"Un lazo de conductor debe envolverse en sentido horario (la dirección de apriete) alrededor del tornillo de sujeción para que el tornillo atraiga el cable hacia adentro en lugar de empujarlo hacia afuera al apretarse."},
  {"id":480,"q":"Antes de usar un multímetro digital para verificar que un circuito está desenergizado como parte de un procedimiento de bloqueo/etiquetado (lockout/tagout), ¿cuál es la mejor práctica para confirmar que el propio medidor está funcionando?","opts":["Golpear el medidor sobre una superficie dura para reiniciarlo","Asumir que el medidor funciona si su pantalla se encendió","Leer el medidor solo una vez en el circuito presuntamente sin tensión","Usar la prueba vivo-muerto-vivo, verificando una fuente viva conocida antes y después de la medición"],"re":"El método vivo-muerto-vivo (probar antes de tocar) confirma que el medidor lee una fuente energizada conocida, luego el circuito presuntamente sin tensión, y luego la fuente viva nuevamente para verificar que el medidor no falló durante la prueba."},
  {"id":481,"q":"Una caja contiene cuatro conductores de 12 AWG y dos conductores de 14 AWG sin dispositivos ni abrazaderas; ¿qué volumen total de caja se requiere según el NEC 314.16(B)?","opts":["11.0 in³","13.0 in³","13.5 in³","15.0 in³"],"re":"Cuatro de 12 AWG a 2.25 = 9.0 in³ más dos de 14 AWG a 2.00 = 4.0 in³, sumando 13.0 pulgadas cúbicas."},
  {"id":482,"q":"Los fabricantes recomiendan que los dispositivos GFCI y AFCI se prueben usando sus botones de prueba con qué frecuencia como práctica de mantenimiento?","opts":["Solo una vez en la instalación","Solo cuando ocurre una falla","Periódicamente, como mensualmente","Nunca, ya que no requieren mantenimiento"],"re":"Debido a que estos dispositivos protectores pueden fallar de forma silenciosa, los fabricantes comúnmente recomiendan probar el botón TEST periódicamente, típicamente cada mes, para confirmar que la protección sigue siendo funcional."},
  {"id":483,"q":"Donde una canalización subterránea entra a un edificio o sube a la superficie (stub-up), el extremo abierto debe estar:","opts":["Dejado completamente abierto para ventilación","Sellado para prevenir la entrada de humedad","Llenado con concreto","Tapado solo con cinta"],"re":"El NEC 300.5(G) requiere que las canalizaciones y los extremos de los conductores se sellen para prevenir la entrada de humedad o gases."},
  {"id":484,"q":"¿Qué tipo de escalera debe seleccionar un electricista al trabajar cerca de conductores o equipos eléctricos energizados expuestos?","opts":["Una escalera de fibra de vidrio","Una escalera de extensión de aluminio","Una escalera de plataforma de acero","Una escalera de madera mojada"],"re":"Las escaleras de fibra de vidrio son no conductoras y son la opción apropiada para trabajo eléctrico cerca de partes energizadas; las escaleras metálicas son conductoras y deben evitarse."},
  {"id":485,"q":"Según el NEC 240.6(A), ¿cuál secuencia enumera correctamente tres clasificaciones de amperios estándar consecutivas de fusible/interruptor?","opts":["30, 40, 50","30, 35, 40","40, 45, 50","50, 55, 60"],"re":"Las clasificaciones estándar en el NEC 240.6(A) incluyen 30, 40 y 50 A de forma consecutiva; 55 A no es estándar, por lo que 50/55/60 es inválido."},
  {"id":486,"q":"Al hacer el armado (rough-in) de un mástil de acometida utilizado para soportar los conductores de acometida aérea, el mástil y sus accesorios deben ser:","opts":["No mayores que un conduit de 1/2 in","Hechos solo de plástico","De resistencia adecuada para soportar la tensión de los conductores","Limitados a uso interior"],"re":"El NEC 230.28 requiere que el mástil de acometida tenga resistencia adecuada o esté soportado para resistir la tensión de los conductores de acometida aérea."},
  {"id":487,"q":"Un circuito se siente caliente en el interruptor y el interruptor se dispara después de un tiempo de funcionamiento prolongado, pero una prueba de cortocircuito no muestra falla atornillada; esta combinación se ajusta mejor a cuál diagnóstico?","opts":["Una sobrecarga, posiblemente empeorada por una conexión floja que agrega calor","Un cortocircuito directo a tierra","Solo un sensor AFCI defectuoso","Un circuito abierto"],"re":"El calor que se acumula con el tiempo de funcionamiento, con disparo retardado y sin cortocircuito atornillado, apunta a condiciones de sobrecarga, y una conexión floja puede agregar calentamiento resistivo que acelera el disparo."},
  {"id":488,"q":"En un circuito derivado estándar de 120 voltios que usa cable NM, ¿cuál es el color requerido del conductor de puesta a tierra de equipos?","opts":["Blanco o gris","Negro o rojo","Verde, verde con franja amarilla, o desnudo","Azul o amarillo"],"re":"Según el NEC 250.119, los conductores de puesta a tierra de equipos deben ser verdes, verdes con una o más franjas amarillas, o desnudos; el blanco/gris está reservado para el conductor puesto a tierra (neutro)."},
  {"id":489,"q":"Siguiendo la regla 4 a 1 para una escalera recta o de extensión, ¿dónde debe colocarse la base si la escalera toca la pared en un punto a 12 pies de altura?","opts":["1 pie de distancia de la pared","3 pies de distancia de la pared","6 pies de distancia de la pared","12 pies de distancia de la pared"],"re":"La regla 4 a 1 coloca la base a 1 pie de distancia de la pared por cada 4 pies de altura de trabajo; 12 pies dividido entre 4 es igual a 3 pies de la pared."},
  {"id":490,"q":"¿Solo cuál de los siguientes puede fijarse a un mástil de acometida?","opts":["Antenas de televisión","Herrajes de tendedero","Cables de comunicación","Conductores de acometida aérea"],"re":"El NEC 230.28(B) permite que solo se fijen al mástil de acometida los conductores de acometida aérea."},
  {"id":491,"q":"Un circuito derivado alimenta una carga continua de 12 A más una carga no continua de 8 A; ¿qué clasificación mínima de OCPD se requiere?","opts":["25 A","23 A","20 A","30 A"],"re":"Según el NEC 210.20(A), OCPD ≥ (12 A × 1.25) + 8 A = 23 A, y el siguiente tamaño estándar es 25 A."},
  {"id":492,"q":"Cuando un circuito de 120 voltios muestra la tensión correcta sin carga pero la tensión colapsa muy por debajo de lo normal en el momento en que se aplica una carga, la falla probablemente reside en:","opts":["Una conexión de alta resistencia (floja o corroída) en la trayectoria de alimentación","El dispositivo de carga está subdimensionado","El botón de prueba del GFCI","El conductor del electrodo de puesta a tierra"],"re":"Una tensión que es normal sin carga pero que cae notablemente bajo carga indica una conexión en serie de alta resistencia que reduce la tensión solo cuando fluye corriente."},
  {"id":493,"q":"¿Cuál es el espacio libre vertical mínimo para los conductores de acometida que pasan sobre una entrada de vehículos residencial, donde la tensión no excede 300 voltios a tierra?","opts":["10 ft","18 ft","15 ft","12 ft"],"re":"El NEC 230.24(B) requiere 12 ft de espacio libre sobre entradas de vehículos residenciales y áreas sujetas a tráfico vehicular para circuitos que no exceden 300 voltios a tierra."},
  {"id":494,"q":"En los cálculos de caída de tensión usando la fórmula VD = 2 × K × I × L / CM, ¿qué representa la variable 'CM'?","opts":["Material del conduit","Temperatura del conductor en Celsius","Multiplicador de carga continua","Mils circulares del conductor"],"re":"En la fórmula de caída de tensión, CM es el área de la sección transversal del conductor expresada en mils circulares."},
  {"id":495,"q":"Bajo la norma de industria general de OSHA (29 CFR 1910), ¿aproximadamente a qué altura sobre un nivel inferior se requiere generalmente protección contra caídas para trabajadores en una superficie de trabajo elevada?","opts":["2 pies","6 pies","4 pies","10 pies"],"re":"OSHA 29 CFR 1910.28 (industria general) generalmente requiere protección contra caídas a 4 pies sobre un nivel inferior; la norma de construcción (1926) usa 6 pies."},
  {"id":496,"q":"Después de verificar un síntoma y recopilar información, el siguiente paso lógico en un proceso estructurado de diagnóstico es:","opts":["Formular una hipótesis sobre la causa probable y probarla","Reemplazar componentes al azar hasta que funcione","Documentar la reparación antes de probarla","Energizar el circuito y alejarse"],"re":"El diagnóstico efectivo sigue una secuencia lógica: observar el síntoma, recopilar datos, plantear la hipótesis de la causa probable, y luego probar para confirmar antes de reparar."},
  {"id":497,"q":"¿Cuál de las siguientes describe mejor la función protectora principal de un tomacorriente GFCI (interruptor de circuito por falla a tierra)?","opts":["Protege el equipo contra el sobrecalentamiento por sobrecarga","Detecta fallas de arqueo en el cableado del circuito derivado","Protege a las personas contra descargas eléctricas detectando pequeños desbalances de corriente entre los conductores vivo y neutro","Limita los picos de tensión de rayos o sobretensiones de conmutación"],"re":"Un GFCI compara la corriente en el vivo y el neutro y se dispara ante un pequeño desbalance (aproximadamente 4-6 mA), protegiendo a las personas contra descargas; un AFCI detecta el arqueo y un dispositivo de sobretensión maneja los picos de tensión (NEC 210.8)."},
  {"id":498,"q":"¿Cuál es la profundidad mínima del espacio de trabajo despejado requerido frente a un equipo eléctrico que probablemente requiera examinación mientras está energizado, bajo la Condición 1 típica (600 voltios o menos), según 110.26?","opts":["2 ft","5 ft","4 ft","3 ft"],"re":"La Tabla 110.26(A)(1) requiere un mínimo de 3 ft (900 mm) de profundidad de trabajo despejada bajo la Condición 1."},
  {"id":499,"q":"Para una caja de dispositivo de un solo módulo existente, ¿cuál valor debe conocerse para realizar un cálculo de llenado de caja cuando la caja no está listada en la Tabla 314.16(A) del NEC?","opts":["El color de la caja","El tamaño comercial del conduit","La clasificación del interruptor","El volumen marcado en pulgadas cúbicas de la caja"],"re":"Según el NEC 314.16(A), las cajas no estándar deben estar marcadas de forma duradera con su volumen en pulgadas cúbicas para su uso en el cálculo."},
  {"id":500,"q":"¿Cuál combinación de equipo de protección personal es la más apropiada cuando un electricista debe realizar una tarea con riesgo de arco eléctrico, como insertar (racking) un interruptor de 480 voltios que no puede desenergizarse?","opts":["Camiseta de algodón, gafas de sol estándar y guantes de trabajo de cuero","Chaqueta de nylon sintético y guantes de examinación de látex","Chaleco reflectante, casco y manos descubiertas para mejor destreza","Ropa con clasificación de arco, una careta o capucha clasificada para la energía incidente, y guantes de goma con clasificación de tensión con protectores de cuero"],"re":"El trabajo energizado con riesgo de arco eléctrico requiere ropa con clasificación de arco y protección facial acordes a la energía incidente, además de guantes aislantes de goma con clasificación de tensión con protectores de cuero, según la NFPA 70E."}
];
